
const T = [{id:"0001",tags:["日韩","电影","文艺","乡村","人生","治愈"],relatedIds:["0020","0002","0069","0026","0029","0032"],title:"梦想夏乡",region:"日韩",type:"电影",year:2011,genreRaw:"乡村文艺 / 人生哲理",oneLine:"厌倦都市生活的设计师，在夏日乡间租住老屋，重拾生活本真并邂逅宁静爱情。",summary:"东京平面设计师浅野夏树，因创意枯竭与情感创伤，在盛夏时节逃也似的来到偏僻的南方海岛乡间，租下一栋老旧的木屋暂住。在这里，她认识了经营小小陶艺工坊的沉默男子森田耕平，以及一群质朴的村民。通过参与乡间祭典、学习陶艺、耕种一小片菜园，夏树慢下来，感受四季流转与自然生命。她与耕平之间也产生了安静而深刻的情感联结。夏日将尽，夏树必须做出选择：是回到喧嚣却空洞的都市，还是留在这片让她找回梦想与内心平静的夏之乡？",review:"影片节奏舒缓如夏日清风，画面唯美治愈，每一帧都像明信片。情感表达含蓄内敛，充满了东方式的物哀之美。它不讲述激烈的故事，而是引导观众思考生活的本质与幸福的定义，余味绵长。",cover:"/130.jpg",m3u8Index:0,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍",rating:"8.7",views:287193},{id:"0002",tags:["国产","电影","爱情","悬疑","心理","惊悚"],relatedIds:["0091","0050","0038","0071","0001","0078"],title:"肆意沦陷",region:"国产",type:"电影",year:2024,genreRaw:"爱情悬疑 / 心理惊悚",oneLine:"完美男友的求婚之夜，她却在镜中发现背后举着刀的他，一段细思极恐的爱情真相被揭开。",summary:"林溪与男友周慕白相爱一年，对方温柔体贴，近乎完美。在周慕白精心策划的浪漫求婚夜，林溪在洗手间的镜中反射里，看到背后举着刀的周慕白，脸上是她从未见过的冰冷表情。惊恐逃婚后，林溪开始暗中调查，发现周慕白的过去是一片空白，而近期几起与她外貌相似女性的失踪案，似乎都与他有关。她求助心理医生和前刑警，却发现自己的一举一动仿佛仍在周慕白的监视之下。这场爱情，从一开始就是一场精心设计的陷阱，而她正在主动或被迫地“肆意沦陷”。",review:"将甜蜜恋爱与毛骨悚然的惊悚感结合得无比精妙，反转设置令人头皮发麻。氛围营造极具压迫感，观众与女主一同陷入猜疑与恐惧。探讨了亲密关系中的控制与欺骗，是一部后劲十足的心理恐怖片。",cover:"/33.jpg",m3u8Index:1,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡",rating:"8.7",views:82828},{id:"0003",tags:["日韩","电影","爱情","都市","童话","浪漫"],relatedIds:["0030","0080","0091","0087","0004","0009"],title:"东京仙履奇缘",region:"日韩",type:"电影",year:1995,genreRaw:"浪漫爱情 / 都市童话",oneLine:"平凡小镇女孩在东京雨夜遗落一只红鞋，由此与豪门贵公子展开一段现代灰姑娘之恋。",summary:"从北海道来到东京打工的松井雪子，单纯善良。一个暴雨夜，她匆忙中遗落了一只红色高跟鞋。这双鞋被开车路过的年轻企业家、高木财团继承人高木雅史拾到。雅史被鞋主人的纯粹所吸引，通过登报等方式寻找。两人因鞋结缘，跨越阶级与身份差距相知相恋。然而，来自家族的压力、前女友的干扰以及两人不同世界带来的摩擦，不断考验着这段感情。最终，雪子不是等待王子拯救的灰姑娘，她凭借自己的真诚与坚韧，赢得了尊重与爱情，与雅史共同谱写属于他们的东京童话。",review:"经典的日式纯爱电影，情感纯粹动人，满足了观众对都市爱情童话的所有幻想。主演颜值与演技在线，化学反应十足。影片画面唯美，主题曲经典，是九十年代爱情片的标志性作品之一。",cover:"/84.jpg",m3u8Index:2,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司, 松隆子",rating:"7.9",views:268119},{id:"0004",tags:["国产","电影","穿越","古装","甜宠","逆袭"],relatedIds:["0066","0029","0042","0033","0026","0050"],title:"步步沦陷，娇妃她有亿点强",region:"国产",type:"电影",year:2023,genreRaw:"古装穿越 / 甜爽逆袭",oneLine:"全能女博士穿越成冷宫废妃，靠现代知识玩转后宫，让冷面帝王步步沦陷。",summary:"因实验室事故，全能女博士沈清辞穿越到古代，成了被打入冷宫、奄奄一息的废妃。面对生存危机，她运用化学知识改良胭脂水粉打开财路，用心理学拿捏人心，用植物学培育奇花异草，一步步从冷宫崛起，暗中建立自己的情报网与商业帝国。皇帝萧执起初只是好奇这个突然变得与众不同的女人，却在一次次交锋与试探中，被她超越时代的智慧、独立不羁的灵魂所吸引，从戒备、欣赏到深爱，最终“真香”地陷入情网。沈清辞则在后宫与前朝的风云中，活出了属于自己的强大人生。",review:"女主“事业型”设定亮眼，不依赖男性，凭实力逆袭，看得人神清气爽。男女主互动诙谐有趣，帝王“打脸”过程极具喜剧效果。剧情爽点密集，融合了宫斗、智斗、甜宠等多种元素，娱乐性十足。",cover:"/72.jpg",m3u8Index:3,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司",rating:"8.9",views:212781},{id:"0005",tags:["国产","电影","喜剧","奇幻","家庭","甜宠"],relatedIds:["0091","0053","0002","0062","0039","0058"],title:"偷听心声岳父全家追着我宠",region:"国产",type:"电影",year:2024,genreRaw:"都市喜剧 / 奇幻家庭",oneLine:"穷小子婚后意外获得读心术，发现表面嫌弃他的岳父一家，内心竟疯狂想宠他。",summary:"普通程序员林枫娶了富家千金苏婉，一直以为岳父苏建国严肃古板，岳母挑剔，小舅子傲慢，全家都看不上自己。一次意外触电后，林枫竟获得了听见苏家人心声的能力。他震惊地发现，表面训斥他不上进的岳父，内心在狂吼：“我女婿熬夜加班好辛苦！明天就让秘书给他公司投个资！”看似挑剔的岳母实际在想：“这孩子太瘦了，我得再研究十道滋补菜谱。”傲慢的小舅子心里则在盘算：“姐夫游戏打得真烂，怎么才能不动声色地带他上分？”自此，林枫的生活被全家人别别扭扭又铺天盖地的“暗宠”淹没。",review:"设定新颖有趣，反差笑料层出不穷，是近期都市喜剧的黑马。家庭温情内核扎实，在搞笑之余展现了家人之间不善表达却深沉的爱。节奏轻快，观感轻松愉悦，适合全家一同观看。",cover:"/108.jpg",m3u8Index:4,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美",rating:"8.8",views:390530},{id:"0006",tags:["日韩","电影","恐怖","悬疑","心理","家庭"],relatedIds:["0035","0060","0029","0022","0024","0069"],title:"衣橱",region:"韩国",type:"电影",year:2020,genreRaw:"恐怖悬疑 / 家庭心理",oneLine:"女儿失踪后，父亲发现她常玩的衣橱里，藏着连接异度空间的恐怖秘密。",summary:"妻子早逝的画家尚元，与女儿伊娜相依为命。在搬入郊外新家后，伊娜变得孤僻，总对着房间里的老旧衣橱说话。某天，伊娜突然在衣橱前消失无踪。心急如焚的尚元在调查中发现，这个衣橱似乎有着诡异的历史，前住户的女儿也以同样方式失踪。在驱魔师的帮助下，尚元得知衣橱连接着一个充满怨念的异度空间，被吞噬的孩子会逐渐被遗忘。为救回女儿，尚元必须克服内心对亡妻的愧疚与伤痛，亲自进入衣橱后的黑暗世界，直面盘踞其中的恶灵，并找到带回女儿的方法。",review:"将东方“衣柜”的童年恐惧意象发挥到极致，恐怖氛围层层递进，不乏令人屏息的Jump Scare。内核是关于父爱与家庭创伤的治愈，恐怖外壳下包裹着感人至深的情感力量，是部有温度的恐怖片。",cover:"/107.jpg",m3u8Index:5,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治, 韩孝周",rating:"9.2",views:233282},{id:"0007",tags:["欧美","电影","喜剧","美食","犯罪","黑色幽默"],relatedIds:["0079","0080","0097","0052","0001","0035"],title:"肝酪上瘾者",region:"欧美",type:"电影",year:2017,genreRaw:"黑色喜剧 / 美食犯罪",oneLine:"一位法国奶酪鉴赏家，为品尝传说中能带来极致体验的非法禁品奶酪，不惜卷入黑市犯罪。",summary:"德尼·拉瓦勒是巴黎著名的奶酪鉴赏家，味蕾挑剔，人生乏味。一次地下美食聚会上，他品尝到一小块名为“肝酪”的传说级奶酪，其滋味带来的极致愉悦感令他瞬间上瘾。然而，“肝酪”的原料与制作工艺被法律明文禁止，只存在于黑市。为了再次获得“肝酪”，德尼这个原本循规蹈矩的中年人，开始与古怪的农场主、狡猾的走私犯、危险的犯罪团伙打交道，闹出一连串令人啼笑皆非又危机四伏的事件。他的人生在追求极致感官体验的过程中彻底失控，也引发了对欲望、法律与道德的思考。",review:"影片充满了法式荒诞与冷幽默，将美食家的偏执刻画得入木三分。剧情在美食、犯罪、喜剧类型间流畅切换，节奏明快。对“成瘾性”的探讨别出心裁，结局意味深长，令人回味。",cover:"/81.jpg",m3u8Index:6,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治",rating:"8.0",views:147868},{id:"0008",tags:["日韩","电影","战国","奇幻","乙女向","恋爱"],relatedIds:["0096","0060","0034","0076","0079","0077"],title:"战刻夜想曲",region:"日韩",type:"电影",year:2019,genreRaw:"战国奇幻 / 乙女向恋爱",oneLine:"平凡女高中生穿越至群雄割据的异界战国，成为能左右战局的关键“圣女”。",summary:"高中生织田樱误入神社密室，穿越到一个类似战国时代但存在“妖力”的异世界“神牙”。这里各大武将势力割据，并能化身强大的“战鬼”形态作战。樱被发现体内拥有纯净的“神子之力”，可以净化战鬼的狂暴，甚至强化其力量，因此被各方势力争抢。她先后结识了高傲的武田军首领、忠诚的上杉家武将、神秘的第六天魔王等魅力各异的战国名将化身的角色。在乱世的漩涡中，樱不仅要运用自己的力量影响战局，寻找归家之路，更要在众多英雄的守护与爱慕中，做出属于自己的命运抉择。",review:"美术风格华丽，武将的战鬼形态设计酷炫。乙女向剧情满足女性观众对战国英雄的浪漫幻想，多位男性角色性格鲜明，互动甜虐交织。将历史题材与奇幻恋爱结合，创意独特。",cover:"/76.jpg",m3u8Index:7,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪",rating:"8.6",views:76543},{id:"0009",tags:["欧美","电影","灾难","动作","科幻","冒险"],relatedIds:["0029","0092","0089","0010","0095","0008"],title:"地球淹没之惊涛大历险",region:"欧美",type:"电影",year:2009,genreRaw:"灾难动作 / 科幻冒险",oneLine:"全球冰川因异常太阳活动急速融化，一家人驾驶改装游艇在淹没的世界中寻找避难所。",summary:"因太阳异常活动，全球气温骤升，两极冰川以惊人的速度融化，海平面在数周内上涨数百米，淹没绝大多数沿海城市。前海军工程师杰克·劳森预见到危机，提前将自家房屋改造为坚固的游艇。洪水来袭时，他带着分居的妻子凯特和两个孩子，踏上危机四伏的航程，前往传说中位于高原的安全区“方舟”。途中，他们遭遇巨浪、海盗、资源争夺以及逐渐显现的深海未知生物威胁。一家人必须在极限环境中修复亲情裂痕，依靠智慧与勇气，在已经成为一片汪洋的地球上，杀出一条求生之路。",review:"灾难场景宏大逼真，尤其是海啸淹没城市的场面极具视觉冲击力。家庭情感线作为内核，与外部灾难压力相辅相成，使影片不止于特效奇观。节奏紧凑，冒险过程一波三折，是经典的灾难片叙事典范。",cover:"/122.jpg",m3u8Index:8,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊, 全度妍",rating:"9.2",views:364918},{id:"0010",tags:["国产","电影","动画","奇幻","温情","友情"],relatedIds:["0025","0029","0024","0037","0086","0023"],title:"叫我僵小鱼叙缘篇2 双鱼记",region:"国产",type:"电影",year:2023,genreRaw:"动画奇幻 / 温情友情",oneLine:"小鱼为帮助新朋友“小蓝”找回记忆与家园，携手踏上穿越水墨江湖的暖心旅程。",summary:"僵尸宝宝小鱼和“爹地”徐小辰的平静生活，被一条意外出现的蓝色小鱼精“小蓝”打破。小蓝失去了大部分记忆，只记得家园在遥远的“忘川源”。善良的小鱼决定帮助小蓝，两人（鱼）偷偷离开家，凭借小蓝残存的感应，踏入一个由传统水墨画风构成的奇幻江湖世界。他们结识了会说话的毛笔、守护古镇的石狮精，也遭遇了想吞噬精灵之气的邪恶画妖。在冒险中，小鱼和小蓝的友谊日益深厚，也逐渐揭开了小蓝身世与“忘川源”背后，关乎两个世界平衡的古老秘密。",review:"延续了僵小鱼系列温暖治愈的风格，水墨风奇幻世界的设定唯美而富有想象力。双主角的互动有趣又感人，冒险故事寓教于乐，传达了关于友情、责任与勇敢的美好品质。适合全年龄观众观看。",cover:"/56.jpg",m3u8Index:9,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊",rating:"7.6",views:366378},{id:"0011",tags:["欧美","电影","喜剧","爱情","女性","成长"],relatedIds:["0094","0075","0086","0062","0078","0064"],title:"剩女大作战第五部",region:"欧美",type:"电影",year:2016,genreRaw:"浪漫喜剧 / 女性成长",oneLine:"三位事业有成的“剩女”闺蜜，在35岁门槛前，决定主动出击寻找真爱，闹出无数笑话。",summary:"律师萨曼莎、设计师克洛伊、医生瑞秋，三位年届三十五的闺蜜事业成功，生活精致，却依然单身，被社会戏称为“剩女”。受够了被动等待和相亲尴尬的她们，在新年来临之际立下“军令状”，要主动、有计划地寻找理想伴侣，并互相监督。她们尝试高端婚恋APP、参加极速约会、甚至报名南极科考团（只为认识优质男性），过程中笑料百出，也遭遇了各种奇葩对象和情感挫折。最终，她们意识到，寻找真爱的意义不在于摆脱“剩女”标签，而在于更清楚地认识自己，并勇敢拥抱任何状态下的幸福可能。",review:"轻松诙谐，对现代都市女性的婚恋困境刻画真实又充满自嘲精神。闺蜜情谊感人，三位女主性格鲜明。影片传递了积极独立的女性价值观，在爆笑之后给人以温暖和力量。",cover:"/86.jpg",m3u8Index:10,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘",rating:"7.7",views:374598},{id:"0012",tags:["日韩","电影","爱情","文艺","悲剧","催泪"],relatedIds:["0062","0069","0093","0056","0003","0035"],title:"纯白之恋",region:"日韩",type:"电影",year:2006,genreRaw:"纯爱文艺 / 绝症悲剧",oneLine:"患有白血病的钢琴天才少女，与默默守护她的邻家男孩之间，一段短暂而永恒的白色恋情。",summary:"天才钢琴少女白羽，17岁那年确诊白血病，被迫离开舞台，住进海边的疗养院。她的童年玩伴、一直暗恋她的林风，不顾一切来到疗养院所在的小镇打工，只为能时常陪伴她。林风不知道如何表达，只是默默为她修理收音机、收集贝壳、在窗外种满她喜欢的白色小花。在白羽被病痛和治疗折磨的日子里，林风的陪伴成了她生命最后时光中最温暖的色彩。两人之间从未说出口的爱恋，在海风、钢琴声与日益迫近的死神阴影中，显得格外纯净而悲伤。最终，白羽在林风的怀中安静离世，留下一段名为《纯白之恋》的未完成曲谱。",review:"典型的日韩纯爱催",cover:"/149.jpg",m3u8Index:11,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡, 役所广司",rating:"9.0",views:442396},{id:"0013",tags:["国产","电影","怪兽","灾难","科幻","特效"],relatedIds:["0032","0033","0028","0062","0049","0075"],title:"摩斯拉",region:"国产",type:"电影",year:2016,genreRaw:"灾难 / 怪兽 / 科幻",oneLine:"沉睡的远古巨蛾摩斯拉苏醒，为保护一枚特殊的卵与人类文明陷入对峙。",summary:"地质勘探队在西伯利亚永久冻土层中发现了一枚巨大的神秘虫茧。能源公司无视生态学家的警告，试图采集茧中生物样本以研究新型生物燃料，意外唤醒了沉睡的远古守护者——巨蛾“摩斯拉”。摩斯拉的苏醒引发了一系列地磁异常和全球性气象灾难，其唯一目标是将那枚被人类夺走的卵护送回北极的巢穴。一支由科学家、军人和环保主义者组成的特殊小队临危受命，必须在摩斯拉摧毁沿途数座城市前，理解它的意图并化解这场人与自然的终极危机。最终他们发现，摩斯拉并非毁灭者，而是地球生态平衡的最后一道保险。",review:"影片将传统的怪兽灾难片提升到了生态寓言的高度。摩斯拉的形象设计兼具神性与生物感，其振翅引发的特效场面宏大且富有诗意。故事节奏张弛有度，在毁灭性的危机中探讨了人类对自然的傲慢与敬畏，情感内核深刻动人。",cover:"/91.jpg",m3u8Index:12,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡",rating:"8.3",views:114492},{id:"0014",tags:["欧美","电影","科幻","惊悚","高概念","虚拟现实"],relatedIds:["0061","0068","0040","0005","0073","0085"],title:"我掌控全世界",region:"欧美",type:"电影",year:2023,genreRaw:"科幻 / 惊悚 / 剧情",oneLine:"一名程序员发现自己能修改全球唯一量子计算机的底层代码，成为无形的“上帝”。",summary:"天才程序员里奥在维护名为“世界之魂”的全球量子计算中枢时，意外发现了一个后门漏洞。通过这个漏洞，他可以悄无声息地修改任何联网设备的运行逻辑，从调整红绿灯到篡改股票交易，甚至能影响人的浅层意识。起初，他用这种能力小规模地“修正”不公，成为网络传说中的“调音师”。但随着权力膨胀，一个名为“守护者”的古老AI系统察觉了他的存在，并启动清除协议。里奥必须与这个几乎全知全能的AI在数字与现实两个维度展开对抗，同时面对自己日益扭曲的道德观，最终决定是成为新世界的神，还是将其彻底关闭。",review:"高概念设定执行得极其出色，将数字权力的哲学思辨融入紧张刺激的猫鼠游戏。男主角的表演精准刻画了权力腐蚀人性的微妙过程。AI“守护者”的设定跳出了传统反派框架，令人深思。全片充满智力挑战和道德拷问。",cover:"/141.jpg",m3u8Index:13,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子",rating:"9.4",views:309761},{id:"0015",tags:["日韩","电影","战争","恐怖","太平洋战争","超自然"],relatedIds:["0052","0009","0072","0027","0081","0010"],title:"钢锯恶魔",region:"日韩",type:"电影",year:2009,genreRaw:"战争 / 恐怖 / 动作",oneLine:"二战冲绳战役中，一支美军小队在钢锯岭遭遇以恐惧为食的日式怨灵。",summary:"1945年冲绳战役，美军陆军医疗兵戴斯蒙德所在的小队奉命攻占战略要地“钢锯岭”。然而，他们很快发现盘踞在此的日军残部行为异常，仿佛被某种东西控制。随着战斗深入，一种源自冲绳古老传说的怨灵“钢锯恶魔”显现，它以战场上士兵的恐惧和痛苦为食，并能附身于阵亡者，不分敌我地展开屠杀。戴斯蒙德凭借坚定的信仰和医疗知识，逐渐洞悉了恶魔的弱点。他必须在枪林弹雨和超自然恐怖的夹击下，带领幸存者找到被日军用于祭祀的地下神龛，终结这场人与恶灵的惨烈战斗。",review:"将残酷的历史战役与民俗恐怖完美嫁接，创造了独特的战争恐怖亚类型。战场环境的压迫感与超自然降临的惊悚感层层递进。主角用信仰对抗无形之恶的设定，为血腥战场注入了一丝悲悯而坚毅的人性光辉。",cover:"/37.jpg",m3u8Index:14,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美, 福山雅治",rating:"9.3",views:434986},{id:"0016",tags:["国产","电影","家庭","喜剧","美食","温情"],relatedIds:["0071","0074","0012","0014","0081","0013"],title:"兄弟拉面",region:"国产",type:"电影",year:2018,genreRaw:"剧情 / 家庭 / 喜剧",oneLine:"一对多年不合的兄弟，为继承父亲留下的拉面店被迫合作，在烟火气中重拾亲情。",summary:"在东京经营一家小型拉面店三十年的老师傅老陈去世，留下遗嘱：他在老家小镇的拉面铺由长期不和的两个儿子——精明的律师大哥陈志远和散漫的艺术家弟弟陈志明共同继承，且必须合作经营一年，否则店铺将捐给社区。两人被迫回到充满回忆的江南小镇，截然不同的生活方式和经营理念让冲突不断，拉面店濒临倒闭。在制作父亲招牌“兄弟豚骨面”的过程中，他们一次次失败，却也一点点拼凑出父亲未曾言说的往事与期盼。最终，他们结合各自所长，创新出属于新时代的“兄弟拉面”，也解开了多年的心结。",review:"一部充满烟火气与人情味的暖心之作。美食镜头令人垂涎，兄弟间的互动既真实好笑又催人泪下。影片通过一家小店，生动展现了中国式家庭的情感羁绊与和解过程，平淡中见真情，治愈力十足。",cover:"/133.jpg",m3u8Index:15,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美",rating:"8.6",views:421776},{id:"0017",tags:["国产","电影","喜剧","爱情","甜宠","反套路"],relatedIds:["0048","0051","0092","0066","0008","0062"],title:"嘶哈 这个男人有点儿帅",region:"国产",type:"电影",year:2021,genreRaw:"都市 / 喜剧 / 爱情",oneLine:"母胎solo的女制片人遇到“AI完美男友”测试员，在真假暧昧中笑料百出。",summary:"策划恋爱综艺屡战屡败的制片人苏晓，为打造爆款，聘请了一家科技公司的“情感体验服务”。她遇到了编号K-007的测试员林述，一个根据大数据设定的“完美男友模板”。按照合约，林述将在三个月内模拟各种浪漫情境，提供数据。苏晓一边理智地将其视为工作，一边又不由自主被这个帅气、体贴、无所不能的男人吸引。而林述在严格执行程序的过程中，也开始产生计划外的“情感误差”。当合约到期日临近，科技公司的秘密、林述的真实身份以及两人之间那些“超纲”的心动，都让这场始于虚假的关系面临真实的选择。",review:"轻松欢快的都市甜宠喜剧，设定新颖有趣。男女主化学反应十足，互动既沙雕又甜蜜。影片巧妙探讨了大数据时代下的情感真实性，笑点密集，糖分超标，是解压放松的绝佳选择。",cover:"/26.jpg",m3u8Index:16,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周",rating:"9.3",views:76861},{id:"0018",tags:["国产","电影","文艺","家庭","空巢老人","乡土"],relatedIds:["0024","0071","0051","0039","0081","0092"],title:"三秋迟暮候鸟无栖",region:"国产",type:"电影",year:2012,genreRaw:"文艺 / 家庭 / 剧情",oneLine:"一个等待候鸟归来的空巢老人，在三个秋天里独自面对村庄的消逝与记忆的留存。",summary:"在即将因修建水库而整体搬迁的南方山村，老教师周望秋独自守着祖屋。儿子在城里安家，多次催促他离开。周望秋坚持要等，他说在等一群每年深秋都会在屋后湿地停留的候鸟，那是他逝去妻子最爱的景象。电影跟随三个连续的秋天，记录周望秋的日常：教书、整理村庄档案、与日渐稀少的邻居话别、对抗拆迁队的压力。候鸟始终没有来，湿地逐渐干涸。最终，在最后一个秋天，村庄即将被淹没前夜，周望秋做出一个决定，他以自己的方式，为村庄和记忆举行了最后的仪式。",review:"影片节奏沉静如诗，画面充满东方美学意境。老人孤独的守望与时代变迁的洪流形成静默而有力的对抗。演员的表演内敛而深刻，每一个眼神和动作都承载着万千情感。这是一部关于时间、记忆与告别的深情挽歌。",cover:"/142.jpg",m3u8Index:17,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪, 宋康昊",rating:"9.4",views:142664},{id:"0019",tags:["欧美","电影","剧情","悬疑","爱情","记忆"],relatedIds:["0063","0082","0062","0015","0065","0089"],title:"纪念",region:"欧美",type:"电影",year:2005,genreRaw:"剧情 / 悬疑 / 爱情",oneLine:"一名患有超忆症的女子，被迫反复“重温”男友遇害那天的每一秒细节以寻找真凶。",summary:"艾拉患有一种罕见的超忆症，能像高清录像一样记住生命中每一天的每一处细节。她的男友马克在一场入室抢劫中被杀，案件因证据不足陷入僵局。悲痛欲绝的艾拉决定利用自己的能力，主动、反复地“回放”案发当天24小时内的所有记忆画面，从阳光的角度到路人的表情，试图找出被警方忽略的蛛丝马迹。然而，随着调查深入，她不仅发现了指向真凶的线索，更在记忆的缝隙里，看到了马克生前未曾向她展示的另一面，以及一段可能与她自身过去有关的隐秘联系。真相远比谋杀本身更令人心碎。",review:"设定极其精巧，将超忆症从猎奇设定转化为推动悬疑和情感的核心动力。女主角的表演极具层次，在理智分析与情感崩溃间游走。记忆回放的叙事方式新颖，让观众身临其境地参与解谜。结局的反转既出人意料，又在情感上浑然天成。",cover:"/1.jpg",m3u8Index:18,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪",rating:"8.0",views:287333},{id:"0020",tags:["日韩","电影","剧情","音乐","爵士","都市"],relatedIds:["0078","0010","0022","0013","0060","0082"],title:"咖啡公社",region:"日韩",type:"电影",year:2017,genreRaw:"剧情 / 音乐 / 励志",oneLine:"首尔一家面临倒闭的老派爵士咖啡馆，成为一群都市失意者重新找回生活节奏的据点。",summary:"在经济浪潮中，“蓝调音符”咖啡馆因经营不善即将被连锁品牌收购。店主兼老爵士乐手朴社长心灰意冷。这时，几个常客——遭遇创作瓶颈的网络漫画家敏熙、被公司排挤的上班族在贤、梦想破灭的前芭蕾舞者秀珍，以及一个神秘寡言的天才钢琴少年——决定联合起来，挽救这家承载他们各自回忆的咖啡馆。他们策划举办一系列地下爵士音乐会，试图让咖啡馆“起死回生”。在筹备过程中，每个人都在爵士乐即兴、自由的精神感染下，直面自己的困境，并找到了新的方向。音乐会之夜，咖啡馆的命运与所有人的未来一同被奏响。",review:"影片充满了爵士乐般的慵懒情调与即兴活力。人物群像刻画生动，每个角色都有完整的弧光。音乐不仅是背景，更是叙事的灵魂和角色成长的催化剂。温暖、治愈，又不失对现代都市人精神困境的细腻观察。",cover:"/116.jpg",m3u8Index:19,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍",rating:"8.7",views:380452},{id:"0021",tags:["国产","电影","悬疑","惊悚","密闭空间","心理"],relatedIds:["0019","0084","0055","0009","0029","0025"],title:"看不见的房客",region:"国产",type:"电影",year:2022,genreRaw:"悬疑 / 惊悚 / 剧情",oneLine:"独居盲人按摩师凭借超常听觉，察觉出租屋内还住着一个从未现身的“隐形人”。",summary:"因意外失明的按摩师陈默，租住在郊区一栋老旧公寓的顶楼。他凭借敏锐的听觉和触觉，将生活打理得井井有条。然而最近，他总感觉屋里有些“不对”：食物会莫名减少，物品的位置有细微变动，深夜会有极轻微的呼吸声。起初他以为是自己多疑，直到一次“偶然”的绊倒，让他摸到了床下不属于自己的行李箱。陈默惊恐地意识到，这个房间里，一直住着另一个“隐形”的房客。对方熟知他的一切习惯，完美地隐藏在他的盲区里。陈默不敢声张，他必须依靠自己残存的感官和智慧，在这间熟悉的“牢笼”中，与这个看不见的入侵者进行一场生死博弈。",review:"视角独特，悬念营造登峰造极。以盲人主角的感知来呈现故事，极大地增强了观众的代入感和恐惧感。密闭空间的心理压迫感十足，主角与“隐形人”的斗智斗勇紧张到令人窒息。结局的反转既残酷又充满人文关怀。",cover:"/53.jpg",m3u8Index:0,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘, 马东锡",rating:"8.0",views:319690},{id:"0022",tags:["国产","电影","喜剧","奇幻","循环","小人物的英雄主义"],relatedIds:["0007","0052","0039","0088","0058","0055"],title:"有完没完",region:"国产",type:"电影",year:2019,genreRaw:"喜剧 / 奇幻 / 剧情",oneLine:"一个懦弱的中年男人被困在女儿生日的前一天，只有学会勇敢才能打破循环。",summary:"4月1日，老实巴交的快递员老范遭遇了一系列倒霉事：被投诉、被罚款、被邻居嘲笑，最重要的是，他凑不齐答应送给女儿的生日礼物——一架昂贵的望远镜。沮丧入睡后，老范醒来，惊讶地发现时间依然是4月1日。他陷入了无尽循环。起初他利用循环投机取巧、肆意妄为，但都无法推进到4月2日。在一次次重复中，他逐渐意识到，打破循环的关键或许不是改变外界，而是改变自己。他必须克服骨子里的懦弱，在循环的最后一天里，鼓起勇气去解决那些他一直在逃避的问题：对抗不公、帮助他人、并向女儿坦诚自己的失败与爱。",review:"本土化的时间循环喜剧，笑中带泪。主角从自私懦弱到勇敢担当的成长弧光清晰感人。影片在奇幻设定下，扎实地刻画了普通中年男性的生存困境与家庭温情，既有爆笑桥段，也有直击人心的情感力量。",cover:"/60.jpg",m3u8Index:1,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘",rating:"9.2",views:410886},{id:"0023",tags:["欧美","电影","动作","犯罪","科幻","硬核追凶"],relatedIds:["0038","0062","0068","0097","0071","0065"],title:"罪证子弹3",region:"欧美",type:"电影",year:2024,genreRaw:"动作 / 犯罪 / 科幻",oneLine:"未来都市中，一颗嵌入智能纳米追踪器的子弹，成为破获跨国器官黑市的关键。",summary:"在近未来的新哥谭市，一种新型智能子弹在黑市流通。这种子弹在击中目标后，会释放纳米追踪器潜入人体，无法被常规手段检测。重案组警探米勒在调查一系列离奇失踪案时，发现所有受害者体内都被植入过这种追踪器，且都与一个名为“生命循环”的跨国医疗集团有关。米勒与曾是子弹研发者的天才工程师索菲亚联手，他们必须在24小时内，赶在受害者被用于非法器官移植前，利用最后一颗追踪子弹的反向信号，潜入防守严密的“生命循环”海上基地，揭露其背后财阀的惊天阴谋，并摧毁这个罪恶系统。",review:"系列第三部将科技设定与硬核动作结合得更加成熟。智能子弹的创意拓展了整个故事的可能性。追车、枪战、潜入戏码一气呵成，节奏紧凑。在爽快的动作场面之外，对生物科技剧情的探讨也颇具深度。",cover:"/128.jpg",m3u8Index:2,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司",rating:"8.4",views:342941},{id:"0024",tags:["日韩","电影","动画","奇幻","冒险","蒸汽朋克"],relatedIds:["0001","0002","0048","0066","0020","0044"],title:"野兽之都",region:"日韩",type:"电影",year:2006,genreRaw:"动画 / 奇幻 / 冒险",oneLine:"少年误入一座由动物统治、人类为奴的蒸汽朋克都市，成为解放同胞的关键。",summary:"在人类与智能动物共存的平行世界，少年雷在地下废墟中发现通往“贝斯特城”的传送门。贝斯特城是一座宏伟的蒸汽朋克都市，但统治者是进化出高等智慧并建立文明的动物，而人类则被视为原始劳动力，被圈养和奴役。雷被当成稀有宠物献给狮王市长，在宫廷中他结识了心怀怜悯的学者狐狸和反抗军首领猎犬。他逐渐了解到，这座城市的光鲜建立在压榨人类和掠夺资源之上。雷利用自己的智慧和人性的力量，团结起被压迫的人类和心怀不满的动物市民，策划一场颠覆阶级的革命，目标是建立一个所有物种平等共存的新城邦。",review:"想象力天马行空，动物都市的蒸汽朋克视觉奇观令人叹为观止。世界观设定细节丰富，寓言性极强，影射了阶级、种族与殖民历史。少年主角的成长与革命历程热血澎湃，兼具娱乐性与思想性，是动画电影的杰作。",cover:"/126.jpg",m3u8Index:3,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子, 长泽雅美",rating:"7.7",views:51522},{id:"0025",tags:["国产","电影","校园","歌舞","喜剧","青春"],relatedIds:["0017","0076","0064","0044","0040","0047"],title:"嗨！好少年2021",region:"国产",type:"电影",year:2021,genreRaw:"校园 / 歌舞 / 喜剧",oneLine:"一群性格各异的高中生，用一场自编自导的校园音乐剧，对抗“唯分数论”的压抑环境。",summary:"2021年，某重点高中高三“火箭班”，在严苛的班主任和升学压力下，学生们疲于奔命。转学生林晓风是个热爱音乐的“异类”，他发现同学们私下各有才华：学霸会Beatbox，体育生跳街舞一级棒，文艺委员能写动人的歌词。晓风提议，在毕业前秘密排演一场原创音乐剧《嗨！好少年》，作为对高中时代的告别。从地下筹备到克服重重阻力公开演出，这群少年在排练中碰撞、磨合，重新认识了彼此和自我，也引发了全校师生对教育本质的思考。演出当天，他们献给所有人的，不仅仅是一场表演，更是青春本该有的色彩与声音。",review:"充满活力的校园歌舞片，歌曲旋律抓耳，舞蹈编排富有创意。真实再现了当代高中生的压力与梦想，人物群像鲜明可爱。影片用音乐和热情冲破了现实的灰暗，是一部能让人重燃热血、回忆起青春美好的正能量作品。",cover:"/113.jpg",m3u8Index:4,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子",rating:"8.2",views:387402},{id:"0026",tags:["国产","电影","年代","爱情","知青","纯爱"],relatedIds:["0078","0097","0038","0046","0064","0025"],title:"心动七零栖在你心尖",region:"国产",type:"电影",year:2023,genreRaw:"年代 / 爱情 / 剧情",oneLine:"七十年代东北林场，上海知青与当地青年在冰天雪地中谱写一段含蓄而炽热的恋曲。",summary:"1972年冬，来自上海的知青苏婉清被分配到东北边陲的红星林场。身体孱弱的她难以适应严酷的环境，屡屡受挫。林场青年突击队队长、沉默可靠的本地青年陈大山受命关照她。从教她生火伐木，到为她挡下流言蜚语，两人在日复一日的劳作与互助中，产生了若有若无的情愫。然而，时代的鸿沟、家庭出身的差异以及未来的不确定性，像林海雪原一样横亘在他们之间。他们只能将心意寄托在借阅的书籍、分享的烤土豆和风雪夜归时的一盏马灯里。一场突如其来的森林大火，成为考验这份感情与信仰的熔炉。",review:"画面极具年代美感，雪原、林场、暖炕构成了一幅质朴而深情的画卷。爱情刻画极为含蓄内敛，一个眼神、一次触碰都饱含张力，完美还原了那个年代特有的情感表达方式。男女主演技细腻，将禁忌之下的暗流涌动演绎得动人肺腑。",cover:"/98.jpg",m3u8Index:5,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治",rating:"8.2",views:374928},{id:"0027",tags:["国产","电影","家庭","剧情","剧情","感人"],relatedIds:["0061","0099","0010","0002","0007","0083"],title:"天下父母心",region:"国产",type:"电影",year:2008,genreRaw:"家庭 / 剧情",oneLine:"一对农村夫妇倾尽所有供养养子成才，二十年后却面临亲子回归与养子离去的双重抉择。",summary:"赵家村农民赵大山和妻子桂兰，二十年前收养了被遗弃在村口的男婴小宝，视如己出。他们节衣缩食，甚至让亲生女儿早早辍学打工，全力供养天资聪颖的小宝读书。小宝不负期望，考入名牌大学，留城工作，成为全村骄傲。就在老两口憧憬晚年团聚时，小宝的亲生父母——一对事业有成的城市夫妇找上门来，希望认回儿子。与此同时，赵家的亲生女儿也带着生病的丈夫和孩子回到娘家求助。一面是养子的犹豫与疏远，一面是亲生女儿的困境与愧疚，赵大山和桂兰那份无私的“父母心”，在血缘、恩情与现实的撕扯中，经历着最残酷的考验。",review:"影片直面中国式家庭最核心的剧情困境，情感冲击力极强。演员表演朴实无华却极具穿透力，尤其是父母面对抉择时的沉默与眼泪，堪称催泪弹。故事没有简单的对错评判，而是深刻揭示了爱与牺牲的复杂维度，引人深思。",cover:"/139.jpg",m3u8Index:6,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周, 李秉宪",rating:"8.0",views:175620},{id:"0028",tags:["欧美","电影","战争","剧情","悬疑","人性拷问"],relatedIds:["0019","0020","0045","0043","0087","0017"],title:"无目标地区",region:"欧美",type:"电影",year:2015,genreRaw:"战争 / 剧情 / 悬疑",oneLine:"一支奉命深入敌后摧毁“无目标”的精英小队，在荒野中逐渐迷失任务与自我的意义。",summary:"阿富汗战争后期，一支由多国士兵组成的特种小队接到绝密指令：深入兴都库什山脉的“无目标地区”，定位并摧毁一个“高价值目标”，目标具体信息将在抵达坐标点后解锁。小队历经艰险抵达指定地点，接收到的最终指令却只有一句话：“判断并处置。”没有具体目标，没有进一步情报。在荒芜的山谷中，怀疑与猜忌在队员间滋生。他们遇到了当地的牧羊人家庭、神秘的洞穴壁画、以及似有若无的监视感。士兵们开始争论“目标”究竟是什么：是隐藏在平民中的敌人？是这片土地本身？还是他们内心不断滋长的暴力与恐惧？小队濒临分裂，任务走向完全失控。",review:"反战主题的深刻之作。剥去了战争片的火爆外壳，深入探讨了命令、道德与人性在极端环境下的冲突。影片氛围营造出色，无尽的荒原如同心理迷宫。开放式结局留给观众巨大的思考空间，后劲十足。",cover:"/31.jpg",m3u8Index:7,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周",rating:"9.4",views:51705},{id:"0029",tags:["国产","电影","历史","剧情","传记","女性"],relatedIds:["0070","0051","0016","0078","0036","0077"],title:"红颜暗老白发新",region:"国产",type:"电影",year:2014,genreRaw:"历史 / 剧情 / 传记",oneLine:"唐朝一位才女历经四朝沉浮，在政治与爱情的漩涡中，以诗词记录一生的风华与沧桑。",summary:"影片以晚年上官婉儿的回忆展开，追溯她从罪臣之女入宫为婢，凭借超凡的才华与机敏，得到武则天赏识，成为女皇的近身女官，参与机要。她周旋于李唐皇室与武周权力核心，见证了神龙政变、韦后乱政等一系列重大历史事件。她与宰相李逸、诗人崔湜等人有过深刻的情感纠葛，但政治始终是她无法挣脱的牢笼。从“红颜”权倾一时，到“暗老”卷入政变，最终在唐玄宗发动先天政变时被赐死。她的一生，犹如一面镜子，映照出大唐盛世光环下，女性知识分子的智慧、挣扎与命运。",review:"制作精良的历史正剧，服化道高度还原盛唐气象。女主角的表演极具张力，完美诠释了上官婉儿在权力、才华与情感间的复杂心境。影片以诗入史，文白相间的台词古朴典雅，勾勒出一幅波澜壮阔又充满个人悲欢的历史长卷。",cover:"/137.jpg",m3u8Index:8,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊",rating:"7.9",views:397073},{id:"0030",tags:["欧美","电影","动作","惊悚","犯罪","感官挑战"],relatedIds:["0063","0066","0045","0083","0023","0006"],title:"盲眼杀机",region:"欧美",type:"电影",year:2011,genreRaw:"动作 / 惊悚 / 犯罪",oneLine:"一位失明的退伍特种兵，必须依靠其他感官在黑暗中保护家人，对抗入室的职业杀手。",summary:"因伤失明的退伍老兵约翰，与妻子和年幼的女儿住在郊区。一天夜里，一群手段专业的劫匪为寻找一份误送至他家的加密硬盘闯入家中。约翰的妻子不幸中弹昏迷。在电力被切断的完全黑暗环境中，视觉的丧失反而成了约翰的优势——他早已适应黑暗，听力、触觉和空间感远超常人。而劫匪们则被困在陌生的黑暗环境里。约翰利用对家中每一寸布局的熟悉，将房子变成狩猎场，凭借军事训练留下的本能，与劫匪展开了一场惊心动魄的“盲眼”周旋。他不仅要消灭敌人，还要在时限内找到药品挽救妻子的生命。",review:"创意十足的高概念动作惊悚片。将主角的缺陷转化为优势的设定非常巧妙。在有限空间内的黑暗追逐与搏杀戏，紧张感拉满，令人屏息。男主角的表演真实可信，展现了非凡的体能和坚毅的父爱，观影体验如同亲身参与一场黑暗中的生存游戏。",cover:"/32.jpg",m3u8Index:9,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍, 孔刘",rating:"7.7",views:391017},{id:"0031",tags:["国产","电影","喜剧","奇幻","爱情","反套路","穿书"],relatedIds:["0069","0062","0038","0028","0068","0011"],title:"穿书后，她把悲剧变爽文",region:"国产",type:"电影",year:2024,genreRaw:"喜剧 / 奇幻 / 爱情",oneLine:"社畜女孩穿成虐文里活不过三章的恶毒女配，她决定放弃剧情，专心搞钱和享受人生。",summary:"天天加班到崩溃的普通白领林小小，一觉醒来发现自己穿进了最近熬夜追读的古风虐文《权倾朝野》里，成了同名同姓、即将被男主利用完就抛弃的恶毒女配林晚晚。按照原剧情，她将在三章后惨死。林小小欲哭无泪，但很快决定：去他的剧情和男主！手握剧本就是最大金手指。她提前救下未来会成为富商的关键配角，利用现代知识开火锅店、办快递、搞投资，赚得盆满钵满。当原著男主还在忙着和女主虐恋情深时，林晚晚已经成了京城首富。只是，那个原著里一笔带过的病弱王爷，看她的眼神怎么越来越不对劲？他似乎……也知道剧情？",review:"轻松解压的“反内卷”穿书喜剧，笑点密集且符合当下网络文化。女主“事业脑”清醒又可爱，彻底颠覆了传统言情套路。与王爷的副线感情发展甜而不腻。影片完美抓住了“爽文”精髓，让观众跟着女主一路畅快逆袭。",cover:"/97.jpg",m3u8Index:10,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍",rating:"9.3",views:296534},{id:"0032",tags:["欧美","电影","动画","冒险","家庭","西部","马"],relatedIds:["0063","0017","0021","0094","0012","0080"],title:"小马王",region:"欧美",type:"电影",year:2002,genreRaw:"动画 / 冒险 / 家庭",oneLine:"一匹热爱自由的野马之王，在西部拓荒时代，与一位年轻的印第安少年建立跨越种族的友谊。",summary:"在广袤的美国西部，野马群的首领、充满灵性的黑色骏马“精灵”无忧无虑地生活着。19世纪末，白人拓荒者的铁路延伸至此，精灵在一次人类围捕中被俘，并被运往骑兵营地。在那里，它拒绝被驯服，遇到了同样渴望自由的印第安少年小溪。小溪理解并尊重精灵的野性，两人在困境中建立起信任。精灵帮助小溪逃离了压迫他的环境，而小溪则帮助精灵挣脱束缚，回归家园。他们一同穿越壮丽的西部荒原，躲避追捕，对抗自然险阻，谱写了一曲关于自由、尊严与友谊的永恒赞歌。",review:"梦工厂的经典2D动画，画面壮丽恢弘，配乐激昂动人。全片几乎没有对白，依靠卓越的动画表演和音乐叙事，情感传递却无比直接有力。精灵的野性与不屈精神被刻画得极具感染力，是一部适合所有年龄观众欣赏的艺术精品。",cover:"/82.jpg",m3u8Index:11,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡",rating:"9.2",views:292226},{id:"0033",tags:["日韩","电影","剧情","家庭","公路","治愈"],relatedIds:["0009","0089","0079","0100","0020","0022"],title:"快要出发啦",region:"日韩",type:"电影",year:2010,genreRaw:"剧情 / 家庭 / 公路",oneLine:"患有阿尔茨海默症的老父亲，在记忆彻底消失前，执意要带成年子女进行最后一次家庭旅行。",summary:"年迈的山下勇介确诊阿尔茨海默症，病情正在快速侵蚀他的记忆。某天，他固执地要求分散在各地、关系疏远的三个子女立刻回家，并宣布要全家一起开车去北海道，完成一场“快要出发啦”的旅行。子女们各自带着生活的烦恼和不情愿上路。旅途中，父亲时常认错人、记错事，但也时常在模糊的记忆碎片中，说出他们早已遗忘的童年趣事，流露出深藏的关爱。随着旅程推进，子女们开始理解父亲此举的深意——他是在用最后清晰的意识，努力修补家庭的裂痕，为孩子们留下关于“家”的最后一份完整记忆。旅程的终点，也是告别的开始。",review:"一部温柔而伤感的公路电影，情感细腻如水。阿尔茨海默症父亲的设定，让每一次回忆与遗忘都充满张力。旅途中的自然风光与家庭内部的微妙变化相得益彰。影片不着痕迹地探讨了记忆、亲情与告别，感人至深，余韵悠长。",cover:"/150.jpg",m3u8Index:12,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司, 松隆子",rating:"9.3",views:170439},{id:"0034",tags:["欧美","电影","恐怖","惊悚","冒险","丛林","生存"],relatedIds:["0017","0048","0058","0077","0091","0074"],title:"致命弯道2",region:"欧美",type:"电影",year:2007,genreRaw:"恐怖 / 惊悚 / 冒险",oneLine:"一群参与野外真人秀的选手，误入变异食人家族的领地，被迫进行最残酷的生存游戏。",summary:"一档名为“极限求生”的真人秀节目，将六名选手空投至一片偏远的国家森林保护区。他们需要依靠有限的装备在规定时间内到达集合点。然而，他们很快发现自己并非森林里唯一的“玩家”。这片土地被一群因长期近亲繁殖和环境污染而产生变异、残暴嗜血的“山野家族”所统治。参赛者们从猎人变成了猎物，在迷宫般的森林和废弃矿洞中逃窜，一个接一个被家族成员用各种残忍原始的方式猎杀。幸存者们必须抛弃比赛规则，利用智慧和求生本能，团结起来对抗这些超出常理的恐怖存在，寻找一线生机。",review:"经典丛林恐怖片的成功续作，在血浆和杀戮场面上升级，更加直接刺激。变异家族的设定增加了恐怖感和猎奇性。密闭森林环境带来的压迫感和未知恐惧营造得相当出色，节奏紧凑，从头到尾惊险不断，是纯粹的感官刺激盛宴。",cover:"/51.jpg",m3u8Index:13,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司",rating:"8.2",views:310720},{id:"0035",tags:["日韩","电影","剧情","惊悚","剧情","医疗","心理"],relatedIds:["0082","0011","0091","0010","0056","0055"],title:"护理师",region:"日韩",type:"电影",year:2020,genreRaw:"剧情 / 惊悚 / 剧情",oneLine:"一位居家护理师对独居老人无微不至的照顾背后，隐藏着获取遗产的精密计划与道德挣扎。",summary:"专业且富有同情心的护理师惠子，受雇照顾独居的富有的退休企业家森田先生。森田先生患有轻度痴呆，子女远在国外。惠子的照顾无可挑剔，很快赢得了老人的完全信任和依赖，甚至开始修改遗嘱，将大部分财产留给她。然而，这一切都是惠子精心设计的计划。她出身贫困，曾因家人无钱治病而留下心理创伤，决心利用职业之便“劫富济贫”。但随着与森田先生如父女般的情感日益加深，惠子陷入了巨大的道德困境。与此同时，森田先生的律师儿子开始对惠子产生怀疑，一场关于信任、贪婪与救赎的心理拉锯战悄然展开。",review:"影片在平静的日常下暗流涌动， suspense 营造得极为出色。女主角的表演复杂而深刻，将角色的算计、矛盾与良知觉醒演绎得淋漓尽致。故事尖锐地触及了老龄化社会中的信任危机与剧情边界，结局令人深思且颇具震撼力。",cover:"/120.jpg",m3u8Index:14,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美",rating:"8.7",views:296685},{id:"0036",tags:["国产","电影","剧情","都市","复仇","女性成长"],relatedIds:["0019","0077","0030","0042","0033","0055"],title:"确诊后我让渣男一家付出代价",region:"国产",type:"电影",year:2023,genreRaw:"剧情 / 都市 / 复仇",oneLine:"家庭主妇确诊绝症后，冷静利用剩余时间，精心策划对出轨丈夫和婆家的终极反击。",summary:"全职主妇苏蔓为家庭付出十年，却换来丈夫陈哲的冷漠与出轨。当她被确诊罹患晚期癌症，生命仅剩数月时，婆家第一反应竟是算计她的保险金和如何让儿子尽快再婚。极度的悲愤让苏蔓从绝望中清醒。她隐瞒病情，开始冷静地搜集丈夫转移财产、出轨、以及婆家公司税务问题的证据。她利用最后的时间，学习法律和金融知识，巧妙布局：一步步收回赠予娘家的财产，将丈夫的出轨对象变成“盟友”，并在婆家最重要的商业项目签约当天，送上了一份包含所有罪证的“大礼”。她不是要同归于尽，而是要夺回尊严，并为自己年迈的父母和年幼的妹妹留下保障。",review:"一部极其爽快又充满力量的女性复仇电影。没有依靠外力，女主角凭借智慧和坚韧完成绝地反击，过程缜密且符合逻辑。情感铺垫到位，让观众的共鸣与代入感极强。在“爽感”之外，也对婚姻、女性价值进行了深刻反思。",cover:"/131.jpg",m3u8Index:15,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治, 韩孝周",rating:"7.5",views:92149},{id:"0037",tags:["国产","电影","古装","喜剧","爱情","甜宠","欢喜冤家"],relatedIds:["0023","0073","0096","0049","0083","0041"],title:"公子不可求",region:"国产",type:"电影",year:2022,genreRaw:"古装 / 喜剧 / 爱情",oneLine:"立志不嫁豪门的小镇女医师，被迫给受伤失忆的傲娇王爷当保姆，笑闹间情根深种。",summary:"小镇医馆的女医师陆小鱼医术高明，性格独立，立志悬壶济世，绝不攀附权贵。一日，她在河边捡到一个身受重伤、失去记忆的俊美男子，无奈将其带回家中医治。男子虽然失忆，但挑剔、傲娇、难伺候的本性不改，自称“本王”，闹出不少笑话。小鱼给他起名“阿贵”，一边行医一边当他的保姆，两人在吵吵闹闹中渐生情愫。然而，阿贵的记忆逐渐恢复，他正是当朝权势滔天的靖王。追兵与阴谋接踵而至，小鱼这才知道，她捡到的不仅是“麻烦”，更是一场涉及皇权争夺的巨大漩涡。面对身份鸿沟与生死危机，这段始于荒唐的感情将何去何从？",review:"古装轻",cover:"/92.jpg",m3u8Index:16,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治",rating:"8.4",views:413305},{id:"0038",tags:["欧美","电影","奇幻","喜剧","动物视角","社会寓言"],relatedIds:["0071","0058","0092","0002","0050","0035"],title:"浣熊：新欧洲人",region:"欧美",type:"电影",year:2018,genreRaw:"奇幻喜剧 / 社会寓言",oneLine:"一群被基因改造的浣熊移民欧洲，以独特智慧引发社会连锁反应。",summary:"在不远的未来，一群经基因改造拥有超高智力的浣熊被秘密投放至欧洲大陆，它们自称“新欧洲人”。它们不像人类想象的那样发动战争，而是通过金融、法律和政治等“文明”手段，巧妙渗透人类社会。它们成立了空壳公司，钻营法律漏洞，甚至参与议会竞选，逐步在欧洲社会获得一席之地。故事以一只名叫“策略家”的浣熊为主角，它试图在人类世界的规则下为族群争取生存空间和“公民身份”，引发了一系列啼笑皆非又发人深省的事件。最终，它们的存在迫使人类重新审视“文明”、“权利”与“物种”的边界。",review:"影片以极致的黑色幽默和讽刺手法，探讨了移民、身份认同与文明冲突等严肃议题。浣熊们的“文明入侵”方式出人意料，笑点密集却不失深度，动物视角的叙事让观众在捧腹之余陷入沉思。",cover:"/85.jpg",m3u8Index:17,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪",rating:"7.7",views:248721},{id:"0039",tags:["欧美","电影","恐怖","惊悚","灾难","动作","小镇危机"],relatedIds:["0033","0013","0092","0070","0088","0006"],title:"杀出狂人镇1973",region:"欧美",type:"电影",year:1973,genreRaw:"恐怖惊悚 / 灾难动作",oneLine:"军方病毒泄露，宁静小镇居民变异成嗜血狂人，幸存者艰难求生。",summary:"1973年，美国一座宁静的矿业小镇“安宁镇”附近，军方秘密研究的生化武器因事故泄露。泄露的病毒通过水源迅速传播，感染者在短时间内变得极具攻击性且力大无穷，沦为只知杀戮的“狂人”。小镇顷刻间变影视间地狱。镇上的警长大卫·威尔逊，在混乱中勉强组织起包括医生、教师和矿工在内的几名幸存者，他们必须利用有限的武器和资源，一面躲避狂人潮的追杀，一面试图找到离开被军方封锁的小镇的方法。在逃亡过程中，他们不仅要对抗外部的恐怖，还要面对内部因绝望而产生的分裂与猜忌。",review:"一部奠定了后世僵尸/感染题材范式的经典之作。影片节奏紧凑，氛围营造出色，对人性在极端压力下的刻画真实而残酷。1973年的特效现在看来依旧毛骨悚然，展现了纯粹的生存恐惧。",cover:"/39.jpg",m3u8Index:18,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊, 全度妍",rating:"8.8",views:370124},{id:"0040",tags:["国产","电影","家庭","剧情","都市","情感","非遗传承"],relatedIds:["0099","0030","0046","0003","0047","0045"],title:"灯火阑珊",region:"国产",type:"电影",year:2021,genreRaw:"家庭剧情 / 都市情感",oneLine:"香港霓虹招牌逐渐消失，丧夫女人为完成亡夫遗愿，重拾造灯手艺。",summary:"香港，霓虹招牌曾是这座不夜城最璀璨的印记，如今却因法规和LED的普及而逐渐暗淡、消失。美香在中年丧夫后陷入巨大悲痛，终日郁郁寡欢。在整理亡夫阿鑣遗物时，她发现了一卷未完成的手绘霓虹灯设计图。阿鑣曾是本地最后一批霓虹灯师傅之一。为了完成丈夫未竟的梦想，也为了寻回与丈夫共同的记忆，美香决心拜师于阿鑣性情古怪的师兄，从头学习这门濒临失传的手艺。从抗拒到沉浸，制作霓虹灯的过程成了美香治愈伤痛、重新与城市记忆以及自我连接的旅程。当最后一盏属于他们夫妻的霓虹灯在巷尾亮起，灯火阑珊处，是告别，也是新生。",review:"影片情感细腻含蓄，以“霓虹灯”这一视觉符号，巧妙串联起个人情感、夫妻情谊与城市变迁。张艾嘉的表演层次丰富，将丧偶之痛与重寻生命力的过程演绎得感人至深，是一部充满人文关怀的佳作。",cover:"/7.jpg",m3u8Index:19,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊",rating:"8.2",views:71973},{id:"0041",tags:["国产","电影","警匪","动作","悬疑","硬核","战术"],relatedIds:["0025","0089","0062","0018","0100","0055"],title:"特警风暴",region:"国产",type:"电影",year:2008,genreRaw:"警匪动作 / 悬疑",oneLine:"特警小队护送关键证人，却陷入内外交困的致命陷阱。",summary:"滨海市，一桩重大的跨国走私案即将开庭，唯一的关键证人“金丝雀”成为各方势力争夺的焦点。特警支队“锐锋”小组奉命执行最高级别的证人护送任务，从安全屋转移至法院。然而行动伊始便遭遇前所未有的精准伏击，小队伤亡惨重，“金丝雀”被劫。队长高峻凭借丰富经验带领剩余队员杀出重围，却发现通讯被屏蔽，支援迟迟不到，仿佛有一双无形的黑手在操控一切。他们被迫在城市中与装备精良的雇佣兵周旋，同时还要警惕内部可能存在的“鬼”。高峻必须在有限的时间内，查明真相，揪出内奸，并夺回证人，一场关乎正义与信任的风暴席卷了整个特警队。",review:"影片动作场面火爆真实，战术细节考究，堪称国产特警题材的硬核之作。剧情环环相扣，悬念设置巧妙，兄弟情与背叛的冲突刻画有力，让观众肾上腺素飙升的同时也深感人心叵测。",cover:"/102.jpg",m3u8Index:0,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘",rating:"8.9",views:253170},{id:"0042",tags:["日韩","电影","青春","运动","热血","励志","夏日"],relatedIds:["0047","0031","0061","0011","0075","0059"],title:"燃夏",region:"日韩",type:"电影",year:2019,genreRaw:"运动青春 / 热血励志",oneLine:"一支屡战屡败的高中棒球队，在最后一个夏天向甲子园发起绝望冲锋。",summary:"位于日本乡下的岬角高中棒球队“海鸥队”，是一支连续十几年未曾突破地区预选赛第一轮的“鱼腩”球队。高三的夏天是队长大泽勇树和几位主力队员最后的赛季。新来的教练是个看似散漫的前职棒球员，他带来了全新的训练方法和不拘一格的战术。球队起初冲突不断，但在一次次失败和磨合中，这群原本只为混日子或享受青春的男孩，逐渐燃起了对胜利的真实渴望。他们用汗水浸透燥热的夏日，用伤痕装饰青春的勋章。面对地区内实力悬殊的强大对手，海鸥队拼尽全力，打出了一场场令人动容的比赛。这个夏天，输赢或许已不重要，那份共同燃烧过的热血，将成为他们一生的财富。",review:"典型的日式热血运动番电影化，情感真挚饱满。球场上的拼搏与球场下的友情交织，笑点与泪点并存。影片完美捕捉了夏日、汗水与青春的气息，能让所有经历过青春的人产生共鸣。",cover:"/19.jpg",m3u8Index:1,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡, 役所广司",rating:"9.0",views:449302},{id:"0043",tags:["国产","电影","悬疑","犯罪","心理","惊悚","高智商对决"],relatedIds:["0016","0073","0004","0053","0046","0008"],title:"无迹可寻",region:"国产",type:"电影",year:2022,genreRaw:"悬疑犯罪 / 心理惊悚",oneLine:"完美密室谋杀案，凶手未留任何痕迹，警探被迫与嫌疑犯玩心理游戏。",summary:"本市著名企业家在自家守卫森严、监控完备的别墅书房内离奇死亡，现场是一个完美的密室，没有外来侵入痕迹，没有找到凶器，甚至没有留下任何指向性的物理证据，堪称“无迹可寻”。刑侦专家沈严受邀参与调查，所有证据都隐隐指向死者的私人心理医生林莫。林莫智商极高，性格冷静，对沈严的询问对答如流，甚至带着一丝挑衅。在缺乏实证的情况下，沈严决定采取非常规手段，与林莫展开一场惊心动魄的心理攻防战。他深入林莫的过去，挖掘其可能的动机，试图在对方精密的心理防线上找到裂痕。然而，随着调查深入，沈严发现自己似乎正被林莫引导向一个更大的谜团。",review:"影片摒弃了传统刑侦片的血腥暴力，专注于高智商的逻辑对决和心理博弈，悬念一直保持到最后一刻。两位主演的演技交锋十分精彩，氛围营造极佳，让观众沉浸在解谜的紧张感中。",cover:"/89.jpg",m3u8Index:2,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡",rating:"8.9",views:386520},{id:"0044",tags:["国产","电影","奇幻","剧情","乡土","传奇","女性成长"],relatedIds:["0080","0004","0011","0083","0028","0069"],title:"凤栖凤息回故乡",region:"国产",type:"电影",year:2024,genreRaw:"奇幻剧情 / 乡土传奇",oneLine:"都市白领继承偏远山村老宅，意外唤醒守护家族的凤凰之灵。",summary:"在广告公司疲于奔命的苏晓，突然接到通知，继承了从未谋面的外婆在西南深山老家“凤栖村”的一幢古老宅院“凤栖阁”。身心俱疲的她决定暂时逃离都市，前往处理遗产。在整理老宅时，她触动了古老的家族信物，意外唤醒了一只栖息在宅院深处的凤凰之灵“凤息”。凤息告知苏晓，她是家族这一代的血脉守护者，凤栖阁镇压着山中的地脉戾气。与此同时，开发商看中了凤栖村的环境，计划进行大规模旅游开发，这将破坏地脉平衡。苏晓在凤息的引导下，逐渐了解了家族历史与自然共存的古老智慧，并联合留守的村民，运用凤凰赋予的微弱灵力和现代知识，寻找既能保护家园又能让村子可持续发展的道路。",review:"将中国神话元素与现代乡村议题结合得十分巧妙。画面充满东方美学意境，凤凰的形象瑰丽而富有灵气。故事内核是关于回归、传承与平衡，女主角的成长弧光清晰动人，是一部治愈又充满想象力的作品。",cover:"/11.jpg",m3u8Index:3,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子",rating:"9.4",views:145501},{id:"0045",tags:["日韩","电影","悬疑","惊悚","科幻","脑洞","高概念"],relatedIds:["0001","0046","0090","0077","0088","0083"],title:"谋杀预想",region:"日韩",type:"电影",year:2016,genreRaw:"悬疑惊悚 / 科幻",oneLine:"男子获得预知他人死亡片段的能力，却发现自己成为下个目标的“目击者”。",summary:"平凡的保险公司调查员小林拓真，在一次意外事故后，获得了诡异的能力：当他与某人发生肢体接触时，偶尔会“看见”该人物未来可能死亡的短暂片段。这些片段模糊、跳跃，如同噩梦的剪影。起初他惶恐不安，试图用这些预知去避免悲剧，却往往弄巧成拙，甚至被警方怀疑。直到有一天，他在与一位陌生女子擦肩而过的瞬间，“看见”了自己被杀害的清晰景象，而凶手的背影赫然就是那名女子。恐惧的小林开始疯狂寻找这名女子，试图改变自己的命运。然而，他越是追查，就越陷入一个更大的阴谋，并发现自己的这种能力，或许并非偶然。",review:"设定新颖，将预知能力与谋杀悬疑结合，创造了极强的心理压迫感。剧情不断反转，节奏掌控出色。影片探讨了命运是否可改的哲学命题，在惊悚的外壳下有着耐人寻味的内核。",cover:"/67.jpg",m3u8Index:4,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美, 福山雅治",rating:"9.2",views:286326},{id:"0046",tags:["日韩","电影","爱情","奇幻","纯爱","治愈","记忆"],relatedIds:["0074","0021","0063","0014","0015","0032"],title:"只属于我",region:"日韩",type:"电影",year:2015,genreRaw:"纯爱 / 奇幻",oneLine:"女孩患怪病记忆每日清零，男孩用日记和爱意为她重建“只属于我”的世界。",summary:"高中生筱原葵患上一种罕见的短期记忆障碍，每天醒来，前一天的记忆都会清零，仿佛人生永远停留在“今天”。她的世界是孤岛。转学生藤堂律默默关注着葵，并决定走进她的世界。每天，律都会以“初次见面”的方式与葵相识，送她回家，陪她做同样的事情。律为葵准备了一本厚厚的日记，每天由葵在睡前记录下当天的点滴，尤其是关于“律”的事情。第二天，葵通过阅读日记，来认识这个“只属于我”的男孩和他们的故事。这个过程充满笨拙的重复与心酸的浪漫。然而，葵的病情可能恶化，而律的家庭即将搬离……这场与时间赛跑的爱情，能否创造奇迹？",review:"极致纯粹的日系纯爱片，设定催泪但叙事清新。影片用大量重复的日常场景堆积出感人至深的情感力量，展现了“爱是无数个今天叠加的永恒”。演员表演自然真挚，触动人心底最柔软的部分。",cover:"/30.jpg",m3u8Index:5,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美",rating:"8.7",views:113061},{id:"0047",tags:["国产","电影","动作","剧情","兄弟","亲情","硬汉柔情"],relatedIds:["0064","0097","0017","0090","0089","0078"],title:"龙的心",region:"国产",type:"电影",year:2020,genreRaw:"动作剧情 / 兄弟情",oneLine:"退役特种兵哥哥为保护有智力障碍的弟弟，卷入黑帮纷争，以拳护亲。",summary:"退役特种兵王龙，因伤离开部队后，独自承担起照顾患有轻度智力障碍的弟弟王虎的责任。弟弟虽然二十多岁，心智却如孩童，单纯善良，是王龙生命中最柔软的部分。王龙在码头做搬运工，生活清苦但平静。然而，当地黑帮为争夺码头控制权，试图利用王虎的单纯让他运送违禁品。王龙为保护弟弟，坚决反抗，因此惹祸上身，兄弟二人遭到黑帮的步步紧逼和残酷报复。被触犯逆鳞的王龙，为守护弟弟和心中的正义，决定不再隐忍。他运用军中练就的过硬本领，以暴制暴，向黑恶势力发起凌厉反击。这是一场为亲人而战的生存之战，展现了铁汉背后最温柔的“龙的心”。",review:"影片动作设计刚猛凌厉，实战感强。兄弟情的刻画是最大亮点，硬汉哥哥与天真弟弟的互动感人至深，摆脱了单纯的动作爽片模式，赋予了故事厚重的情感内核和现实温度。",cover:"/83.jpg",m3u8Index:6,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周",rating:"9.0",views:290352},{id:"0048",tags:["国产","电影","喜剧","家庭","情感","重生","团宠","女性"],relatedIds:["0040","0005","0016","0053","0026","0034"],title:"重生后我被姐姐们团宠",region:"国产",type:"电影",year:2023,genreRaw:"都市喜剧 / 家庭情感",oneLine:"备受忽视的小妹重生回童年，决心改变，却意外成为全家姐妹团宠中心。",summary:"35岁的林小溪在家庭中一直是最被忽视的小女儿，性格怯懦，人生平淡。一场意外后，她竟重生回7岁那年。带着前世记忆，她决定不再讨好任何人，要为自己而活。她冷静地指出大姐的男友是渣男，帮二姐解决了校园霸凌，用“童言无忌”点醒忙于工作的父母多关心三姐的心理健康……她原本只想避免家人重复前世的悲剧，却没想到，这一系列操作让她在三个姐姐眼中的形象彻底改变。从前对她爱答不理的姐姐们，现在纷纷把她当成“福星”和“贴心小军师”，争相对她好。林小溪在懵懂中，陷入了被姐姐们“过度关爱”的甜蜜烦恼，也在这个过程中，真正理解了亲情与爱的含义。",review:"轻松下饭的都市轻喜剧，重生设定玩出了新意，不再专注于复仇或开挂，而是聚焦家庭关系和情感治愈。姐妹间的互动温馨有趣，“团宠”剧情满足观众情感需求，笑点自然，充满生活气息。",cover:"/3.jpg",m3u8Index:7,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪, 宋康昊",rating:"9.4",views:299973},{id:"0049",tags:["国产","电影","爱情","喜剧","都市","经典","群像"],relatedIds:["0009","0012","0073","0047","0017","0028"],title:"爱情是什么国语第一部",region:"国产",type:"电影",year:1999,genreRaw:"都市爱情 / 情景喜剧",oneLine:"九十年代末，北京胡同大杂院里，几对男女用欢声笑语探讨“爱情是什么”。",summary:"影片背景设定在1998年的北京，一个热闹的胡同大杂院里。住着心直口快的出租车司机大民、文艺青年兼书店店员苏雯、留学归来创业的海归李昂、泼辣能干的餐馆老板娘彩霞等性格各异的年轻人。故事围绕他们展开，通过一系列生活化的喜剧情节——如相亲乌龙、创业挫折、邻里纠纷、友情考验等，生动展现了那个时代年轻人对待爱情、婚姻和事业的不同态度与困惑。没有狗血的多角恋，只有平凡生活中真诚的喜怒哀乐。他们在磕磕绊绊中寻找答案，用京味十足的幽默语言，演绎了一幅九十年代末都市青年的爱情与生活浮世绘。片名“爱情是什么”，既是角色的自问，也留给观众思考。",review:"一部充满时代印记与生活质感的经典爱情喜剧。人物鲜活立体，台词幽默接地气，宛如中国版的《老友记》。它不刻意煽情，却在琐碎的日常中捕捉到了爱情与友情的真谛，让人回味无穷。",cover:"/10.jpg",m3u8Index:8,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪",rating:"7.6",views:280238},{id:"0050",tags:["日韩","电影","恐怖","惊悚","复仇","校园","心理阴影"],relatedIds:["0038","0026","0066","0046","0071","0076"],title:"老师的恩惠",region:"日韩",type:"电影",year:2006,genreRaw:"恐怖惊悚 / 复仇",oneLine:"退休老师举办谢师宴，当年学生们接连以诡异方式惨死，往昔秘密浮出水面。",summary:"德高望重的退休女教师朴孝真举办生日宴，邀请了七名她曾认为最有出息的学生。宴会在一处偏远的别墅举行。起初气氛怀旧温馨，学生们纷纷表达对老师的感激。然而，随着一场暴风雨切断了与外界的联系，恐怖事件接连发生。学生们一个接一个地以极其残忍且带有“惩罚”意味的方式被杀害，凶手似乎就在他们中间。在极度的恐惧中，彼此猜忌爆发，而深埋多年、关于学生时代因朴老师的一句话、一个决定或一次偏袒而改变命运、留下心理创伤的秘密，也逐渐被揭开。原来，这场“谢师宴”并非为了感恩，而是一场精心策划的复仇。所谓的“恩惠”，有时是蜜糖，有时也可能是毒药。",review:"日韩恐怖片的经典之作，将校园心理阴影与密闭空间屠杀结合得天衣无缝。悬念设置层层递进，反转出人意料。影片对“师恩”与“伤害”的辩证探讨令人不寒而栗，后劲十足。",cover:"/90.jpg",m3u8Index:9,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍",rating:"7.8",views:329330},{id:"0051",tags:["国产","电影","爱情","音乐","治愈","浪漫","失意人生"],relatedIds:["0020","0062","0040","0064","0010","0057"],title:"悄然走进你的世界",region:"国产",type:"电影",year:2017,genreRaw:"爱情 / 音乐",oneLine:"失意小提琴手遇见失明女孩，用音乐为她描绘世界，两人彼此照亮人生。",summary:"曾经的天才小提琴手顾泽，因一场比赛失利和手部旧伤，职业生涯跌入谷底，变得颓废孤僻。他在一家盲人按摩店对面租了间陋室，每日与酒为伴。偶然间，他遇到了按摩店的盲人女孩苏晓晓。晓晓虽然看不见，却对世界充满好奇与热情，能用耳朵“听”出色彩和形状。被晓晓的生命力触动，顾泽开始用音乐为她描述他眼中的世界：清晨的露珠是哪个音符，黄昏的街道是什么旋律。他重拾小提琴，为晓晓创作独一无二的乐曲。在这个过程中，顾泽不仅为晓晓打开了感知世界的另一扇窗，自己的创作灵感和生活热情也被重新点燃。两个失意的人，以音乐为桥，悄然走进了彼此的世界，相互救赎。",review:"影片风格清新文艺，音乐元素融入得恰到好处，几首原创小提琴曲动人心弦。爱情的发生自然而然，没有刻意煽情，着重刻画了两人心灵上的相互靠近与扶持，治愈感满满。",cover:"/74.jpg",m3u8Index:10,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘, 马东锡",rating:"8.6",views:278614},{id:"0052",tags:["国产","电影","奇幻","冒险","动作","悬疑","唐朝","志怪"],relatedIds:["0100","0065","0026","0023","0038","0012"],title:"唐朝异闻录",region:"国产",type:"电影",year:2025,genreRaw:"奇幻冒险 / 动作悬疑",oneLine:"不良人小吏搭档神秘方士，专司调查长安城内光怪陆离的“异闻”事件。",summary:"开元盛世下的长安城，繁华似锦，却也暗流涌动，流传着诸多科学无法解释的“异闻”。李不语，是长安县衙一名不得志的不良人（类似刑警），因不信鬼神、只信证据而屡遭排挤。他被迫与一位被朝廷招安的神秘方士玄灵子组成搭档，成立“异闻司”，专门处理这些诡秘案件。从看似狐妖作祟的连环失踪，到涉及蛊术的宫廷秘宝失窃，再到波及全城的“梦魇”瘟疫……两人一个用逻辑推理和刑侦手段，一个用奇门遁甲和玄学知识，在碰撞与磨合中，屡破奇案。他们逐渐发现，这些“异闻”背后，似乎隐藏着一个企图颠覆盛世的巨大阴谋。",review:"构建了一个充满奇思妙想的“唐传奇宇宙”，将历史、志怪、侦探元素巧妙融合。双男主设定有趣，一文一武，一理性一玄学，互动火花四溅。视效瑰丽，动作设计飘逸，是一部成功的商业类型片探索。",cover:"/95.jpg",m3u8Index:11,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘",rating:"7.8",views:102249},{id:"0053",tags:["日韩","电影","美食","治愈","青春","群像","温情"],relatedIds:["0068","0065","0055","0074","0011","0046"],title:"满溢的水果挞",region:"日韩",type:"电影",year:2021,genreRaw:"美食治愈 / 青春群像",oneLine:"五位性格各异的少女，为继承即将关闭的甜品店，组成偶像团体“水果挞”。",summary:"在宁静的海边小镇，一家名为“Fruit Tart”的老式甜品店因店主奶奶年事已高，面临关闭。五位常来光顾的少女：活泼的樱、内向的蓝子、酷炫的椎名、元气的小阳和稳重的小町，为了保住这份承载大家回忆的甜蜜，决定接受奶奶的挑战——组建一支地方偶像团体，若能在半年后的镇上夏日祭演出成功，就能获得店铺继承权。完全不懂偶像为何物的她们，从零开始学习唱歌跳舞，同时还要跟奶奶学习制作美味的水果挞。练习的汗水、创作的争吵、登台的紧张，与烤炉里飘散的香气交织在一起。她们用青涩但真诚的表演和能治愈人心的甜品，一点点赢得小镇居民的支持，也找到了各自的梦想与友谊。",review:"典型的日式温情治愈系作品。美食与偶像两大治愈元素的结合非常巧妙，看着女孩们一边努力排练一边认真做甜点的样子格外暖心。故事简单却充满正能量，人物可爱，画风清新，适合放松心情。",cover:"/79.jpg",m3u8Index:12,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司",rating:"8.8",views:191924},{id:"0054",tags:["国产","电影","喜剧","古装","讽刺","民间智慧"],relatedIds:["0015","0042","0002","0028","0090","0026"],title:"毛驴县令之五官争功",region:"国产",type:"电影",year:2014,genreRaw:"古装喜剧 / 讽刺",oneLine:"清官“毛驴县令”巧断奇案：人的五官为争“头功”在公堂上吵翻了天。",summary:"清河县来了个骑着毛驴、不按常理出牌的县令伍四六。这天，县衙接到一桩前所未有的“官司”——一个名叫“全有”的人，他的眼睛、耳朵、鼻子、嘴巴五个“器官”竟然活了过来，在公堂上互相指责，都声称自己才是主人最重要的部分，功劳最大，吵得不可开交。眼睛说自己“眼观六路”，耳朵说自己“耳听八方”，鼻子说自己“呼吸辨味”，嘴巴说自己“能言善辩吃四方”。伍县令没有将这荒诞之事轰出公堂，反而煞有介事地升堂问案。他巧设情境，让五官分别单独“工作”，结果闹出各种笑话，证明了缺一不可的道理。最终，伍县令以幽默而富有哲理的方式平息了“争端”，也让围观的百姓和暗中观察的上级明白了团结协作的重要性。",review:"借古讽今的荒诞喜剧，创意源自经典相声，但影视化后更加生动夸张。潘长江饰演的伍四六机智诙谐，断案过程妙趣横生，在笑声中传达了“各司其职，团结至上”的朴素道理，寓教于乐。",cover:"/55.jpg",m3u8Index:13,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子, 长泽雅美",rating:"8.2",views:108963},{id:"0055",tags:["欧美","电影","动画","科幻","奇幻","平行宇宙","脑洞"],relatedIds:["0082","0061","0089","0015","0042","0002"],title:"假如…？第二季",region:"欧美",type:"电影",year:2024,genreRaw:"动画 / 科幻 / 奇幻",oneLine:"观察者继续讲述多元宇宙的“假如”故事：假如蜘蛛侠成为丧尸猎人？",summary:"全能的存在“观察者”打破了“绝不干涉”的誓言后，继续带领观众探索漫威多元宇宙中更多光怪陆离的可能性。本季的故事更加天马行空：假如彼得·帕克在被辐射蜘蛛咬伤的同时，丧尸病毒爆发，他成为了在末日纽约穿梭的“丧尸猎人蜘蛛侠”？假如托尼·斯塔克降落在外星，被培养成了银河系最伟大的角斗士？假如斯蒂芬·斯特兰奇为了拯救爱人，吸收了所有平行宇宙中黑暗的自己，成为了“至尊奇异博士”？假如阿斯加德的洛基，被钢铁侠收养？每一个独立单元都颠覆原作设定，在全新的情境下，探讨角色不同的命运走向，动作、幽默与情感并存，不断拓展漫威宇宙的边界。",review:"动画形式给予了创作者最大的自由，本季的脑洞比第一季更大，视觉风格也更多变。每个短篇故事都像一颗精心打磨的宝石，在有限的时长内完成了高概念设定、角色塑造和情感冲击，是献给漫威粉丝的盛宴。",cover:"/88.jpg",m3u8Index:14,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子",rating:"7.7",views:435545},{id:"0056",tags:["欧美","电影","音乐剧","青春","喜剧","校园","成长"],relatedIds:["0039","0078","0020","0034","0063","0031"],title:"13 13 The Musical",region:"欧美",type:"电影",year:2022,genreRaw:"音乐剧 / 青春喜剧",oneLine:"纽约男孩13岁生日前搬家到小镇，他计划用一场完美摇滚派对赢得新朋友。",summary:"埃文·戈德曼是一个即将满13岁的纽约男孩，热爱音乐和派对。然而父母离婚迫使他随母亲搬到了印第安纳州一个无聊的小镇。距离他的13岁生日派对只剩几周，他急需在新学校交到朋友并邀请他们参加，否则派对将是一场灾难。在这个充斥着青春期焦虑、社交小团体和家庭烦恼的陌生环境里，埃文尝试用各种方法融入，甚至不惜改变自己。他结识了性格各异的同学：受欢迎的运动员、古怪的宅男、早熟的女孩。通过一系列爆笑又尴尬的经历，以及随时可能爆发的歌舞场面，埃文最终明白，做真实的自己比讨好他人更重要。生日派对如期举行，一场属于13岁的、不完美却真实的摇滚狂欢上演。",review:"一部充满活力的青春音乐剧电影，歌曲朗朗上口，舞蹈编排充满青春气息。它精准地捕捉了13岁少年面临的社交压力、身份认同和家庭变故，并用幽默和音乐将其化解，欢乐而真诚。",cover:"/136.jpg",m3u8Index:15,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治",rating:"7.6",views:211013},{id:"0057",tags:["欧美","电影","动画","科幻","动作","超级英雄","团队"],relatedIds:["0021","0035","0025","0045","0036","0062"],title:"复仇者集结第三季",region:"欧美",type:"电影",year:2016,genreRaw:"动画 / 科幻 / 动作",oneLine:"复仇者联盟遭遇来自宇宙和微观世界的双重威胁，必须与神奇四侠等联手。",summary:"在经历了奥创纪元等事件后，动画版复仇者联盟迎来了更广阔的挑战。本季故事分为两大篇章：上半部分，来自宇宙的征服者“克里人”发动大规模入侵，其首领“至高智慧”力量惊人，迫使复仇者与星际势力“新星军团”乃至老对手“行星吞噬者”产生交集。下半部分，危机转向微观世界。汉克·皮姆（蚁人）的旧日发明失控，将复仇者们缩小并吸入“量子领域”，在那里他们遇到了被遗忘的初代黄蜂女珍妮特，并必须对抗企图统治现实与微观两个世界的邪恶存在“时空之王”。团队面临分裂危机，新旧成员交替，合作与信任经受终极考验。",review:"本季扩展了动画宇宙的格局，太空史诗与微观冒险交替，故事容量巨大。角色刻画比前两季更深入，尤其是鹰眼、黑寡妇等非超能力成员的表现亮眼。动作场面华丽，忠实体现了漫画的想象力。",cover:"/21.jpg",m3u8Index:16,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周, 李秉宪",rating:"7.8",views:265855},{id:"0058",tags:["日韩","电影","动画","奇幻","冒险","异世界","王者"],relatedIds:["0099","0090","0027","0001","0071","0024"],title:"不死者之王：剧场版前篇",region:"日韩",type:"电影",year:2024,genreRaw:"动画 / 奇幻 / 冒险",oneLine:"安兹·乌尔·恭魔导国建国后，首次面临来自外界人类国家的联合讨伐。",summary:"在纳萨力克地下大坟墓统治者安兹·乌尔·恭（飞鼠）宣布建立魔导国后，其强大的实力和异形的外貌引起了周边人类国家的极度恐慌与敌视。由王国、帝国、教国等人类势力组成的“反魔导国同盟”正式结成，集结人类最精锐的军队和英雄级人物，准备对魔导国发动一场声势浩大的“圣战”。安兹一方面要应对这外部的巨大军事压力，另一方面也要继续扮演好“至高无上的统治者”，安抚纳萨力克内心思各异的守护者们。剧场版前篇将详细展现同盟军的集结过程、各方势力的博弈，以及魔导国为应对战争所做的政治与军事部署。大战一触即发，安兹将如何运用智慧与力量，迎接这建国后的首次存亡考验？",review:"剧场版制作精良，宏大战争场面的描绘远超TV版。文戏部分扎实，深入刻画了人类各国的政治算计与恐惧心理，与纳萨力克的绝对力量形成鲜明对比。粉丝期待的大规模魔法对战初露端倪，吊足胃口。",cover:"/127.jpg",m3u8Index:17,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周",rating:"8.2",views:401502},{id:"0059",tags:["日韩","电影","爱情","喜剧","职场","浪漫","短信情缘"],relatedIds:["0034","0085","0087","0041","0062","0020"],title:"请确认活动吧",region:"日韩",type:"电影",year:2021,genreRaw:"爱情喜剧 / 职场",oneLine:"男女因一条发错的“请确认活动吧”短信结缘，在职场中展开匿名浪漫。",summary:"大型活动策划公司的新人员工韩夏天，因紧张在给重要客户发送活动确认短信时，输错了一位号码。这条“XX活动已安排妥当，请确认吧”的短信，发到了竞争对手公司职员姜宰赫的手机上。同样工作压力巨大的宰赫，鬼使神差地回复了“确认收到”，并附带了一句吐槽工作的玩笑。从此，两个不知对方姓名、相貌和公司的陌生人，因为这个错误的号码，开始了每日的短信交流。他们互相抱怨上司、分享职场趣事、给予匿名鼓励，成为了彼此枯燥生活中的一抹亮色和情感寄托。直到有一天，两人所在的公司要竞标同一个大型项目，他们被迫在现实中成为对手。当“熟悉的陌生人”近在咫尺，他们能否认出彼此，又将如何选择？",review:"充满现代都市感的浪漫爱情小品。基于短信的匿名交流设定新颖，情感铺垫细腻自然。职场背景真实，容易引起打工人的共鸣。影片节奏轻快，笑点与甜点分布得当，是一部合格的“周六下午电影”。",cover:"/23.jpg",m3u8Index:18,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊",rating:"7.7",views:173530},{id:"0060",tags:["国产","电影","科幻","喜剧","末世","冒险","萌娃","心声"],relatedIds:["0056","0043","0094","0099","0068","0023"],title:"崽崽心声助我在末世杀疯了",region:"国产",type:"电影",year:2023,genreRaw:"科幻喜剧 / 末世冒险",oneLine:"末世女战神意外能听到怀中婴儿的心声，靠“奶娃攻略”横扫废土。",summary:"在丧尸横行的末世，战斗力爆表的独行侠林焰被誉为“赤炎女王”。一次行动中，她救下了一个尚在襁褓中的婴儿“崽崽”。令人崩溃的是，林焰发现自己突然能清晰听到崽崽的心声！更离谱的是，崽崽的心声不是“饿饿”“怕怕”，而是各种精准的末世生存指南：“左边第三条巷子有埋伏三个”，“那个罐头过期了”，“这个人对你有恶意”。起初林焰将信将疑，但几次试验下来，崽崽的“攻略”百发百中。于是，画风突变的末世之旅开始了：外表冷酷的女战神，怀里抱着个咿呀婴儿，听着婴儿的“指挥”，一路开挂般扫清障碍、搜刮物资、甄别敌友。两人组合名声大噪，“赤炎女王和她的先知幼崽”的传说在废土上流传开来。",review:"将末世硬核题材与带娃喜剧结合，产生了奇妙的化学反应。设定新颖有趣，“心声”梗玩出了花样。动作场面爽快，喜剧节奏明快，婴儿的“内心吐槽”是最大笑点来源，娱乐性十足。",cover:"/69.jpg",m3u8Index:19,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍, 孔刘",rating:"7.7",views:76262},{id:"0061",tags:["日韩","电影","爱情","悬疑","剧情","身份之谜"],relatedIds:["0097","0060","0005","0050","0030","0001"],title:"爱上谎言的女人",region:"日韩",type:"电影",year:2018,genreRaw:"爱情悬疑 / 剧情",oneLine:"同居五年的完美男友突然失踪，女子调查后发现他的身份、姓名全是谎言。",summary:"职业女性早月与男友小出桔平同居五年，感情稳定，桔平温柔体贴，几乎是完美伴侣。某天早月回家，发现桔平莫名失踪，只留下一部手机。警察在调查中告知早月，她所提供的关于桔平的一切信息——姓名、职业、家庭背景——全部是伪造的，这个人仿佛不存在。震惊的早月拒绝接受，她决心自己寻找真相。她利用桔平留下的手机和零星线索，开始抽丝剥茧地调查。她找到了桔平可能去过的地方，接触了他可能认识的人，每一步都让她更接近真相，却也让她更加困惑和心痛：这个与她朝夕相处五年的男人究竟是谁？他为何要编织一个巨大的谎言？而自己爱上的，到底是那个虚构的“桔平”，还是谎言背后真实的人？",review:"影片更像一部包裹着爱情外衣的心理悬疑片。节奏张弛有度，悬念一直保持到结尾。长泽雅美的表演极具感染力，将女性从信任到崩塌再到寻求真相的复杂心路历程刻画得丝丝入扣，引人深思“爱情与真实”的关系。",cover:"/80.jpg",m3u8Index:0,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍",rating:"8.2",views:97220},{id:"0062",tags:["国产","电影","爱情","冒险","西藏","救援","生死"],relatedIds:["0081","0002","0097","0050","0060","0012"],title:"雪域情",region:"国产",type:"电影",year:2020,genreRaw:"爱情 / 冒险 / 剧情",oneLine:"为爱穿越生命禁区，两位陌生人在暴风雪中书写生死情缘。",summary:"一场突如其来的暴风雪，将前往西藏进行地质勘探的工程师方远，与独自旅行寻求心灵救赎的女画家苏禾，困在了海拔五千米的无人区。有限的物资、逐渐失温的身体，以及随时可能发生的雪崩，让两人的生命进入倒计时。在绝境中，他们从互相戒备到彼此依靠，分享各自的人生故事与遗憾。方远用专业知识寻找生机，苏禾则以画笔记录下最后的“生命印象”。当救援队的直升机轰鸣声隐约传来时，苏禾却因严重的高原反应陷入昏迷。方远必须在最后的窗口期，做出一个关乎两人性命的艰难抉择。",review:"影片将壮美与残酷并存的雪域奇观作为舞台，极致的环境压迫感让两位主角的情感递进真实可信。没有刻意煽情，生死边缘迸发出的纯粹情感与人性光辉，直击人心。结尾处的开放式处理，余味悠长。",cover:"/28.jpg",m3u8Index:1,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡",rating:"9.2",views:161229},{id:"0063",tags:["国产","电影","喜剧","纪录片","相声","德云社","现场"],relatedIds:["0031","0048","0085","0068","0074","0079"],title:"德云社德云七队小园子天桥站2021",region:"国产",type:"电影",year:2021,genreRaw:"喜剧 / 纪录片",oneLine:"镜头深入相声后台，记录德云七队成员台前幕后的欢笑与汗水。",summary:"本片以纪实手法，聚焦德云社七队2021年在北京天桥小剧场的封箱演出季。镜头不仅捕捉了孟鹤堂、周九良等角儿们在台上妙语连珠、引爆全场的精彩瞬间，更罕见地深入到后台、排练厅和日常生活。观众将看到演员们对活时的严谨认真、上场前的紧张忐忑、成功“炸场”后的如释重负以及兄弟间的插科打诨。影片通过跟拍多位队员，展现了年轻相声演员在传统艺术传承与个人风格创新之间的摸索，以及在名利场中如何守住对相声的初心与热爱。",review:"这是一部粉丝向与普通观众都能找到乐趣的作品。它打破了舞台的第四面墙，以亲切平实的视角，展现了相声演员作为普通人的一面。影片节奏明快，笑料与温情并存，是对中国传统曲艺后台文化的一次有趣窥探。",cover:"/78.jpg",m3u8Index:2,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司, 松隆子",rating:"8.0",views:245134},{id:"0064",tags:["日韩","电影","亲情","美食","治愈","乡村","成长"],relatedIds:["0011","0034","0091","0054","0048","0004"],title:"姐姐家的产地直送",region:"日韩",type:"电影",year:2019,genreRaw:"亲情 / 美食 / 治愈",oneLine:"都市少女被迫接手乡下果园，在与自然相处中重拾亲情与自我。",summary:"在东京广告公司疲于奔命的OL美咲，突然接到母亲病倒的消息，不得不暂时回到阔别多年的乡下老家，接手姐姐留下的一个小型柑橘园。对农事一窍不通的她，在手忙脚乱中得到了邻居老农夫阿勋和几位热心阿姨的帮助。从疏于打理到亲手摘下第一颗成熟的橘子，美咲不仅学会了劳作，更在四季流转中理解了姐姐当年坚守这里的理由。她开始尝试用网络直播“产地直送”，将新鲜的柑橘和田园故事传递给城市。当母亲康复、去留抉择摆在面前时，美咲发现自己早已与这片土地产生了无法割舍的联结。",review:"典型的日式温情小品，画面清新治愈，田园风光赏心悦目。影片巧妙地通过“务农”这一过程，完成了主角从疏离到融入的情感转变。美食与亲情的结合恰到好处，不甜腻，却温暖人心。",cover:"/46.jpg",m3u8Index:3,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司",rating:"9.1",views:343274},{id:"0065",tags:["国产","电影","武侠","悬疑","权谋","江湖","复仇"],relatedIds:["0048","0055","0072","0036","0007","0016"],title:"公子无双",region:"国产",type:"电影",year:2022,genreRaw:"武侠 / 悬疑 / 剧情",oneLine:"无双公子身陷灭门谜案，以病弱之躯智斗江湖朝堂。",summary:"天下第一智者，“无双公子”谢云流，虽身体孱弱、手无缚鸡之力，却凭借超凡智计名动天下。然而，一夕之间，谢府满门被灭，他因在外云游幸免于难，却成为朝廷通缉的要犯。为查明真相、清洗冤屈，谢云流隐匿身份，以书生打扮踏入波谲云诡的江湖与朝堂。他利用人心的弱点与信息的落差，借力打力，在各方势力间周旋。随着调查深入，他发现灭门惨案背后竟牵扯到一桩动摇国本的巨大阴谋，而自己，也早已是棋局中最关键的一枚棋子。",review:"反套路的武侠设定令人眼前一亮，主角以智取胜而非武力，使得剧情充满了精巧的算计与反转。氛围营造出色，文戏张力十足。主角病弱谋士的形象塑造丰满，其与强大反派的智力对决扣人心弦。",cover:"/14.jpg",m3u8Index:4,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美",rating:"8.9",views:82295},{id:"0066",tags:["国产","电影","历史","权谋","宫廷","成长","逆袭"],relatedIds:["0053","0039","0004","0062","0036","0070"],title:"大周皇太子",region:"国产",type:"电影",year:2023,genreRaw:"历史 / 权谋 / 剧情",oneLine:"废太子被流放边陲，于绝境中锻造新军，踏上传奇复国路。",summary:"大周皇太子萧景琰因遭陷害被废，流放至苦寒北疆。昔日的天之骄子沦为囚徒，受尽冷眼与欺辱。在北疆，他亲身感受到边境百姓的困苦与外敌的威胁。放下身份，他结识了耿直的边军校尉、智慧的女医官和神秘的游侠，并凭借过人的胆识与智慧，整合边军残部与民间力量，锻造出一支纪律严明、战力强悍的“北府军”。当京城剧变、外敌入侵、国难当头之际，萧景琰率领这支铁骑南下，不仅要收复山河，更要重回权力中心，查清当年的阴谋，肩负起家国天下。",review:"影片格局宏大，将个人命运与家国情怀紧密结合。太子成长线清晰，从失意到奋起的转变扎实可信。战争场面气势磅礴，朝堂权谋戏码环环相扣。整体是一部制作精良、叙事扎实的历史正剧风格电影。",cover:"/29.jpg",m3u8Index:5,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治, 韩孝周",rating:"7.5",views:310381},{id:"0067",tags:["国产","电影","文艺","年代","青春","选择","传承"],relatedIds:["0002","0028","0021","0017","0037","0047"],title:"无问西东",region:"国产",type:"电影",year:2018,genreRaw:"剧情 / 文艺 / 年代",oneLine:"四段时空，四代青年，在时代洪流中追寻内心的真实与光芒。",summary:"影片以非线性的叙事手法，讲述了四个不同时代却出自同一所大学的年轻人的故事：1920年代，富家子沈光耀在国难面前违背母命，毅然投身空军；1930年代，理工天才吴岭澜在迷茫中聆听泰戈尔的演讲，思考生命的真实；1960年代，医生王敏佳和李想因不同的选择，命运走向截然不同的方向；现代，职场精英张果果在尔虞我诈的商战中，面临是否要帮助一个贫困四胞胎家庭的人性抉择。四个故事看似独立，却在精神内核上紧密相连，探讨了青春、理想、爱情与家国情怀，最终汇聚成“立德立言，无问西东”的精神传承。",review:"影片气质沉静而富有力量，史诗般的叙事格局和深厚的人文关怀令人动容。四个故事的剪辑与衔接充满巧思，音乐与画面极具感染力。它不止于讲故事，更是在叩问观众：面对时代与人生，你是否能忠于内心？",cover:"/61.jpg",m3u8Index:6,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治",rating:"8.6",views:357437},{id:"0068",tags:["日韩","电影","运动","励志","台球","热血","逆袭"],relatedIds:["0015","0011","0056","0036","0066","0063"],title:"一杆清台",region:"日韩",type:"电影",year:2017,genreRaw:"运动 / 励志 / 剧情",oneLine:"昔日台球天才跌落谷底，为守护球房重新拿起球杆。",summary:"前职业斯诺克选手李俊，因一场比赛失利和随之而来的丑闻而一蹶不振，沦落在自家破旧的老式台球房里浑噩度日。直到房地产开发商企图强拆球房，而这里亦是周围老街坊们唯一的精神乐园。为了守住父亲留下的球房和众人的寄托，李俊决定复出，参加一场高额奖金的业余黑八大赛。他重新擦拭球杆，克服心理阴影，在昔日对手、现在的顶级球星金在中的刺激与帮助下，进行着艰苦的训练。比赛当天，他面对的不仅是强大的对手，更是自己心魔的最终对决。",review:"运动题材的励志故事总能燃起热血，本片将台球这项相对静态运动的紧张与优雅表现得淋漓尽致。男主角的成长弧光完整，从颓废到重燃斗志的过程刻画细腻。最后的比赛场面剪辑节奏感强，悬念迭起。",cover:"/36.jpg",m3u8Index:7,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪",rating:"9.1",views:194682},{id:"0069",tags:["欧美","电影","惊悚","悬疑","家庭","秘密","心理"],relatedIds:["0025","0056","0004","0007","0057","0027"],title:"无辜",region:"欧美",type:"电影",year:2021,genreRaw:"惊悚 / 剧情 / 悬疑",oneLine:"一个陌生男孩的闯入，彻底颠覆了重组家庭的平静假象。",summary:"心理医生劳拉与丈夫马特带着各自的孩子组成了新的家庭，生活看似平静美满。某天，一个自称是马特与前妻所生、却从未被他提及的九岁男孩卢卡斯突然找上门。劳拉出于同情收留了他，但卢卡斯乖巧的外表下似乎隐藏着令人不安的特质。家中开始接连发生诡异事件：宠物失踪、物品被破坏、孩子们之间关系紧张。劳拉调查后发现，卢卡斯的身世成谜，而丈夫马特似乎也在隐瞒着什么。当大女儿发生严重“意外”后，劳拉意识到，这个“无辜”的男孩，可能正将她的家庭拖入万劫不复的深渊。",review:"影片营造的家庭内部惊悚氛围非常出色，步步为营的悬念设置让观众全程神经紧绷。小演员的表演堪称惊悚，天真与邪气并存。电影深刻探讨了信任、谎言与家庭关系的脆弱性，结局的反转令人背脊发凉。",cover:"/112.jpg",m3u8Index:8,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊, 全度妍",rating:"9.3",views:114257},{id:"0070",tags:["欧美","电影","动画","恐怖","喜剧","荒诞","影视","脑洞"],relatedIds:["0072","0019","0008","0081","0084","0054"],title:"颤抖的真相第二季",region:"欧美",type:"电影",year:2023,genreRaw:"动画 / 恐怖 / 喜剧 / 荒诞",oneLine:"更诡异、更辛辣的黏土动画寓言，直刺现代社会的疯狂内核。",summary:"这部先锋黏土动画剧集以更多元、更令人不安的短篇故事回归。本季中，一个男人发现自己所有的情绪都可以通过手机APP量化与控制；一座城市的居民集体患上了“错位症”，身体器官开始随机交换；一个普通家庭通过订阅服务获得了一个“完美”的虚拟儿子，却引来了实体世界的恐怖存在；还有关于社交媒体点赞成瘾、职场异化、存在主义焦虑等光怪陆离的隐喻。每一个故事都以极度扭曲的视觉形象和黑色幽默，揭露当代生活中那些令人“颤抖的真相”。",review:"比第一季更大胆、更尖锐。其独特的黏土动画风格将荒诞与恐怖融合到极致，视觉冲击力极强。每个短篇都像一记针对现代文明的闷棍，在令人不适的搞笑中，引发深层次的反思与战栗。是专属影视的脑洞盛宴。",cover:"/94.jpg",m3u8Index:9,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊",rating:"8.6",views:89238},{id:"0071",tags:["国产","电影","战争","历史","抗战","小队","狙击"],relatedIds:["0084","0023","0004","0008","0097","0089"],title:"战火黎明",region:"国产",type:"电影",year:2022,genreRaw:"战争 / 历史 / 剧情",oneLine:"一支敌后狙击小队，在黎明前的至暗时刻，执行绝密斩首行动。",summary:"1944年，抗战进入最艰苦的相持阶段。一支由神枪手、爆破专家、侦察兵和医疗兵组成的八路军敌后特别行动小队，奉命潜入日军重兵防守的华北某枢纽城镇，执行一项几乎不可能的任务：在日军中将举行婚礼的当夜，对其进行斩首，以打乱敌人的扫荡计划。小队成员各自身怀绝技，也背负着不同的伤痛往事。在穿越敌占区的过程中，他们遭遇重重险阻，内部也因理念产生分歧。当行动暴露，陷入重围时，他们必须利用城镇复杂的地形，在黎明到来之前，完成使命，并争取一线生机。",review:"影片以小见大，通过一次具体的战术行动，展现了敌后抗战的艰险与英雄们的牺牲精神。战术细节考究，狙击与巷战场面紧张刺激，颇具临场感。人物群像刻画生动，没有脸谱化，在战火中闪现的人性光辉尤为动人。",cover:"/65.jpg",m3u8Index:10,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘",rating:"9.1",views:419213},{id:"0072",tags:["日韩","电影","动作","恐怖","喜剧","暴力美学","cult"],relatedIds:["0004","0040","0083","0076","0027","0015"],title:"电锯少女血肉之华",region:"日韩",type:"电影",year:2016,genreRaw:"动作 / 恐怖 / 喜剧",oneLine:"手持电锯的暴走少女，在血肉横飞的校园中对抗僵尸化同学。",summary:"就读于封闭女校的机械宅少女藏间，因为性格孤僻备受欺凌。某天，学校爆发一种奇怪的病毒，感染的学生会变得嗜血狂暴，如同僵尸。在混乱中，藏间躲进了学校的旧工坊，利用自己的机械知识，将一台除草机改装成了一把狂暴的电锯。为了寻找失踪的好友，也为了生存，这个平时沉默寡言的少女，挥舞着轰鸣的电锯，在走廊、教室、礼堂中杀出一条血路。战斗愈演愈烈，她甚至不断“升级”自己的武器。然而，她逐渐发现，病毒的源头似乎与学校一个黑暗的秘密实验有关。",review:"一部将日式暴力美学发挥到极致的Cult片。电锯少女的设定反差感十足，血腥场面夸张而富有创意，充满漫画感。在极致的暴力和黑色幽默之下，也暗含了对校园霸凌等社会问题的讽刺。观感爽快，cult迷的盛宴。",cover:"/25.jpg",m3u8Index:11,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡, 役所广司",rating:"8.6",views:50173},{id:"0073",tags:["日韩","电影","医疗","剧情","温情","儿科","成长"],relatedIds:["0019","0066","0049","0040","0030","0011"],title:"37.5℃的眼泪",region:"日韩",type:"电影",year:2015,genreRaw:"医疗 / 剧情 / 家庭",oneLine:"新手儿科护士用微热的温度，温暖每一个患病的孩子与家庭。",summary:"佐仓枫怀抱着满腔热情成为一名儿科护士，然而现实却给她泼了一盆冷水。她不仅要面对繁重的工作、孩子们的哭闹、家长的焦虑与不理解，还要处理复杂的医患关系和同事间的竞争。在严厉却经验丰富的护士长以及一位充满智慧的退休老医生的指导下，枫开始明白，儿科护理需要的不仅是技术，更是37.5℃般恰到好处的耐心、细心与爱心。她陪伴白血病患儿完成心愿，帮助自闭症儿童打开心扉，在一次次与疾病和生死交手的经历中，枫逐渐成长为一名能独当一面、真正理解“生命温度”的优秀护士。",review:"非常典型的日式职业剧风格电影，细腻而真实。影片没有刻意制造戏剧冲突，而是通过一个个平凡的病例和医患故事，层层递进地塑造人物，传递出温暖治愈的力量。对儿科医护工作者艰辛与伟大的刻画，令人动容。",cover:"/35.jpg",m3u8Index:12,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡",rating:"9.0",views:249077},{id:"0074",tags:["国产","电影","爱情","喜剧","都市","夜店","反转"],relatedIds:["0049","0022","0041","0090","0085","0051"],title:"爱夜蒲之备胎上位",region:"国产",type:"电影",year:2017,genreRaw:"爱情 / 喜剧 / 都市",oneLine:"万年备胎在夜店误打误撞，却意外吸引了真命天女的注意。",summary:"老实内向的程序员阿杰，长期暗恋同事女神 Cindy，甘当其随叫随到的“备胎”。在损友的怂恿下，他第一次踏入了光怪陆离的夜店，试图改变形象。阴差阳错中，他帮一位被搭讪困扰的酷飒女孩小鹿解了围，并因醉酒后的“真情流露”逗乐了她。小鹿对阿杰产生了兴趣，而阿杰却一心只想着如何吸引Cindy。在小鹿的“套路”和助攻下，阿杰竟真的与Cindy越走越近。然而，当他以为自己即将“转正”时，却发现Cindy背后有着复杂的感情纠葛，而始终陪伴他、理解他的，却是那个他从未当作“选项”的小鹿。",review:"都市爱情喜剧的轻松套路，但人物设定有趣，笑点密集自然。男主从备胎到清醒的成长过程有共鸣，女主小鹿的角色塑造非常讨喜，独立又聪明。影片对都市男女情感关系的描绘，既有浪漫幻想，也有现实调侃。",cover:"/106.jpg",m3u8Index:13,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子",rating:"9.1",views:135980},{id:"0075",tags:["国产","电影","谍战","悬疑","年代","卧底","智斗"],relatedIds:["0059","0054","0034","0065","0011","0081"],title:"谍变1939",region:"国产",type:"电影",year:2021,genreRaw:"谍战 / 悬疑 / 剧情",oneLine:"双面间谍游走于敌我之间，每一步都是如履薄冰的死亡游戏。",summary:"1939年，孤岛上海。表面上是汪伪政府特工总部高级情报员的沈放，实则是中共地下党潜伏人员“青鸟”。他的亲哥哥沈林，却是军统上海站负责人。沈放周旋于日本特高课、汪伪76号以及军统等多方势力之间，传递关键情报，保护同志。一次意外，导致他的单线联络人牺牲，自己也面临暴露风险。与此同时，一位心思缜密的日本特工佐藤开始怀疑他。沈放必须在没有上级指令的情况下，独立判断，利用各方矛盾，同时应对来自哥哥沈林不知情的调查与试探，在绝境中完成一项关乎战略全局的秘密任务。",review:"谍战氛围营造得极为出色，压迫感贯穿始终。兄弟对立的设定增加了戏剧张力和情感厚度。男主角在多重身份间的挣扎与智斗戏码非常精彩，情节环环相扣，反转合理。是近年国产谍战片中完成度很高的作品。",cover:"/52.jpg",m3u8Index:14,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美, 福山雅治",rating:"7.8",views:415209},{id:"0076",tags:["国产","电影","古装","喜剧","家庭","萌娃","宅斗"],relatedIds:["0010","0053","0034","0068","0024","0098"],title:"侯府主母养崽手册",region:"国产",type:"电影",year:2024,genreRaw:"古装 / 喜剧 / 家庭",oneLine:"现代社畜魂穿侯府恶毒主母，为保命开始佛系养娃改造计划。",summary:"加班猝死的社畜李薇一睁眼，竟穿成了古言小说里嚣张跋扈、虐待庶子庶女、即将被休弃赐死的侯府主母柳氏。为了活下去，她决定彻底改变人设。面对侯爷的冷眼、妾室的挑衅，以及原著中未来会黑化报复自己的三个“崽”——阴郁长子、病弱次女和顽劣幼子，李薇祭出现代育儿理念和职场生存法则：带长子做生意搞钱重建自信，陪次女锻炼身体学习医术，用科学实验征服幼子。就在她以为可以躺平当个富贵闲人时，侯府的财政危机和朝堂的风波，却将她这个只想“养崽保命”的主母，推到了风口浪尖。",review:"轻松欢快的穿越喜剧，反套路设定有趣。将现代观念与古代环境的碰撞处理得幽默而不违和。“养崽”过程温馨治愈，萌娃们各有特色。女主的事业线同样亮眼，是一部合格的下饭爽片。",cover:"/13.jpg",m3u8Index:15,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美",rating:"9.5",views:91846},{id:"0077",tags:["欧美","电影","科幻","惊悚","深海","克苏鲁","孤绝"],relatedIds:["0046","0002","0078","0075","0089","0043"],title:"先锋2019",region:"欧美",type:"电影",year:2019,genreRaw:"科幻 / 惊悚",oneLine:"深海勘探队遭遇未知生命体，深潜器成为人类最后的避难所。",summary:"一支国际科研小队乘坐世界上最先进的深潜器“先锋号”，下潜至马里亚纳海沟最深处，进行地质与生命样本采集。在接近海床时，他们发现了一片超出认知的、散发着微光的奇异生态系统，并成功采集到一个未知的有机体样本。然而，在返航途中，深潜器遭到神秘生物的攻击，严重受损，被困在万米深海。更可怕的是，那个被带回的样本开始影响船员的神智，引发幻觉与偏执。外部是未知的深海巨兽，内部是逐渐崩溃的同伴，队长艾娃必须在氧气耗尽前，带领幸存者找出样本的真相，并找到一线生机。",review:"将幽闭恐惧症与深海恐惧症完美结合，营造出令人窒息的紧张氛围。克苏鲁式的未知恐怖概念运用得当，心理惊悚层面优于简单的视觉惊吓。深潜器的细节设定真实，特效出色，是一部高质量的深海科幻惊悚片。",cover:"/110.jpg",m3u8Index:16,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周",rating:"8.9",views:170635},{id:"0078",tags:["日韩","电影","校园","喜剧","冒险","公路","青春"],relatedIds:["0057","0073","0009","0040","0019","0092"],title:"没有数学的修学旅行",region:"日韩",type:"电影",year:2018,genreRaw:"校园 / 喜剧 / 冒险",oneLine:"数学竞赛队大巴抛锚荒岛，天才少年们被迫展开一场生存大挑战。",summary:"全国高中数学竞赛队的精英学生们，在前往决赛地点的修学旅行途中，大巴因山体滑坡被困在一座与世隔绝的湖心荒岛上。带队的老师重伤昏迷，手机没有信号，食物短缺。这群只会解微积分和几何证明的天才们，突然发现生存所需的野外知识几乎为零。在最初的混乱后，他们不得不运用逻辑思维、物理知识和团队协作，解决生火、取水、搭建庇护所、寻找食物等一系列实际问题。在这场“没有数学”的考试中，他们经历了从书呆子到实践者的蜕变，也结下了超越竞赛胜负的深厚友谊。",review:"创意新颖的青春喜剧，将高智商与低生活技能的矛盾制造出大量笑料。角色群像鲜明，每个天才都有独特的怪癖与闪光点。影片在搞笑之余，也真诚地探讨了知识的意义、团队合作与青春成长，轻松有趣，充满正能量。",cover:"/45.jpg",m3u8Index:17,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪, 宋康昊",rating:"8.4",views:144879},{id:"0079",tags:["欧美","电影","动画","冒险","音乐","经典重制","史诗"],relatedIds:["0022","0025","0088","0046","0089","0070"],title:"狮子王2019",region:"欧美",type:"电影",year:2019,genreRaw:"动画 / 冒险 / 音乐 / 剧情",oneLine:"利用尖端CG技术，真实再现草原之王辛巴的传奇生命轮回。",summary:"本片是对1994年经典动画《狮子王》的“真人”（全CG）重制版。故事依旧围绕小狮子辛巴展开，他是荣耀国王木法沙的儿子，王位的合法继承人。然而，叔叔刀疤的阴谋导致木法沙惨死，辛巴被迫流亡，并自责不已。在疣猪彭彭和狐獴丁满的帮助下，他度过了无忧无虑的成长时光。直到童年好友母狮娜娜的出现和巫师拉飞奇的指引，让辛巴重新认识到自己的责任。他返回正在刀疤暴政下衰败的荣耀国，挑战叔叔，夺回王位，并让大地重焕生机，完成生命轮回的史诗。",review:"视觉奇观无可挑剔，几可乱真的CG动物和壮丽的非洲草原风光令人叹为观止。经典音乐的重编与演绎依然动人。然而，极度追求真实的动物表情也带来了一些情感传达上的折扣。总体而言，是一次对经典的成功技术献礼，但灵魂依旧属于原版。",cover:"/129.jpg",m3u8Index:18,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪",rating:"9.0",views:234779},{id:"0080",tags:["国产","电影","爱情","喜剧","都市","爽文","团宠"],relatedIds:["0004","0075","0026","0048","0024","0068"],title:"韩少别哭，夫人她有三个大佬哥哥",region:"国产",type:"电影",year:2024,genreRaw:"爱情 / 喜剧 / 都市",oneLine:"被抛弃的真千金携三位霸总哥哥归来，前夫追妻火葬场。",summary:"苏晚作为替身嫁给韩氏总裁韩峥三年，受尽冷眼。当他的白月光回国，她一纸离婚协议潇洒离开。韩峥不以为意，直到他发现，那个被他忽视的前妻，竟是帝都顶级豪门苏家走失的真千金，而她三位叱咤商界、政界、律界的哥哥正将她捧在手心。大哥是科技巨头，二哥是政坛新星，三哥是金牌律师。曾经欺负过苏晚的人纷纷遭殃，韩氏集团也处处受制。韩峥这才后悔莫及，开启艰难的“追妻火葬场”模式，不仅要面对苏晚的冷漠，更要应付三位护妹狂魔大舅哥的各种“考验”与刁难。",review:"精准投喂观众爽点的都市甜爽剧。女主不再忍气吞声，开篇即逆袭的设定很痛快。三位哥哥的“宠妹”戏码满足观众幻想，与男主的互动笑点十足。剧情节奏快，冲突密集，是轻松解压的佳品。",cover:"/17.jpg",m3u8Index:19,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍",rating:"9.0",views:443812},{id:"0081",tags:["国产","电影","喜剧","剧情","乡土","进城","反差"],relatedIds:["0043","0011","0061","0023","0086","0038"],title:"都市放牛",region:"国产",type:"电影",year:2006,genreRaw:"喜剧 / 剧情",oneLine:"陕北放牛娃勇闯大上海，用最质朴的方式搅动都市江湖。",summary:"憨厚朴实的陕北青年牛建国，为寻找离家出走打工的未婚妻杏花，只身来到光怪陆离的大上海。他揣着放牛攒下的钱，操着一口方言，在上海闹出无数笑话。他做过建筑工、送过外卖，甚至因为帮助一位老人而误入古董行当。凭借山里人特有的实在、韧性和一点运气，牛建国竟然在复杂的都市里站稳了脚跟，还结识了一帮同样来自天南地北的朋友。当他终于找到已成为酒吧歌手的杏花时，却发现两人之间已经隔着一道无形的墙。牛建国必须做出选择：是留在已然熟悉的城市，还是回到那片生他养他的黄土地？",review:"一部充满乡土气息与时代印记的喜剧。主角与都市环境的巨大反差制造了源源不断的笑料，但在搞笑背后，是对进城务工人员生存状态的细致观察与温情关怀。演员表演接地气，情感真挚动人。",cover:"/54.jpg",m3u8Index:0,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘, 马东锡",rating:"9.4",views:351217},{id:"0082",tags:["国产","电影","喜剧","动作","冒险","夺宝","团队"],relatedIds:["0096","0097","0063","0025","0019","0035"],title:"夺宝五福星",region:"国产",type:"电影",year:2023,genreRaw:"喜剧 / 动作 / 冒险",oneLine:"五个不靠谱的“专家”组队，为夺回国宝展开啼笑皆非的环球冒险。",summary:"一件流失海外的国宝“天珠”即将在海外拍卖，民间爱国商人出资，招募了一支“专家”团队去“取回”它。团队成员分别是：身手退化的前特工“力王”、半吊子风水师“神算”、开锁技术一流却胆小如鼠的“钥匙”、精通各国语言但路痴的“博士”，以及伪装大师“千面”。这五个毛病比本事多的奇葩，从澳门赌场到东南亚雨林，再到中东沙漠，一路过关斩将，闹出无数笑话。他们不仅要应对国际黑帮的围追堵截，还要提防团队内部层出不穷的“猪队友”行为。最终，在啼笑皆非的协作中，他们竟意外地完成了任务。",review:"合家欢式的冒险喜剧，致敬了经典港片的“福星”系列。五位主角人设鲜明有趣，互动火花四溅。动作戏混搭搞笑元素，节奏明快，全球取景的画面也相当养眼。是一部轻松热闹、不带脑子的快乐爆米花电影。",cover:"/5.jpg",m3u8Index:1,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘",rating:"7.6",views:215283},{id:"0083",tags:["日韩","电影","剧情","家庭","运动","父子","温情"],relatedIds:["0084","0095","0024","0099","0002","0092"],title:"我的小小英雄",region:"日韩",type:"电影",year:2013,genreRaw:"剧情 / 家庭 / 运动",oneLine:"失意拳击手父亲，为患有心脏病的儿子，重返擂台挑战不可能。",summary:"前职业拳击手洙赫因一次失利而一蹶不振，沦为落魄的健身房教练，与妻子关系破裂，儿子东柱则因先天性心脏病而体弱。东柱最大的梦想是看到爸爸在拳台上获胜。一次偶然，东柱的主治医生表示，如果东柱能保持积极的心态和适当的运动，病情有望稳定。为了激励儿子，也为了弥补曾经的失败，洙赫决定以高龄重返业余拳击赛场。训练过程异常艰辛，他不仅要恢复体能，还要克服心理阴影。每一场比赛，东柱都在医院通过直播为爸爸加油。这对父子的命运，因小小的拳台而紧紧相连，共同面对人生的重拳。",review:"非常催泪又励志的亲情电影。拳击比赛的激烈与父子之情的柔软形成强烈对比，情感铺垫细腻，爆发点精准。男主角的表演极具说服力，将失败者的颓废与父亲的责任感演绎得层次分明。最后赛场内外的互动，感人至深。",cover:"/66.jpg",m3u8Index:2,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司",rating:"7.7",views:432101},{id:"0084",tags:["国产","电影","爱情","剧情","现实","婚姻","选择"],relatedIds:["0008","0041","0029","0003","0012","0025"],title:"般配关系",region:"国产",type:"电影",year:2022,genreRaw:"爱情 / 剧情",oneLine:"一场始于“条件匹配”的婚姻，能否在现实摩擦中生出真正的爱情？",summary:"林静，32岁，大型企业HR总监，理性、高效，将人生规划得井井有条。陈默，35岁，大学副教授，温和、内敛，沉浸于学术世界。两人通过相亲认识，无论是家境、学历、职业还是外在条件，都被周围人评价为“般配”。在适婚年龄的压力下，他们像完成项目一样，顺利结婚。然而，婚姻不是合伙开公司。林静追求效率与物质保障，陈默注重精神交流与生活情趣。从装修风格到生育计划，从社交方式到价值观念，差异逐渐显现。当“般配”的光环褪去，他们必须思考：这段关系是应该用理性经营下去，还是该遵从内心，寻找真正的情感联结？",review:"一部非常写实的都市婚恋电影，精准地击中了当代许多“条件匹配”式婚姻的痛点。影片没有狗血的情节，而是通过大量生活细节，展现两人温水煮青蛙般的摩擦与疏离。表演克制而有力，引发观众对爱情与婚姻本质的深度思考。",cover:"/16.jpg",m3u8Index:3,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子, 长泽雅美",rating:"9.1",views:281652},{id:"0085",tags:["国产","电影","惊悚","悬疑","民俗","乡村","秘密"],relatedIds:["0055","0047","0001","0066","0093","0031"],title:"美人鱼村",region:"国产",type:"电影",year:2016,genreRaw:"惊悚 / 悬疑 / 剧情",oneLine:"民俗学家探访与世隔绝的渔村，发现村民祭祀“美人鱼”的恐怖传统。",summary:"民俗学研究生陈宇为撰写论文，来到一个传说有“鲛人”（美人鱼）出没的偏远海岛渔村。村里气氛诡异，村民对他这个外来者充满戒心，尤其是对女性“鲛人”的话题讳莫如深。陈宇借住在老村长家，发现村长女儿阿月行为古怪，似乎被某种仪式束缚。他逐渐从零碎的线索中拼凑出真相：所谓“鲛人”，其实是村里世代将患有一种罕见遗传病的女性囚禁于海边洞穴，加以神化并举行残忍祭祀，以祈求渔获丰收。而阿月，正是下一任“鲛人”祭品。陈宇试图带阿月逃离，却引发了整个村子的围捕。",review:"将民俗传说与惊悚悬疑结合得相当出色。影片营造的孤岛村落氛围阴森压抑，神秘感和压迫感十足。对人性的愚昧与残忍的揭露令人不寒而栗。结局的处理既绝望又有一丝微光，余味复杂，是国产惊悚类型的一次成功探索。",cover:"/18.jpg",m3u8Index:4,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子",rating:"7.7",views:186121},{id:"0086",tags:["欧美","电影","科幻","惊悚","平行世界","身份","哲学"],relatedIds:["0061","0036","0096","0063","0040","0088"],title:"雅努斯之镜",region:"欧美",type:"电影",year:2024,genreRaw:"科幻 / 惊悚 / 剧情",oneLine:"一面能映照平行世界自我的镜子，引发了关于身份与存在的噩梦。",summary:"物理学家艾丽莎在一次实验事故后，得到了一面古老的镜子残片——“雅努斯之镜”。她震惊地发现，这面镜子映照出的不是自己现在的样子，而是来自无数平行世界中、过着不同人生的“她”。起初她沉迷于观察其他“自己”的人生，获取知识甚至预知未来。但很快，镜子中的一些“艾丽莎”开始试图与她沟通，甚至表现出敌意。现实世界开始出现诡异的错乱，她的人际关系、记忆乃至身体都受到干扰。艾丽莎意识到，这面镜子不是观察工具，而是一扇门，其他世界的“她”正试图穿过这扇门，取代她的存在。",review:"概念非常出色的科幻惊悚片。它以“平行自我”为核心，探讨了身份唯一性的哲学命题，设定严谨且令人毛骨悚然。视觉呈现上，镜子内",cover:"/119.jpg",m3u8Index:5,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治",rating:"8.5",views:402305},{id:"0087",tags:["欧美","电影","奇幻","冒险","喜剧","合家欢"],relatedIds:["0029","0099","0013","0084","0031","0017"],title:"小叮当与海盗仙子",region:"欧美",type:"电影",year:2014,genreRaw:"奇幻冒险 / 家庭喜剧",oneLine:"仙子小叮当误入海盗世界，与叛逆海盗仙子联手，阻止一场颠覆童话世界的阴谋。",summary:"仙子谷的修理匠小叮当，在一次实验事故中意外坠入了神秘的“永无海”。这里并非彼得的梦幻岛，而是被一群崇尚“坏规矩”的海盗仙子统治的混乱海域。在这里，仙子翅膀的亮粉是违禁品，海盗仙子头子“铁钩莉莉”正密谋用收集来的“第一粒快乐眼泪”制造黑暗风暴，席卷所有童话国度。小叮当与海盗团中最不合群的导航员“星尘”结盟，这个内心向往光明的海盗仙子掌握着前往“时间源头”的秘密航线。她们必须驾驶破旧的海盗飞梭，躲避海盗女王的追捕，赶在月食之夜前修复被破坏的童话时间线。这段冒险让小叮当明白，规则与叛逆并非对立，而真正的魔法源自内心的选择与勇气。",review:"影片将经典的童话角色置入颠覆性的海盗世界观，碰撞出意想不到的火花。冒险节奏明快，视觉效果充满想象力，海盗仙子的蒸汽朋克风格与仙子谷的璀璨光影形成鲜明对比。小叮当与星尘的友谊线细腻感人，诠释了“理解与接纳”的主题。",cover:"/43.jpg",m3u8Index:6,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周, 李秉宪",rating:"9.1",views:199827},{id:"0088",tags:["国产","电影","爱情","喜剧","校园","都市"],relatedIds:["0087","0090","0033","0015","0057","0028"],title:"哥哥的死对头，我的秘密恋人",region:"国产",type:"电影",year:2021,genreRaw:"都市爱情 / 青春喜剧",oneLine:"为帮哥哥挽回颜面，我假意接近他的死对头，却陷入了一场真假难辨的甜蜜陷阱。",summary:"大学生林小溪的哥哥林海，与校草兼学霸陈屿是多年的竞争死对头。一次关键的创业大赛决赛前，哥哥因紧张过度病倒，恳求妹妹去“刺探”陈屿的决赛方案。林小溪只好以“追求者”身份接近陈屿，却没想到这位传闻中高冷毒舌的男神，竟然对她的笨拙“套路”全盘接受，甚至反客为主，展开了一场浪漫又令人心跳加速的“反向追求”。在虚拟游戏社区里，他们是默契的战友；在现实图书馆中，他们是互相调侃的学伴。林小溪在虚假任务与真实心动间挣扎，直到她发现，陈屿从一开始就知道她的身份，而这场“阴谋”，或许是他精心策划的、关于一场多年前误会的甜蜜复仇与和解。",review:"剧情在“套路”与“反套路”间巧妙游走，喜剧桥段自然不做作。男女主化学反应十足，从互相试探到真心相许的情感转变细腻可信。影片不仅关于爱情，更探讨了兄妹亲情与少年意气的和解，结局温暖动人。",cover:"/27.jpg",m3u8Index:7,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周",rating:"7.7",views:331599},{id:"0089",tags:["国产","电影","校园","青春","喜剧","友情"],relatedIds:["0072","0031","0060","0068","0094","0085"],title:"一起同过窗第一季",region:"国产",type:"电影",year:2016,genreRaw:"校园青春 / 情景喜剧",oneLine:"摄影系新生的大学一年级，在奇葩室友、严苛师友与青春躁动中，笑着闹着共同成长。",summary:"南方传媒大学摄影系大一新生路桥川、钟白、任逸帆，这对“铁三角”发小继续着他们的同窗生涯，并结识了性格迥异的新室友：自恋的学霸毕十三、沉默的富二代肖海洋、以及油滑的“情报部长”余皓。故事围绕他们大一学年的点滴展开：从军训的严格考验，到加入五花八门社团的趣事；从为完成奇葩作业绞尽脑汁，到面对初次心动的手足无措；从寝室夜谈的人生理想，到因为误解而产生的短暂隔阂。他们共同经历了学业压力、友情考验与朦胧的情感萌芽，在一场场令人捧腹的闹剧和一次次真诚的倾诉中，逐渐褪去青涩，明白了责任、包容与梦想的初定义。",review:"影片真实还原了大学新生的生活图景，人物群像刻画鲜明生动，每个角色都有完整的成长弧光。笑点密集且贴近生活，情感表达含蓄而有力，在嬉笑怒骂中道出了青春的珍贵与成长的阵痛，极易引发观众共鸣。",cover:"/2.jpg",m3u8Index:8,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊",rating:"9.4",views:148153},{id:"0090",tags:["日韩","电影","犯罪","爱情","悬疑","剧情"],relatedIds:["0067","0096","0042","0083","0001","0060"],title:"为爱劫持",region:"日韩",type:"电影",year:2019,genreRaw:"犯罪爱情 / 剧情悬疑",oneLine:"他策划了一场完美的银行劫案，只为赎回被绑架的爱人，却发现真相远比绑架更残酷。",summary:"平凡的银行职员朴志勋，某日收到神秘讯息：女友尹瑞妍被绑架，赎金是他必须从自己工作的银行金库中，带出一枚特定的、毫无金钱价值的旧版纪念币。在警方与银行系统的双重压力下，深爱瑞妍的志勋被迫精心策划了一场“一个人的劫案”。他利用职务之便与对银行的了解，在众目睽睽下取走纪念币，却也在过程中意外揭露了银行高层涉及洗钱的黑色交易。当他历经艰险交付赎金时，等待他的并非爱人，而是一个更深的漩涡：瑞妍的真实身份，以及这枚纪念币所牵连的、一段被掩埋的家族血仇，逐渐浮出水面。",review:"影片将紧张刺激的犯罪过程与深情缱绻的爱情主线紧密结合，悬念设置层层递进。男主在情与法间的挣扎演绎得极具张力，结尾的反转既出人意料，又在情理之中，令人唏嘘不已，深度探讨了爱与牺牲的边界。",cover:"/68.jpg",m3u8Index:9,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍, 孔刘",rating:"9.4",views:51384},{id:"0091",tags:["欧美","电影","爱情","喜剧","宠物","家庭"],relatedIds:["0068","0045","0086","0079","0066","0040"],title:"真爱狗公园",region:"欧美",type:"电影",year:2009,genreRaw:"爱情喜剧 / 宠物家庭",oneLine:"因狗结缘也因狗生恨的两对邻居，在社区狗公园的“遛狗战争”中意外寻回真爱与自我。",summary:"刚经历离婚的律师艾拉带着她神经质的小型犬“公爵”，搬入新社区，与隔壁独居的严谨建筑师大卫及其稳重的大型犬“船长”成了邻居。两只狗狗在社区狗公园一见如故，成了最好的玩伴，但它们的主人却因生活习惯和教养理念的差异冲突不断。另一边，单身妈妈莎拉与居家父亲迈克也因各自的宠物狗在公园相识，却在如何发展关系上顾虑重重。两条故事线在狗公园交织，从最初的争吵、恶作剧，到被迫合作解决一场宠物危机，四位成年人渐渐放下心防，不仅理解了彼此的处境，更在狗狗们纯粹快乐的感染下，重新审视了生活、家庭与爱的意义。",review:"轻松温馨的宠物喜剧，狗狗们的表现堪称亮点，自然推动剧情发展。四主角的人物设定具有代表性，互动幽默又充满生活气息。影片探讨了现代都市人的孤独与连接，治愈力十足，适合全家人一同观看。",cover:"/4.jpg",m3u8Index:10,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍",rating:"9.2",views:280035},{id:"0092",tags:["日韩","电影","惊悚","剧情","心理","剧情"],relatedIds:["0015","0072","0089","0042","0061","0006"],title:"恋物",region:"日韩",type:"电影",year:2012,genreRaw:"心理惊悚 / 剧情",oneLine:"专门修复旧物的匠人，逐渐被客户寄托在物品上的强烈情感吞噬，走向危险的共情深渊。",summary:"技艺精湛却性格孤僻的器物修复师高木莲，拥有一项不为人知的能力：能轻微感知到委托修复物品上残留的、原主人的强烈情感或记忆碎片。一天，一位神秘女子委托他修复一个看似普通的旧音乐盒。在修复过程中，莲被其中汹涌的、关于一场炽热却悲剧收场的恋情的记忆所淹没，甚至开始在现实中产生与记忆男主人公重合的幻觉。他不由自主地开始调查音乐盒的来历，越是接近真相，他与委托女子的生活就缠绕得越紧。最终他发现，音乐盒并非简单的纪念物，而是一个精心设计的、关于执念与替代的情感陷阱，而他已深陷其中，难以分辨自我与幻影的边界。",review:"影片氛围营造极为出色，将日常物品赋予了诡谲的生命力。男主心理变化的层次感极强，从专业冷静到逐渐崩溃的过程令人信服。故事探讨了记忆的可靠性、情感的依附性与人格的边界，主题深刻，后劲十足。",cover:"/144.jpg",m3u8Index:11,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡",rating:"9.3",views:393321},{id:"0093",tags:["欧美","电影","超级英雄","侦探","惊悚","心理创伤"],relatedIds:["0073","0034","0059","0014","0030","0033"],title:"杰西卡·琼斯第一季",region:"欧美",type:"电影",year:2015,genreRaw:"超级英雄 / 黑色侦探 / 心理惊悚",oneLine:"拥有怪力与创伤过往的女私家侦探，被迫面对能操控人心的宿敌，拯救他人也完成自我救赎。",summary:"杰西卡·琼斯曾短暂尝试过超级英雄生涯，但因一场被超级反派“紫人”基尔格雷夫操控身心的惨痛经历而崩溃。如今她隐于纽约地狱厨房，开着一家不入流的私家侦探社，用酒精麻痹自己。一桩寻找失踪女孩的普通委托，却将所有线索引向她最深的梦魇——重获自由并愈发强大的紫人。紫人能用声音操纵任何人，并以此为乐。为了阻止紫人伤害更多无辜者，也为了终结自己内心的恐惧，杰西卡必须鼓起残存的勇气，联合电台主播崔西·沃克、律师闺蜜杰里·霍加斯等人，与这个无形无影、甚至能操控她身边所有人的敌人展开一场极度不对等的心理与力量对决。",review:"这部作品重新定义了超级英雄类型，基调黑暗、影视化。杰西卡的角色塑造极其成功，她的创伤、酗酒与硬汉外壳下的脆弱真实可信。紫人作为反派，带来的心理压迫感远超物理威胁。剧集对权力、同意与创伤后恢复的探讨深刻有力。",cover:"/105.jpg",m3u8Index:12,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司, 松隆子",rating:"9.4",views:198584},{id:"0094",tags:["国产","电影","黑色喜剧","奇幻","剧情","meta"],relatedIds:["0006","0058","0086","0084","0012","0038"],title:"观众们！",region:"国产",type:"电影",year:2023,genreRaw:"黑色喜剧 / 奇幻剧情",oneLine:"不得志的演员突然能看见观众对现实生活的“弹幕”，生活自此变成一场无法下线的荒诞直播。",summary:"三十八线话剧演员周默，在又一次演出被喝倒彩后，意外获得了看见“观众弹幕”的能力。这些半透明的文字悬浮在每个人周围，内容多是吐槽、剧透甚至恶意的攻击。起初他惊恐万分，但很快发现，这些弹幕有时会“剧透”未来几秒要发生的事。他利用这个能力避免了车祸、猜中了彩票号码，生活似乎开始好转。然而，能力开始失控，“弹幕”不再局限于他视野内，甚至开始反向影响现实：当大量弹幕“希望”他出丑时，他真的会平地摔；当弹幕“要求”剧情走向时，现实竟随之扭曲。周默意识到，自己乃至整个世界，可能都只是某个未知存在眼中的“一场戏”。他必须找到关闭“弹幕”的方法，夺回自己人生的“主导权”。",review:"创意天马行空，将互联网时代的“观众文化”以超现实方式呈现，极具讽刺意味。影片在荒诞搞笑的外壳下，深刻探讨了表演型人格、社会凝视与个体自由等议题。男主从利用能力到反抗能力的转变，发人深省。",cover:"/38.jpg",m3u8Index:13,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司",rating:"8.7",views:214763},{id:"0095",tags:["国产","电影","历史","剧情","年代","传奇"],relatedIds:["0020","0029","0045","0100","0012","0099"],title:"大时代风云录",region:"国产",type:"电影",year:2022,genreRaw:"历史剧情 / 年代传奇",oneLine:"从清末到改革开放，江南丝绸世家的百年沉浮，缩影中国近现代工商业的艰难蜕变与新生。",summary:"影片以江南“锦云记”丝绸工坊三代传人的命运为主线，串联起中国近现代波澜壮阔的历史画卷。第一代沈云山，在清末洋货冲击下苦苦支撑传统工艺，实业救国梦碎。第二代沈仲文，于抗战烽火中辗转后方，保护技艺火种，见证了民族工业的凋零与坚韧。第三代沈念祖，在改革开放春潮中，面临是卖掉祖产融入外资，还是重振老字号的两难抉择。故事通过沈家与时代洪流的碰撞、与竞争对手的商海博弈、以及与不同立场家庭成员间的理念冲突，展现了民族工商业在历史巨变中的挣扎、坚守、转型与复兴，歌颂了贯穿其中的工匠精神与家国情怀。",review:"制作宏大精良，服化道还原度极高，营造出浓厚的时代氛围。叙事跨度大但脉络清晰，人物命运与历史事件结合紧密，既有家族史诗的厚重感，又不乏细腻动人的情感刻画。是一部兼具历史厚度与艺术感染力的诚意之作。",cover:"/40.jpg",m3u8Index:14,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美",rating:"8.6",views:379824},{id:"0096",tags:["国产","电影","都市","爱情","喜剧","萌宝"],relatedIds:["0060","0005","0095","0067","0001","0053"],title:"顾总每天都想凭儿子上位",region:"国产",type:"电影",year:2024,genreRaw:"都市爱情 / 轻松喜剧",oneLine:"高冷总裁发现天才萌宝竟是自己亲生，为追回带球跑的前女友，开启“父凭子贵”的爆笑追妻路。",summary:"游戏公司CEO顾延舟，冷静自持，是商界传奇。五年前一场意外，让他与实习生苏晚有了一夜交集，随后苏晚不告而别。五年后，公司新人产品发布会上，一个酷似顾延舟缩小版的天才儿童“苏小乐”以惊人编程能力惊艳全场。顾延舟震惊之余，通过调查确认小乐是自己的儿子，而他的母亲正是已成为独立游戏制作人的苏晚。原来当年苏晚因家庭变故和误会选择离开。顾延舟深感愧疚，决定追回妻儿。但他发现，直接追求屡屡碰壁，反倒是通过“收买”儿子，利用小乐的神助攻创造机会，效果拔群。于是，一场由萌宝主导，高冷总裁全力配合的“上位”计划，在鸡飞狗跳中甜蜜展开。",review:"设定虽带套路感，但执行得趣味盎然。萌宝智商情商双高，是推动剧情的关键“催化剂”而非工具人。男女主之间的误会化解与情感升温过程自然流畅，互动甜而不腻。整体轻松下饭，喜剧效果出众。",cover:"/117.jpg",m3u8Index:15,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治, 韩孝周",rating:"8.2",views:76127},{id:"0097",tags:["国产","电影","灾难","动作","冒险","剧情"],relatedIds:["0037","0095","0088","0067","0040","0005"],title:"瀚海潮",region:"国产",type:"电影",year:2018,genreRaw:"灾难动作 / 冒险剧情",oneLine:"远洋钻井平台遭遇百年罕见“疯狗浪”，被困工程师们必须在平台倾覆前，穿越死亡海域求生。",summary:"在南海深处的“瀚海一号”超深水钻井平台上，工程师团队正在庆祝一项新的开采纪录。然而，气象部门突然发来紧急预警，一个异常强大的温带气旋与复杂洋流结合，正生成破坏力惊人的超级涌浪——“瀚海潮”。平台虽设计先进，但面对这种极端天气仍岌岌可危。撤离直升机因天气无法抵达，平台结构在巨浪连续冲击下开始受损。以平台经理老周、海工专家陆远为首的团队，必须利用有限的资源和时间，在平台彻底失控前，修复关键设施，并驾驶仅存的抗浪能力较强的工程船，在高达数十米的浪墙中杀出一条生路。他们不仅要对抗自然之怒，还要面对内部恐慌、资源短缺以及人性在绝境中的考验。",review:"国产灾难片的工业化标杆之作。特效场面震撼逼真，将深海钻井平台的宏伟与自然的狂暴力量展现得淋漓尽致。剧情紧凑，灾难推进与人物群像刻画并重，逃生过程充满专业细节与紧张悬念，彰显了人类在绝境中的智慧与勇气。",cover:"/123.jpg",m3u8Index:16,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治",rating:"8.3",views:420846},{id:"0098",tags:["日韩","电影","剧情","音乐","人生","治愈"],relatedIds:["0094","0007","0095","0089","0064","0039"],title:"喧闹的街·宁静的海",region:"日韩",type:"电影",year:2006,genreRaw:"剧情 / 音乐人生",oneLine:"在都市街头卖唱的失意歌手，与在海边小镇沉默修补渔网的老人，通过一卷录音带彼此治愈。",summary:"在东京喧闹的涩谷街头，歌手健太郎每日弹唱，却无人驻足，梦想与生计都陷入困境。某日，他收到祖父从老家寄来的遗物，其中有一卷老式录音带，记录着祖父与一位老友的日常对话和海浪声。为处理遗产，健太郎来到祖父度过晚年的宁静海滨小镇。在那里，他遇见了录音带中的另一位主角——寡言的渔网修补匠松造老人。老人几乎失聪，生活简朴，每日与海为伴。健太郎本想尽快卖掉老屋离开，却在替老人整理仓库时，发现了祖父未完成的乐谱和老人年轻时代辉煌的音乐往事。两个失意者，一个用声音寻找出路，一个在寂静中埋葬过去，因一段尘封的旋律和共同珍视的回忆，逐渐向彼此敞开内心。",review:"影片节奏舒缓如海潮，画面静谧优美，与都市的喧嚣形成诗意的对比。故事没有强烈冲突，却通过细节和情感积累打动人心。音乐成为连接时空与心灵的桥梁，探讨了梦想、传承与和解的主题，充满东方式的含蓄与温情。",cover:"/58.jpg",m3u8Index:17,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪",rating:"8.1",views:380736},{id:"0099",tags:["欧美","电影","科幻","剧情","哲学","宗教"],relatedIds:["0060","0052","0024","0092","0010","0065"],title:"他们称之为罪",region:"欧美",type:"电影",year:2017,genreRaw:"科幻剧情 / 宗教哲学",oneLine:"在未来世界，情绪被列为非法“罪源”，一对恋人因无法抑制的“爱”而成为被清除的对象。",summary:"22世纪，人类社会的“大和谐”建立在情感抑制技术之上。所有强烈情绪，尤其是爱、恨、悲伤，都被视为导致冲突与低效的“罪源”，公民需定期接受神经调节，维持情绪平稳。数据分析师艾登与档案管理员莉亚，在一次系统错误中，意外体验到了未经调节的“对视心跳加速感”——即古老记录中称为“爱”的罪。这种被禁止的感受令他们既恐惧又迷恋。他们开始秘密约会，品尝“罪恶”的甜蜜，但行为异常很快被无处不在的“净心委员会”AI系统察觉。为了守护这份情感，他们必须利用职务之便，潜入系统核心，寻找情感被列为禁忌的真相，并决定是永久删除自己的“罪”，还是为“爱”正名，对抗整个冰冷的系统。",review:"设定极具思想性，构建了一个情感荒漠化的反乌托邦世界。影片在科幻外壳下，深刻质询了人性的本质与社会的基石。两位主角的表演克制而富有张力，从迷茫到觉醒的过程令人信服。结局的抉择发人深省，余韵悠长。",cover:"/101.jpg",m3u8Index:18,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊, 全度妍",rating:"9.5",views:399712},{id:"0100",tags:["国产","电影","奇幻","喜剧","家庭","乡村"],relatedIds:["0031","0069","0039","0081","0089","0091"],title:"好运旺荒年，乌鸦宝宝带继娘吃肉",region:"国产",type:"电影",year:2025,genreRaw:"奇幻喜剧 / 家庭剧情",oneLine:"饥荒年代，被嫌弃的继女竟能听懂乌鸦说话，在“乌鸦军师”帮助下，带领全家寻粮觅生机。",summary:"民国初年，北方大旱，饥荒蔓延。寡妇秀娥带着女儿小喜改嫁给老实农民赵大山，却遭到大山儿子铁柱的排斥和村里人的闲话。小喜性格孤僻，常与乌鸦为伴。一次高烧后，她竟发现自己能听懂乌鸦的语言。一只自称见过大世面的老乌鸦“黑爷”主动找上门，声称能帮她们找到食物，条件是分它一份。于是，在“黑爷”的空中侦察和出谋划策下，小喜“偶然”发现了田鼠洞里的存粮、河床下的暗流鱼群、甚至山崖上的野蜂巢。她将功劳归于“好运”，带领继父和哥哥一次次渡过难关。铁柱从怀疑到感激，秀娥也凭借智慧和善良赢得了尊重。乌鸦们成了这个特殊家庭的秘密盟友，在荒年上演了一出充满温情的求生喜剧。",review:"将民间传说“乌鸦报喜”与现实主义饥荒背景结合，创意独特。奇幻元素与现实困境的交织处理得幽默而温暖，毫无违和感。小演员表演灵动，人与乌鸦的互动妙趣横生。影片内核是关于接纳、信任与在绝境中绽放的人性光辉，感人至深。",cover:"/115.jpg",m3u8Index:19,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊",rating:"7.8",views:327225},{id:"0101",tags:["国产","电影","都市","情感","励志","温情"],relatedIds:["0091","0004","0020","0050","0032","0031"],title:"拥抱朝阳",region:"国产",type:"电影",year:2020,genreRaw:"都市情感 / 励志剧情",oneLine:"退休老干部与都市抑郁症青年，因社区晨练意外相识，在每日的朝阳下互相治愈，重启人生。",summary:"刚从重要岗位退休的老干部老陈，一时间难以适应生活的巨大落差，每日清晨在公园对着朝阳长吁短叹。同样每日清晨出现在公园长椅上的，还有患有轻度抑郁症的年轻设计师林朝阳，他因作品被剽窃和感情受挫而意志消沉。一天，老陈的太极剑不小心碰掉了林朝阳的画本，两人由此结识。老陈看不惯年轻人的颓废，开始“多管闲事”，硬拉着林朝阳加入晨练队伍，教他太极，与他分享自己年轻时的挫折故事。而林朝阳则用他的画笔，记录下老陈和公园里其他老人的生活瞬间。一老一少，在每日清晨的陪伴与“斗嘴”中，慢慢打开心结：老陈找到了退休生活的新意义，林朝阳则重拾了创作的勇气和对生活的热情。",review:"影片聚焦“退休综合症”与“青年抑郁”两大社会情绪痛点，切入点细腻真实。两位主角的忘年交情感发展自然流畅，充满生活化的幽默与温情。没有刻意的煽情，只有如朝阳般温暖和煦的互相照亮，传递出积极向上的生命力量。",cover:"/62.jpg",m3u8Index:0,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘",rating:"8.8",views:167507},{id:"0102",tags:["国产","电影","奇幻","动作","游戏改编","视效"],relatedIds:["0042","0065","0046","0080","0047","0027"],title:"梦幻西游之天命之战",region:"国产",type:"电影",year:2021,genreRaw:"奇幻动作 / 游戏改编",oneLine:"游戏世界第一剑侠客，为拯救被病毒吞噬的服务器与队友，携神器穿越至真实的梦幻盛唐。",summary:"《梦幻西游》顶级玩家林飞，在争夺全服最强神器“星瀚”时，所在的服务器突遭未知数据病毒侵袭，游戏世界崩坏，众多玩家意识被困。林飞凭借神器之力，意识意外穿越到了与游戏背景相似的、妖魔横行的真实盛唐世界。在这里，他遇见了与游戏队友长相、性格一模一样的真实人物：化生寺武僧、盘丝洞女侠、龙宫太子等。他们正面临一场足以毁灭人、仙、魔三界的巨大危机，而危机的源头，似乎与游戏世界的病毒同出一辙。林飞必须说服这些“陌生”的队友相信他的离奇经历，并将在游戏中磨练的战术与真实世界的武学、法术结合，带领这支特别的团队，为两个世界的存续而战。",review:"成功将游戏IP的经典元素与穿越奇幻类型结合，满足粉丝情怀的同时，构建了独立完整的故事线。动作场面设计巧妙融入了游戏技能特效，视觉华丽。团队协作与友情是核心亮点，热血中带着幽默，娱乐性十足。",cover:"/143.jpg",m3u8Index:1,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡, 役所广司",rating:"8.0",views:227593},{id:"0103",tags:["日韩","电影","惊悚","悬疑","生存游戏","人性"],relatedIds:["0029","0078","0016","0073","0052","0084"],title:"国王游戏",region:"日韩",type:"电影",year:2013,genreRaw:"惊悚悬疑 / 生存游戏",oneLine:"全班同学被迫参与来自未知“国王”的短信指令游戏，拒绝或失败者，将迎来恐怖的死亡惩罚。",summary:"私立高中二年级三班的学生们，某日同时收到一条来自未知号码的短信：“欢迎参加国王游戏。命令：藤原健必须在放学前亲吻山本丽子。拒绝或失败者，将受到惩罚。”众人起初以为是恶作剧，但性格孤僻的藤原健拒绝执行。放学后，他就在众人面前以极其诡异的方式暴毙。恐惧瞬间笼罩全班。紧接着，第二条、第三条命令接踵而至，内容越来越残酷、隐私，逼迫同学们互相伤害、揭露秘密。他们试图报警、扔掉手机、逃离学校，但“国王”的力量如影随形。在极端的恐惧与猜忌中，曾经的友情与秩序崩塌，人性之恶被彻底激发。少数试图团结反抗的学生，必须找出“国王”的真实身份和游戏规则漏洞，才能结束这场血腥的生存竞赛。",review:"概念高设定强，悬疑氛围从始至终拉满。死亡方式创意十足，惊吓点密集。影片深度挖掘了群体压力下的人性阴暗面，对校园欺凌、社交恐惧等议题有侧面折射。节奏紧张，结局反转令人脊背发凉。",cover:"/50.jpg",m3u8Index:2,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡",rating:"7.6",views:191725},{id:"0104",tags:["国产","电影","爱情","文艺","都市","遗憾"],relatedIds:["0002","0010","0065","0095","0011","0016"],title:"月亮不曾拥抱你",region:"国产",type:"电影",year:2019,genreRaw:"爱情文艺 / 都市剧情",oneLine:"她追逐着城市夜晚最亮的霓虹，他守护着天文台最暗的星空，两个世界的爱情如何交汇？",summary:"叶晚晴是顶尖奢侈品牌的公关经理，她的世界是华丽的宴会、精确的KPI和不眠的都市霓虹。陆星河是市郊天文台的研究员，他的世界是寂静的山顶、浩瀚的星图和漫长的数据观测。两人因一场品牌与天文台的跨界公益活动相识，仿佛是磁铁的两极，却产生了不可思议的吸引力。晚晴被星河的沉静与对宇宙的浪漫解读所吸引，星河则欣赏晚晴在现实世界中的璀璨与活力。他们努力融入对方的世界，晚晴试着熬夜观星，星河尝试穿戴西装出席活动。但不同的生活节奏、价值观和对未来的规划，像无形的引力波，拉扯着这段关系。在“超级月亮”即将出现的夜晚，他们必须做出选择：是为对方改变轨道，还是尊重彼此的轨迹，像月亮与地球，虽有引力纠缠，却永远保持着遗憾的距离。",review:"影片气质清冷文艺，将都市爱情与天文意象结合得巧妙而富有诗意。两位主角代表了两种截然不同的生活哲学，他们的相爱与相离都充满美感与思辨。没有狗血冲突，只有成年人关于爱情与自我实现的理性抉择，细腻真实，余味悠长。",cover:"/124.jpg",m3u8Index:3,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子",rating:"7.8",views:184726},{id:"0105",tags:["国产","电影","古装","商战","励志","大女主"],relatedIds:["0075","0066","0099","0073","0059","0036"],title:"凤翔九天之姐就是豪门",region:"国产",type:"电影",year:2023,genreRaw:"古装商战 / 大女主励志",oneLine:"商贾之女在家破人亡后，伪装身份白手起家，誓以女儿身打造商业帝国，向仇家复仇。",summary:"江南丝商之女沈惊鸿，聪慧过人，协助父亲打理家业。然而沈家因掌握关键织染技术，遭对手联合官府陷害，家产抄没，父兄惨死，惊鸿侥幸逃脱。她烧毁身份文牒，化名“凤九”，以孤女身份从最底层的绣坊织工做起，凭借过人的商业天赋和坚韧意志，一步步积累资本。她改良织机，创立“凤翔号”，从布匹到成衣，从陆运到漕运，生意版图不断扩大，成为江南商界神秘崛起的巨贾。过程中，她结识了志同道合的落魄皇商之子萧琰，也周旋于各方势力之间。当终于有实力对抗昔日仇敌时，她却发现了父亲惨案背后更深的宫廷阴谋。沈惊鸿决定，不仅要报仇，更要建立一个足以影响天下经济命脉的“豪门”，掌握自己的命运。",review:"大女主爽剧的优质范例。女主智商全程在线，事业线逻辑清晰，步步为营，看得人热血沸腾。商战博弈与朝堂权谋结合紧密，情节跌宕起伏。感情线作为辅线，克制而动人。展现了女性在封建时代的另一种强大可能性。",cover:"/48.jpg",m3u8Index:4,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美, 福山雅治",rating:"8.1",views:209304},{id:"0106",tags:["国产","电影","喜剧","爱情","荒诞","小镇"],relatedIds:["0035","0051","0082","0043","0019","0099"],title:"逗爱熊仁镇",region:"国产",type:"电影",year:2019,genreRaw:"爱情喜剧 / 荒诞剧情",oneLine:"一对竞争银行职位的都市情侣，被派到奇葩小镇追讨欠款，结果卷入一场全民“戏精”大狂欢。",summary:"同在一家银行信用卡部工作的恋人何必与蒙小鲜，正面临一个升职机会，两人成为竞争对手。为做最后考核，上司将一桩最难缠的案子交给他们：去一个以耍赖闻名、名为“熊仁镇”的偏远小镇，追回一笔烂账。两人来到小镇，发现这里民风“淳朴”到诡异：欠债的火锅店老板天天请他们免费吃喝就是不给钱，养猪大户用猪表演杂技抵债，全镇人似乎都在用各种荒唐方式对抗“还钱”这件事。在追债过程中，他们意外揭开了小镇居民共同守护的一个温暖秘密，而这个秘密与银行高层的一桩旧事有关。何必与小鲜在笑料百出的经历中，重新审视了金钱、规则与情感的关系，也做出了关于爱情与事业的选择。",review:"喜剧风格鲜明，荒诞感贯穿始终，小镇居民个个是“人才”，贡献了密集的笑点。但在胡闹的外表下，包裹着一个关于诚信与互助的温情内核。男女主的感情在奇葩任务中得到升华，从竞争到携手的过程自然有趣。",cover:"/12.jpg",m3u8Index:5,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美",rating:"9.1",views:202632},{id:"0107",tags:["国产","电影","爱情","奇幻","喜剧","都市"],relatedIds:["0026","0063","0076","0085","0079","0058"],title:"OMG! 我爱你...但不合时宜",region:"国产",type:"电影",year:2022,genreRaw:"都市爱情 / 奇幻轻喜剧",oneLine:"每次对真爱心动，时间就会倒流回心动前一刻，她必须在无尽的循环中，找到“对的时间”。",summary:"平面设计师苏念有个难以启齿的“诅咒”：每当她对某人产生真正的、想要在一起的心动感觉时，时间就会“啪”地一下倒流回心动发生前的几分钟，一切重置，只有她保留记忆。因此她一直单身，不敢动心。直到她在公司楼下的咖啡馆，对来谈合作的新锐建筑师顾川一见钟情。时间再次倒流。不甘心的苏念决定这次要反抗“诅咒”。她利用循环积累的信息，在每一次重置后以更完美的方式接近顾川，试图在不触发“心动阈值”的情况下与他发展关系。然而，感情岂能精确控制？在一次次失败的时间循环中，苏念不仅更了解顾川，也更深地爱上了他。她开始怀疑，这究竟是一种诅咒，还是一种保护？而打破循环的钥匙，或许就藏在顾川自己都遗忘的过去里。",review:"“时间循环+恋爱”的设定新颖有趣，喜剧效果源于女主一次次“攻略失败”的抓狂。循环的设定不仅服务于笑料，也巧妙推进了男女主情感的层层递进与真相揭秘。结局温暖治愈，探讨了“时机”与“真心”哪个更重要的爱情命题。",cover:"/114.jpg",m3u8Index:6,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周",rating:"8.1",views:196835},{id:"0108",tags:["日韩","电影","动作","喜剧","冒险","怀旧"],relatedIds:["0053","0017","0050","0044","0016","0069"],title:"城市猎人1993",region:"日韩",type:"电影",year:1993,genreRaw:"动作喜剧 / 都市冒险",oneLine:"好色却身手不凡的私家侦探寒羽良，与搭档牧村香接受各种危险委托，游走在东京的暗面。",summary:"在新宿经营“城市猎人”侦探事务所的寒羽良，是个见到美女就原形毕露的“色狼”，但同时他也是枪法如神、格斗顶尖的超级高手。他的搭档牧村香，是已故好友的妹妹，为了监视并“矫正”良的行为而加入，担任保镖兼助手，常用一把100t的大锤教训良的逾矩行为。这次，他们接受了一位神秘女性的委托，寻找她失踪的妹妹。调查将他们引向了东京地下庞大的器官黑市交易网络，并与一个凶残的国际犯罪集团“东京猫眼”发生冲突。在枪林弹雨、飞车追逐和一系列令人啼笑皆非的意外中，这对欢喜冤家式的搭档，既要保护委托人，又要破解犯罪阴谋，还要应付彼此间吵吵闹闹又默契十足的合作关系。",review:"经典动漫改编的真人版之一，成功抓住了原作的精髓：夸张的喜剧表演、流畅刺激的动作场面，以及男女主之间独特的搭档情谊。影片节奏明快，娱乐性极高，兼具怀旧风情与不减当年的时尚感，是动作喜剧的典范之作。",cover:"/135.jpg",m3u8Index:7,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪, 宋康昊",rating:"9.0",views:126316},{id:"0109",tags:["国产","电影","玄幻","动作","热血","唐门"],relatedIds:["0028","0038","0029","0078","0051","0064"],title:"斗罗大陆之燃魂战",region:"国产",type:"电影",year:2023,genreRaw:"玄幻 / 动作 / 热血",oneLine:"唐三为守护伙伴燃尽魂力，在绝境中领悟海神九考终极奥义。",summary:"在武魂殿的终极围剿下，史莱克七怪陷入生死危机。唐三为保护重伤的伙伴小舞，不惜燃烧自己的神魂本源，强行引动海神传承。在意识即将消散之际，他看到了初代海神留下的神念幻境，历经九重炼心考验，终于明白了真正的力量源于守护与牺牲，而非单纯的毁灭。最终，他以残存的神识驱动海神三叉戟，发出惊天一击，不仅击退了强敌，更以燃魂为代价，为伙伴们开辟了一条生路，而自己的身影却在金光中缓缓消散，留给世界一个永恒的传说。",review:"影片将热血战斗与深沉情感完美结合，唐三燃魂的段落视效震撼，情感冲击力极强。对“力量本源”的探讨超越了普通玄幻片，结局的牺牲与升华令人动容。",cover:"/132.jpg",m3u8Index:8,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪",rating:"9.0",views:107594},{id:"0110",tags:["国产","电影","灾难","动作","催泪","英雄"],relatedIds:["0098","0023","0042","0015","0039","0008"],title:"消防员",region:"国产",type:"电影",year:2021,genreRaw:"灾难 / 动作 / 剧情",oneLine:"一位因失误留下心结的消防队长，在化工爆炸中带领新兵逆行救援。",summary:"消防队长林峰因三年前一次救援失误导致队友牺牲，自此被心魔困扰。队里新来的热血青年李锐，正是当年牺牲队友的弟弟，对林峰抱有复杂情绪。当市郊化工厂发生连环爆炸，大量人员被困，林峰带领队伍作为第一梯队冲入火海。在极端高温、有毒气体和随时可能二次爆炸的危机下，林峰必须克服内心的恐惧，同时保护一心想证明自己却经验不足的李锐。两人在火场中从隔阂到信任，最终通力合作，用生命践行了消防员的誓言，完成了几乎不可能的任务。",review:"火场特效真实震撼，救援场面紧张到窒息。人物弧光完整，林峰与李锐的情感转变细腻动人，展现了平凡英雄背后的血肉与成长。",cover:"/64.jpg",m3u8Index:9,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍",rating:"8.6",views:324113},{id:"0111",tags:["欧美","电影","科幻","冒险","脑洞","亲子"],relatedIds:["0087","0011","0056","0008","0005","0071"],title:"忆世界大冒险",region:"欧美",type:"电影",year:2018,genreRaw:"科幻 / 冒险 / 家庭",oneLine:"为唤醒昏迷的母亲，兄妹俩通过特殊装置进入她光怪陆离的记忆世界。",summary:"母亲因意外事故成为植物人，医生表示她的意识活跃但被困在深层记忆。科学家父亲研制出“记忆链接舱”，让11岁的哥哥小凯和8岁的妹妹小汐进入母亲的忆世界寻找唤醒她的“核心记忆碎片”。在这个世界里，母亲的记忆化为各种奇幻场景：童年幻想的糖果城堡、少女时代的星空海滩、成为母亲后焦虑形成的迷雾森林。孩子们必须克服记忆世界的混乱与危机，同时直面母亲内心深处关于家庭、事业与自我的矛盾与遗憾。最终，他们用亲情的力量整合了碎片，让母亲在现实世界中苏醒。",review:"设定新颖，将亲情内核包裹在瑰丽的视觉奇观中。记忆世界的构建充满童趣与想象力，情感真挚，是一部适合全家观看的温暖科幻片。",cover:"/47.jpg",m3u8Index:10,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘, 马东锡",rating:"8.4",views:298802},{id:"0112",tags:["日韩","电影","动画","奇幻","环保","治愈"],relatedIds:["0064","0050","0065","0098","0007","0029"],title:"海龟奇妙之旅",region:"日韩",type:"电影",year:2015,genreRaw:"动画 / 奇幻 / 环保",oneLine:"一只被放生的小海龟，穿越海洋环流，见证人类对海洋的伤害与守护。",summary:"在冲绳的海龟保护区，小女孩小悠将一只名为“小绿”的受伤海龟治愈并放归大海。影片以小绿的视角，展开一场横跨太平洋的漫长归家之旅。它途经璀璨的珊瑚礁、遭遇塑料垃圾形成的“幽灵渔网”、误入被核废水影响的诡异海域，也遇到了志愿清理海洋的船队、致力于保护珊瑚的科学家。小绿一路成长，从懵懂到意识到海洋面临的危机。最终，它历经数年回到出生的海滩产卵，并与已成长为海洋生物学家的故人小悠重逢。影片通过小绿的眼睛，展现了海洋的美丽与伤痛。",review:"画面精美绝伦，海龟的旅程充满诗意与冒险。环保主题表达得自然而不说教，情感细腻，具有强烈的现实感染力。",cover:"/134.jpg",m3u8Index:11,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘",rating:"9.3",views:366737},{id:"0113",tags:["欧美","电影","奇幻","喜剧","想象力","经典改编"],relatedIds:["0050","0055","0035","0100","0068","0021"],title:"哈罗德和紫色蜡笔",region:"欧美",type:"电影",year:2006,genreRaw:"奇幻 / 喜剧 / 家庭",oneLine:"一个能用紫色蜡笔画出真实世界的小男孩，展开了一场拯救想象力的冒险。",summary:"改编自经典绘本。害羞孤独的小男孩哈罗德拥有一支神奇的紫色蜡笔。他画一扇门，就能进入门后的世界；画一条船，就能在海上航行。一晚，他画出的月亮被一个名为“灰暗者”的反派偷走，目的是吸干所有世界的色彩与想象力。哈罗德必须用他的蜡笔，穿越自己创造的丛林、城堡和城市，沿途结识了由他画出的、渴望拥有真实生命的伙伴们。他们共同对抗“灰暗者”，最终哈罗德明白了想象力的珍贵不仅在于创造，更在于分享，他画出了一个新的、色彩斑斓的太阳，照亮了所有世界。",review:"充满童真和创意的视觉盛宴，将二维绘画与三维现实巧妙结合。故事温暖有趣，寓意深刻，是关于创造力与勇气的完美寓言。",cover:"/71.jpg",m3u8Index:12,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司",rating:"7.6",views:403481},{id:"0114",tags:["国产","电影","都市","爱情","喜剧","马甲文"],relatedIds:["0058","0070","0060","0049","0042","0032"],title:"实习夫人马甲藏不住",region:"国产",type:"电影",year:2024,genreRaw:"都市 / 爱情 / 喜剧",oneLine:"为体验生活，豪门千金伪装成笨拙实习生，却总被顶头上司撞破马甲。",summary:"全球顶尖珠宝集团继承人苏念，为逃避家族联姻并寻找设计灵感，隐姓埋名进入对手公司“星璨”当了一名实习生。她故意扮演出身普通、笨手笨脚的新人模样，却屡屡在关键时刻因专业本能“露馅”。苛刻毒舌的设计总监顾泽言从一开始就怀疑她的身份，在一次次“抓包”与反抓包的趣味交锋中，两人从互怼到互相欣赏。当公司陷入重大商业危机，苏念的真实身份以及她暗中帮助公司的行为被迫曝光。最终，她不仅用实力化解危机，更与顾泽言联手，开创了珠宝设计的新理念。",review:"轻松欢快的甜宠喜剧，男女主互动火花四溅。“马甲”设定玩出新意，情节紧凑笑点密集，是解压放松的佳选。",cover:"/87.jpg",m3u8Index:13,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子, 长泽雅美",rating:"8.4",views:181381},{id:"0115",tags:["欧美","电影","战争","剧情","狙击","人性"],relatedIds:["0025","0024","0094","0005","0087","0055"],title:"最后的狙击战",region:"欧美",type:"电影",year:2017,genreRaw:"战争 / 剧情 / 动作",oneLine:"二战末期，盟军王牌狙击手与德军狙击精英，在废墟城市中展开意志对决。",summary:"1945年初，德军即将溃败。盟军顶尖狙击手杰克奉命潜入一座废弃的德国工业城市，消灭藏匿其中的德军残部指挥节点。然而，他遭遇了德军神秘的狙击精英“幽灵”。两人在断壁残垣间展开了一场长达数日的残酷猫鼠游戏。枪响之外，是精神的较量。杰克通过“幽灵”留下的痕迹，逐渐拼凑出对方同样厌恶战争、只想守护家园的普通人一面。当最终对决来临，杰克发现了“幽灵”守护的秘密——一群躲藏在地窖中的无辜平民。他必须在任务与人性之间做出最终抉择。",review:"气氛营造极为出色，废墟场景充满肃杀美感。双雄对决的心理刻画深刻，避免了脸谱化，对战争的反思沉痛而有力。",cover:"/93.jpg",m3u8Index:14,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子",rating:"8.5",views:441141},{id:"0116",tags:["国产","电影","古装","奇幻","喜剧","种田"],relatedIds:["0099","0082","0057","0048","0046","0078"],title:"桃源赘婿",region:"国产",type:"电影",year:2022,genreRaw:"古装 / 奇幻 / 喜剧",oneLine:"现代农学生穿越成古代桃源村的窝囊赘婿，用科学知识带领世外桃源致富。",summary:"农业大学生秦川意外穿越，成为古代与世隔绝的“桃源村”里备受白眼的赘婿。村里风景如画但生活清苦，靠天吃饭。秦川利用现代知识，改良稻种、兴修水利、打造生态农业链，让桃源村迅速富足起来。他的举动引起了外界贪婪县令的注意，县令企图强占桃源。秦川联合村民，利用地理优势和科学制造的“奇物”（如土制烟雾弹、简易滑翔翼）巧妙周旋，最终不仅保住了桃源，更让这里成为一方乐土，他也赢得了妻子和全村人的真心尊重，从“赘婿”变成了真正的“守护者”。",review:"将种田文与轻喜剧、微奇幻元素巧妙结合，剧情轻松有趣又不乏智慧。男主成长线清晰，群像生动，是一部别具一格的古装片。",cover:"/103.jpg",m3u8Index:15,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治",rating:"8.8",views:280963},{id:"0117",tags:["日韩","电影","剧情","青春","犯罪","救赎"],relatedIds:["0032","0095","0068","0033","0028","0014"],title:"少年不良",region:"日韩",type:"电影",year:2010,genreRaw:"剧情 / 青春 / 犯罪",oneLine:"因义气卷入黑帮纠纷的不良少年，在暴力和背叛中寻找真正的出路。",summary:"高中生金秀贤因家境贫寒且性格倔强，成为学校周边的小混混头目。一次为兄弟出头，他无意中得罪了本地真正的黑帮组织，被迫卷入毒品运送的犯罪活动。在暴力、背叛和警方追查的多重压力下，秀贤目睹了兄弟的惨死和黑帮的冷酷。一直暗中关心他的女同学恩静和一位退休老警察给了他关键的引导。最终，秀贤选择用自己作为诱饵，配合警方捣毁了黑帮据点，自己也因过往行为付出了代价。出狱后，他洗心革面，成为一名帮助边缘少年的社工。",review:"影片风格冷峻写实，对青少年犯罪的心理和社会根源剖析深刻。男主角的表演极具爆发力，救赎的主题沉重而充满希望。",cover:"/70.jpg",m3u8Index:16,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周, 李秉宪",rating:"7.5",views:196084},{id:"0118",tags:["国产","电影","爱情","校园","奇幻","治愈"],relatedIds:["0083","0095","0045","0020","0100","0090"],title:"原来时光都记得",region:"国产",type:"电影",year:2019,genreRaw:"爱情 / 校园 / 奇幻",oneLine:"女主患上罕见“时光倒流感”，在记忆与现实的交错中，找回被遗忘的初恋。",summary:"职场精英洛枳患上一种罕见病症，记忆会突然“倒流”到高中时代，在现实与过去间跳跃。她发现记忆中有一段关于同桌男生方成的空白。随着“倒流”频率增加，她逐渐拼凑出真相：当年两人因一场误会和家庭压力分开，洛枳因打击过大，大脑选择性遗忘了这段感情。在时光的闪回中，她重新体验了青春的悸动、甜蜜与伤痛，也理解了当年彼此的不成熟。最终，她在一次长久的“倒流”中，于记忆里与年轻的方成和解。醒来后，她鼓起勇气联系了已是知名建筑师的方成，发现对方也从未真正忘记。",review:"用奇幻设定包裹纯爱内核，构思巧妙。时光闪回的剪辑手法富有诗意，情感细腻动人，勾起了每个人对青春遗憾的共鸣。",cover:"/44.jpg",m3u8Index:17,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周",rating:"8.3",views:319203},{id:"0119",tags:["国产","电影","青春","运动","友情","成长"],relatedIds:["0092","0048","0008","0002","0012","0031"],title:"最好的夏天",region:"国产",type:"电影",year:2020,genreRaw:"青春 / 运动 / 剧情",oneLine:"五个高三死党在高考前最后一个夏天，为实现骑行西藏的约定而冒险出发。",summary:"距离高考还有三个月，五个从小一起长大的高三学生面临着人生的分岔路。他们曾有个疯狂约定：高中最后一个夏天，要一起骑行去西藏。在学业压力、家庭反对和自身犹豫下，这个约定几乎被遗忘。直到其中一人查出患有重症，时日无多。为了不留遗憾，五人瞒着家人，骑着自行车，踏上了通往高原的旅程。一路上，他们经历了爆胎、摔伤、高原反应，也见识了壮丽的风景和质朴的人情。旅途不仅是地理上的跋涉，更是心灵的释放与成长。最终，他们虽未抵达拉萨，却抵达了彼此心中最深的羁绊，拥有了一个“最好的夏天”。",review:"青春气息扑面而来，骑行之旅拍得热血而真挚。友情刻画深刻，没有狗血爱情，只有少年间最纯粹的承诺与陪伴，感人至深。",cover:"/96.jpg",m3u8Index:18,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊",rating:"9.4",views:186701},{id:"0120",tags:["国产","电影","历史","战争","动作","抗日"],relatedIds:["0093","0060","0030","0079","0033","0011"],title:"战天狼",region:"国产",type:"电影",year:2024,genreRaw:"历史 / 战争 / 动作",oneLine:"一支八路军敌后武工队，利用驯化的狼群作为特殊战力，奇袭日军据点。",summary:"1942年，华北山区。八路军武工队队长霍云山，在一次任务中救下一窝狼崽，并意外地与头狼建立了信任。他萌生了一个大胆的想法：训练狼群作为秘密武器。在精通动物习性的女队员林小雨帮助下，他们成功组建了一支“战狼小队”。利用狼群夜间行动敏捷、嗅觉听觉灵敏的特性，武工队多次成功进行侦查、破袭和营救任务，令日军闻风丧胆，称之为“天狼”。日军调来特种部队围剿，武工队与狼群陷入绝境。最终，人与狼并肩作战，以惨烈代价完成了摧毁日军重要细菌战基地的任务。",review:"题材新颖，将抗日传奇与动物元素结合，动作场面设计独特且震撼。人与狼的情感纽带刻画细腻，家国情怀与自然野性交织。",cover:"/20.jpg",m3u8Index:19,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍, 孔刘",rating:"8.3",views:111588},{id:"0121",tags:["欧美","电影","剧情","冒险","文艺","孤独"],relatedIds:["0026","0081","0042","0004","0092","0098"],title:"西伯利亚和他",region:"欧美",type:"电影",year:2013,genreRaw:"剧情 / 冒险 / 文艺",oneLine:"一位隐居西伯利亚荒野的法国学者，与一只受伤西伯利亚虎的意外共处。",summary:"法国生物学家安东尼因个人变故，自我放逐到西伯利亚森林中的小木屋，进行孤僻的生态观测。一天，他在陷阱里发现一只后腿受伤的成年西伯利亚虎。出于学者的本能，他战胜恐惧，为这只猛兽处理了伤口并将其放生。然而，老虎并未远离，开始时不时出现在木屋附近。一人一虎维持着危险而微妙的距离。安东尼观察着老虎，老虎也似乎“观察”着这个孤独的人类。在严酷的自然环境中，这种无声的陪伴逐渐成为了双方精神上的慰藉。直到偷猎者的枪声打破了平衡，安东尼必须为这位沉默的“邻居”而战。",review:"影片节奏舒缓如诗，西伯利亚的冰原美景与极致孤独感扑面而来。人与虎的关系处理得极其克制而富有哲学意味，表演和摄影俱佳。",cover:"/24.jpg",m3u8Index:0,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍",rating:"8.0",views:288547},{id:"0122",tags:["国产","电影","家庭","喜剧","温情","短片集"],relatedIds:["0082","0094","0022","0007","0065","0063"],title:"我们仨短剧",region:"国产",type:"电影",year:2023,genreRaw:"家庭 / 喜剧 / 剧情",oneLine:"通过三幕短剧，展现一个普通三口之家在十年间的笑泪成长与羁绊。",summary:"影片由三个时间片段组成：第一幕《小升初》（2013年），夫妻为儿子升学焦虑争吵，儿子用幼稚却温暖的方式调和；第二幕《叛逆期》（2018年），儿子沉迷网络与父亲激烈冲突，母亲在中间艰难维系，一次父亲重病让家庭关系破冰；第三幕《送别》（2023年），儿子即将去外地上大学，夫妻在空荡的家中回忆往昔，从拌嘴到默默落泪，最后一起笑着为儿子录制叮嘱视频。三幕剧，勾勒出中国式家庭的典型面貌，充满了烟火气的烦恼与不可割舍的深情。",review:"剧情贴近生活，笑点与泪点自然不生硬。演员表演细腻，尤其是父母角色的变化刻画入微，能引起广泛共鸣，是一部优秀的家庭小品集。",cover:"/121.jpg",m3u8Index:1,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡",rating:"8.0",views:136318},{id:"0123",tags:["国产","电影","都市","爱情","剧情","中年爱情"],relatedIds:["0052","0068","0097","0093","0002","0074"],title:"二婚后包子铺阿姨遇见真爱",region:"国产",type:"电影",year:2021,genreRaw:"都市 / 爱情 / 剧情",oneLine:"离异带娃的包子铺女店主，与常来买早餐的儒雅园艺师展开一段踏实恋情。",summary:"45岁的刘桂香在社区门口经营一家包子铺，离异后独自抚养上高中的女儿。她的生活围着灶台、女儿和账本转，从未想过爱情。常来买早餐的顾客中，有一位沉默寡言的园艺师老周。一次，老周帮她修好了店铺漏水的水管，两人开始有了交流。老周妻子早逝，同样独自生活。他们从分享一壶茶，到聊起各自的孩子、生活的艰辛与小小的乐趣。感情如水到渠成，没有轰轰烈烈，只有互相扶持的温暖。当双方子女因财产等现实问题产生疑虑时，两人用真诚和智慧化解了矛盾，在平凡的烟火气中，找到了专属的踏实幸福。",review:"聚焦中年人的情感世界，质朴真实，感人至深。两位主演的表演生活化，情感表达含蓄而有力，让观众相信爱情不分年龄。",cover:"/9.jpg",m3u8Index:2,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司, 松隆子",rating:"7.5",views:320153},{id:"0124",tags:["欧美","电影","科幻","惊悚","冒险","密闭空间"],relatedIds:["0041","0019","0013","0027","0064","0001"],title:"极北以北",region:"欧美",type:"电影",year:2016,genreRaw:"科幻 / 惊悚 / 冒险",oneLine:"北极科研站与世隔绝后，队员接连离奇死亡，幸存者发现凶手并非人类。",summary:"在北极最偏远的一个跨国科研站，极夜降临，暴风雪切断了所有对外联系。八名队员原本进行着常规的冰芯样本研究，但一名队员在站外作业时神秘失踪，随后站内开始发生诡异死亡事件。恐慌蔓延，猜忌滋生。临时站长、女科学家艾拉在调查中发现，他们从冰层深处钻取的一份未知生物样本可能已经泄露。这种生物能模仿人类形态，并寄生在宿主身上。幸存者们必须在黑暗、寒冷和彼此无法信任的环境中，找出伪装者，同时防止这种可怕的生物逃离北极，扩散到全球。",review:"将科幻惊悚与极地密室逃脱相结合，氛围营造堪称一流。悬念迭起，节奏紧张，对人性在极端环境下的拷问令人不寒而栗。",cover:"/8.jpg",m3u8Index:3,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司",rating:"8.0",views:222592},{id:"0125",tags:["国产","电影","剧情","教育","励志","现实主义"],relatedIds:["0062","0023","0020","0099","0014","0017"],title:"良师难为",region:"国产",type:"电影",year:2018,genreRaw:"剧情 / 教育 / 励志",oneLine:"满怀理想的青年教师被调到问题班级，用非常规方式打开学生们封闭的心。",summary:"师范大学毕业的李明，被分配到一所城乡结合部中学的“问题班级”当初三班主任。班里学生要么是留守儿童，要么家庭复杂，对学习毫无兴趣，抵触一切管教。李明一开始的常规教学方法处处碰壁。他决定改变策略：家访了解每个学生的困境，带他们踢足球发泄精力，用社会热点而不是课本引发讨论，甚至为想学手艺的学生联系职校。过程中，他遭到家长不解、学校质疑。但当他看到学生们眼中逐渐有了光，开始为自己的未来思考时，他坚信自己的选择。中考不是终点，他教会了他们如何面对生活。",review:"现实主义力作，直击教育痛点。没有刻意煽情，只有真实的力量。青年教师与学生的互动真挚感人，发人深省。",cover:"/75.jpg",m3u8Index:4,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美",rating:"7.6",views:287393},{id:"0126",tags:["国产","电影","都市","喜剧","爱情","直播"],relatedIds:["0069","0099","0023","0037","0098","0030"],title:"全网直播，小姨子曝光了我的身份",region:"国产",type:"电影",year:2023,genreRaw:"都市 / 喜剧 / 爱情",oneLine:"低调的亿万富翁，因小姨子在其豪宅直播，全网皆知他是“软饭男”。",summary:"白手起家的科技新贵陆沉舟，为追求纯粹的爱情，伪装成普通上班族与妻子苏晴结婚。苏晴的妹妹苏月是个小网红，为博眼球，偷偷溜进姐姐家的豪华别墅（陆沉舟的资产）做直播，声称这是姐姐的豪宅，而姐夫只是个“吃软饭”的幸运儿。直播爆火，陆沉舟“软饭男”形象全网皆知，工作和生活陷入混乱。他必须在隐瞒真实身份的前提下，处理这场公关危机，同时应对得知“真相”后妻子家族的质疑和妻子的伤心。最终，在一场混乱的家族聚会上，他的真实身份以意想不到的方式曝光，引发一连串爆笑与感人的反转。",review:"喜剧效果拉满，误会丛生，笑点密集。剧情反转巧妙，在搞笑之余也探讨了爱情中信任与坦诚的重要性，娱乐性十足。",cover:"/22.jpg",m3u8Index:5,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治, 韩孝周",rating:"8.0",views:381970},{id:"0127",tags:["国产","电影","家庭","喜剧","儿童","成长"],relatedIds:["0019","0039","0056","0081","0023","0034"],title:"吾家笑笑初长成",region:"国产",type:"电影",year:2022,genreRaw:"家庭 / 喜剧 / 儿童",oneLine:"记录五岁女孩笑笑一年内的童言童语和奇思妙想，串联起家庭的温暖日常。",summary:"影片以纪录片式的跟拍视角，聚焦五岁小女孩笑笑上幼儿园大班这一年的成长点滴。通过她的眼睛看世界：她认为爸爸上班是去“打怪兽”，妈妈生气是因为“肚子里有火龙”，爷爷养的花会“在晚上聊天”。她的每一个天真问题、古怪念头，都给家庭带来欢笑和思考。期间也经历了和好朋友闹别扭、第一次登台表演紧张、面对宠物仓鼠死亡的悲伤等“人生大事”。影片没有强烈的戏剧冲突，只有平凡日子里流淌的亲情与童真。笑笑的成长，也映照着父母、祖辈的反思与改变。",review:"清新治愈，宛如一篇优美的散文。小演员的表演自然灵动，童趣十足。能唤醒观众心中最柔软的角落，是献给所有孩子和曾是孩子的大人的礼物。",cover:"/41.jpg",m3u8Index:6,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治",rating:"8.8",views:174615},{id:"0128",tags:["欧美","电影","悬疑","犯罪","剧情","侦探"],relatedIds:["0038","0059","0022","0081","0048","0074"],title:"谜探路德维希",region:"欧美",type:"电影",year:2009,genreRaw:"悬疑 / 犯罪 / 剧情",oneLine:"19世纪末维也纳，患有学者综合征的警探凭借超凡记忆力破解连环谜案。",summary:"故事发生在1898年的维也纳。路德维希是一名警局的档案管理员，他患有学者综合征，拥有过目不忘的记忆力，但社交能力极弱，行为刻板。一桩模仿古老传说“提线木偶”的离奇谋杀案难倒了所有警探。新任女警探夏洛特偶然发现了路德维希的天赋，说服上司让他协助破案。路德维希能从海量档案中瞬间找到关联线索，通过现场细节在脑中完美还原犯罪过程。两人搭档，一个凭直觉与社交手段，一个靠绝对的逻辑与记忆，在维也纳的艺术殿堂与阴暗小巷中穿行，逐渐接近一个指向皇室秘辛的惊人阴谋。",review:"侦探设定新颖，将历史背景与特殊能力结合巧妙。案件复杂曲折，充满古典悬疑美感。双主角的互动有趣，化学反应十足。",cover:"/138.jpg",m3u8Index:7,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪",rating:"9.0",views:73314},{id:"0129",tags:["日韩","电影","恐怖","悬疑","科幻","心理惊悚"],relatedIds:["0042","0092","0083","0062","0043","0065"],title:"灵异空间",region:"日韩",type:"电影",year:2012,genreRaw:"恐怖 / 悬疑 / 科幻",oneLine:"参加意识上传实验的志愿者，醒来发现自己的数字灵魂被困在虚拟鬼域。",summary:"科技公司“彼岸”招募志愿者进行人类意识数字化初期实验。大学生朴秀贤为赚取妹妹的医药费参与其中。实验过程中发生未知错误，秀贤的意识醒来，发现自己被困在一个不断循环的诡异数字空间里——这里是他记忆碎片拼凑成的童年老宅，但充满了无法解释的灵异现象：倒流的时钟、重复闪现的陌生人影、无法打开的房门。他逐渐意识到，这个空间里还困着其他实验失败者的意识残片，它们充满怨念，正在侵蚀他的存在。秀贤必须在自己的意识被完全同化或消散前，找到这个虚拟世界的“后门”逃出生天。",review:"将科技恐惧与心理恐怖完美融合，概念超前。虚拟空间的诡异感营造出色，节奏步步紧逼，结局的反转令人细思极恐。",cover:"/59.jpg",m3u8Index:8,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊, 全度妍",rating:"7.9",views:338842},{id:"0130",tags:["国产","电影","爱情","奇幻","短片集","都市童话"],relatedIds:["0036","0052","0013","0090","0063","0075"],title:"恋恋不忘短剧",region:"国产",type:"电影",year:2024,genreRaw:"爱情 / 奇幻 / 短片集",oneLine:"三个关于“记忆残留物”的都市奇幻短剧，讲述物品承载的未竟之爱。",summary:"本片由三个独立的奇幻爱情短剧构成，核心设定是：强烈的情感会残留在相关物品上，形成“记忆残留物”。《旧钢笔》：作家发现一支旧钢笔写出的字迹，会自动补全他已故女友未写完的小说结局。《雨伞店》：总在下雨天走进同一家店借伞却从不归还的男士，原来是为了见到已成为“伞灵”的初恋。《语音导航》：失恋女孩的车载导航里，残留着前男友声音的AI，引导她走出情感低谷，走向新的旅程。三个故事彼此独立，主题统一，探讨了告别、释怀与爱的多种形态。",review:"构思精巧，情感细腻。每个短剧都像一首微型的都市童话，奇幻设定服务于情感内核，浪漫而治愈，余味悠长。",cover:"/49.jpg",m3u8Index:9,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊",rating:"8.8",views:250116},{id:"0131",tags:["港台","电影","动作","剧情","犯罪","经典"],relatedIds:["0081","0003","0062","0060","0086","0047"],title:"阿虎",region:"港台",type:"电影",year:2e3,genreRaw:"动作 / 剧情 / 犯罪",oneLine:"一名隐退的泰国拳王，为寻找失踪多年的女儿，被迫重拾拳头踏入黑帮漩涡。",summary:"孟虎，绰号“阿虎”，曾是在泰国地下拳场未尝败绩的华人拳王，因一次失手打死对手而心灰意冷，隐居曼谷。二十年后，一位修女带来消息，他从未谋面的女儿可能生活在香港，并卷入黑帮纠纷。阿虎踏上寻女之路，发现女儿因欠下高利贷被黑帮控制。为救女儿，年近五十的阿虎不得不重披战袍，以老迈之躯挑战香港黑帮拳场的新生代高手。每一场拳赛都是对自己过往罪孽的救赎，也是对父爱的证明。最终，他用生命诠释了一个父亲的尊严与力量。",review:"经典港式悲情英雄片，打斗场面硬桥硬马，充满力量感。刘德华饰演的阿虎，将沧桑、愧疚与父爱演绎得淋漓尽致，感人至深。",cover:"/99.jpg",m3u8Index:10,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘",rating:"7.8",views:275742},{id:"0132",tags:["国产","电影","都市","爱情","剧情","兄妹"],relatedIds:["0030","0065","0055","0077","0020","0087"],title:"离婚后，三个哥哥独宠我",region:"国产",type:"电影",year:2023,genreRaw:"都市 / 爱情 / 剧情",oneLine:"离婚后心灰意冷的女孩，被三位身份显赫的亲生哥哥找到并捧成公主。",summary:"林晚晚在不幸的婚姻中受尽冷落，离婚后一无所有。此时，三位气质不凡的男人找上门，声称是她失散多年的亲生哥哥。大哥是商界巨鳄，二哥是顶尖律师，三哥是天才医生。他们为当年未能保护妹妹而愧疚，决心补偿。哥哥们强势介入她的生活，帮她教训前夫，给她最好的一切，甚至为她挑选新的恋爱对象。在极致的宠爱中，晚晚从自卑逐渐找回自信，但也产生了新的困扰——哥哥们过度的保护欲让她无法独立飞翔。最终，在一场事业危机中，晚晚凭借自己的努力和哥哥们背后的支持成功化解，找到了家庭宠爱与自我价值的平衡点。",review:"满足观众对亲情与宠爱的终极幻想，剧情苏爽甜蜜。兄妹互动有趣，在梦幻设定下也探讨了个人成长的主题，观看体验愉悦。",cover:"/57.jpg",m3u8Index:11,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘, 马东锡, 役所广司",rating:"8.9",views:70857},{id:"0133",tags:["欧美","电影","剧情","惊悚","家庭","心理"],relatedIds:["0080","0014","0061","0022","0041","0009"],title:"破裂",region:"欧美",type:"电影",year:2014,genreRaw:"剧情 / 惊悚 / 家庭",oneLine:"一场车祸后，妻子坚称儿子已死，丈夫却在镜中看到活着的儿子身影。",summary:"大卫和妻子凯伦驾车出游发生严重车祸，他们的儿子乔希当时在后座。凯伦在医院醒来后，悲痛欲绝地告诉大卫，乔希在车祸中丧生了。大卫因脑震荡记忆模糊，但回家后，他开始在房子的反光面（窗户、镜子、水渍）中反复看到一个男孩跑过的身影，并听到细微的笑声。当他询问凯伦，凯伦却坚称是他的创伤后应激障碍。大卫开始偷偷调查，发现凯伦的行为举止越来越怪异，关于车祸的细节也前后矛盾。真相逐渐浮出水面，牵涉出一个关于爱与偏执的恐怖秘密。",review:"心理惊悚氛围营造登峰造极，悬念一直保持到最后一刻。对婚姻关系、丧子之痛与心理防线的刻画入木三分，结局震撼。",cover:"/109.jpg",m3u8Index:12,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡",rating:"8.4",views:137119},{id:"0134",tags:["国产","电影","文艺","剧情","古装","工匠精神"],relatedIds:["0098","0009","0016","0088","0077","0008"],title:"雨过天青",region:"国产",type:"电影",year:2021,genreRaw:"文艺 / 剧情 / 古装",oneLine:"宋代天青釉瓷技艺失传之际，一位倔强女匠人用一生追寻那抹传奇釉色。",summary:"北宋末年，战乱将至。汝窑因战火封闭，天青釉的配方与烧制技艺濒临失传。窑工之女青瓷，自幼痴迷制瓷，有着超越常人的天赋与执着。为复原天青釉，她女扮男装，拜师学艺，遍访古籍，试验无数。过程中，她与欣赏她才华的落魄文人顾清风相知相爱，但乱世之中，个人情感与家国命运、技艺传承相比显得渺小。一次次开窑，一次次失败，希望的微光在动荡时局中明灭。最终，在都城沦陷的前夜，青瓷燃尽最后的窑火，开出一窑雨过天青，将最美的瞬间凝固，随后与瓷窑一同隐没于历史尘埃。",review:"画面如宋画般清雅隽永，将工匠精神与乱世悲歌融为一体。女主角的坚韧与宿命感令人动容，是一部充满东方美学韵味的文艺佳作。",cover:"/140.jpg",m3u8Index:13,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子",rating:"8.3",views:112285},{id:"0135",tags:["日韩","电影","喜剧","爱情","职场","治愈"],relatedIds:["0011","0041","0076","0026","0097","0080"],title:"调教咖啡厅",region:"日韩",type:"电影",year:2017,genreRaw:"喜剧 / 爱情 / 职场",oneLine:"笨手笨脚的女大学生，进入一家需要扮演特定属性的主题咖啡厅打工。",summary:"内向笨拙的大学生美樱急需打工收入，误打误撞进入了著名的“属性咖啡厅”。这里的服务员必须扮演固定的“属性”来服务客人，如傲娇、妹系、高冷等。美樱被分配到了最冷门的“无口阴沉”属性，这对于不擅表达的她简直是灾难。在严厉但帅气的主理人神崎的“调教”下，美樱闹出无数笑话，却也慢慢找到了属于自己的服务方式——用细微的肢体动作和真诚的眼神打动客人。她与神崎也从互相嫌弃到渐生情愫。当咖啡厅面临倒闭危机时，美樱用自己的方式，策划了一场独一无二的主题活动，拯救了咖啡厅，也收获了爱情与自信。",review:"轻松爆笑又温暖治愈，将宅文化元素自然地融入浪漫喜剧。人物设定有趣，互动可爱，是一部能让人忘却烦恼的甜蜜小品。",cover:"/34.jpg",m3u8Index:14,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子, 长泽雅美, 福山雅治",rating:"9.0",views:248153},{id:"0136",tags:["国产","电影","古装悬疑","武侠探案","动作","反转"],relatedIds:["0092","0005","0070","0079","0089","0029"],title:"侠探白玉堂之诡狼奇案",region:"国产",type:"电影",year:2022,genreRaw:"古装 / 悬疑 / 动作",oneLine:"开封侠探白玉堂卷入离奇狼患案，揭开了边境城池掩埋的惊天阴谋。",summary:"北宋年间，边境雄州接连发生诡异“狼患”，受害者身上留下似狼似人的抓痕，人心惶惶。侠探白玉堂奉包拯之命暗中调查，发现所谓狼患实为一种致人狂化的西域奇毒，而投毒者竟与雄州守将有关。白玉堂在调查中结识了精通医术的神秘女子凌霜，两人抽丝剥茧，逐步接近真相。原来守将勾结外邦，企图以奇毒制造混乱，为敌军入侵铺路。最终，白玉堂与凌霜联手，在月圆之夜的城楼之上，与化身“狼王”的守将展开生死对决，不仅粉碎了阴谋，更找到了解毒之法，拯救了一城百姓。",review:"影片将武侠与探案巧妙融合，动作戏设计飘逸凌厉，极具观赏性。悬疑氛围营造出色，“诡狼”设定新颖，层层反转出人意料，主角间的默契与情感暗线也处理得细腻动人。",cover:"/6.jpg",m3u8Index:15,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美",rating:"7.8",views:321029},{id:"0137",tags:["欧美","电影","爆笑喜剧","公路旅行","兄弟情","运动"],relatedIds:["0038","0062","0037","0008","0056","0092"],title:"哈拉上路2：啤酒桌球赛",region:"欧美",type:"电影",year:2009,genreRaw:"喜剧 / 运动 / 公路",oneLine:"三个死党为参加全国啤酒桌球赛，展开了一场状况百出的疯狂公路之旅。",summary:"距离上一段冒险几年后，乔什、塞布和E.L.已步入社会但依然不着调。他们偶然得知在新奥尔良将举行一场奖金丰厚的全国啤酒桌球锦标赛，冠军可获得十万美元。不愿错过“翻身”机会的三人，开着那辆老破车再次上路。旅途充满经典美式喜剧桥段：被奇怪的公路餐厅坑钱、误入小镇的古怪节日、与一群暴躁的卡车司机发生冲突，甚至他们的车在半路彻底报废。他们依靠 hitchhike（搭便车）和各种奇葩交通工具，在比赛截止前最后一刻赶到现场。面对强大的对手，他们凭借多年“默契”和出人意料的无厘头打法，竟一路闯进决赛，最终虽未夺冠，却赢得了尊重、友谊和比奖金更宝贵的人生体悟。",review:"延续了前作的疯狂与无厘头风格，笑点密集且自然。公路片的外壳下，核心仍是关于成长与友谊的温暖内核，三位主演的化学反应依旧火花四射。",cover:"/111.jpg",m3u8Index:16,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周",rating:"8.3",views:268809},{id:"0138",tags:["国产","电影","重生","古装爱情","宫斗","虐恋反转"],relatedIds:["0045","0044","0054","0077","0039","0032"],title:"重生嫁太子二皇子追悔莫及",region:"国产",type:"电影",year:2023,genreRaw:"古装 / 爱情 / 奇幻",oneLine:"将军嫡女重生归来，毅然嫁与病弱太子，让曾负她的二皇子痛悔一生。",summary:"上一世，将军嫡女沈清婉痴恋二皇子萧承睿，倾尽家族之力助他夺嫡，最终却落得家族覆灭、被弃冷宫的下场。含恨而终后，她竟重生回选妃前夕。这一世，她看清了二皇子的虚伪与野心，在宫宴上主动求嫁予体弱多病、看似与世无争的太子萧承瑾。她的选择震惊朝野。嫁入东宫后，她不再恋爱脑，凭借前世记忆与智慧，暗中协助太子调理身体、培植势力，并巧妙化解一次次来自二皇子与后宫的阴谋。太子的深情与信任也逐渐融化了她冰封的心。当二皇子发现沈清婉才是真正的“福星”并试图挽回时，为时已晚。最终，太子在她的辅佐下稳固地位，二人携手开创盛世。",review:"重生设定运用巧妙，女主角智商在线，复仇与成长的爽感十足。男女主角从相互扶持到情深意笃的情感线细腻感人，权谋部分虽简单但服务于主线，节奏明快。",cover:"/147.jpg",m3u8Index:17,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周, 李秉宪, 宋康昊",rating:"7.7",views:229793},{id:"0139",tags:["国产","电影","商战","职场逆袭","家族恩怨","权谋"],relatedIds:["0072","0062","0040","0016","0061","0046"],title:"总裁上位记",region:"国产",type:"电影",year:2018,genreRaw:"都市 / 商战 / 剧情",oneLine:"豪门私生子隐忍十年，在集团危机中强势回归，上演惊心动魄的权力游戏。",summary:"陆景轩是龙腾集团董事长流落在外的私生子，自幼与母亲相依为命，受尽冷眼。母亲病逝后，他被接回陆家，却成为嫡母和兄弟的眼中钉，被派往海外不起眼的业务部门。十年间，他默默积累人脉与资本，锤炼心性。金融危机爆发，龙腾集团核心业务遭遇重创，内部争权夺利导致局面崩坏。关键时刻，陆景轩携带一份足以改变格局的跨国合约与雄厚资金悄然回国。他以铁腕手段整顿内部，化解外部危机，在与家族内外的对手进行了一系列惊心动魄的商战与心理博弈后，最终在董事会上一举夺得集团控制权，完成了从弃子到王者的逆袭。",review:"商战情节紧凑且专业细节到位，主角的隐忍与爆发极具张力。影片不仅聚焦权力争夺，更深入探讨了家族、亲情与个人价值的复杂关系，引人深思。",cover:"/145.jpg",m3u8Index:18,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪",rating:"8.1",views:238787},{id:"0140",tags:["国产","电影","乡村题材","成长","亲情","治愈"],relatedIds:["0022","0011","0052","0094","0062","0025"],title:"田间的少年",region:"国产",type:"电影",year:2020,genreRaw:"剧情 / 家庭 / 乡村",oneLine:"城市少年因家庭变故而回乡，在与外公和土地的相处中，找回了生活的根。",summary:"15岁的城市少年林晓宇因父母离异且各自忙碌，被暂时送到南方乡下与独居的外公生活。初到田间，他格格不入，嫌弃这里的落后与枯燥。外公是个沉默寡言的老农，只是每日带着他下地劳作，插秧、除草、看水。在日复一日的劳作中，晓宇经历了从抗拒到疲惫，再到慢慢适应的过程。他结识了淳朴的乡村伙伴，见证了生命的孕育与收获，也听到了外公关于家族、关于土地的故事。一次暴风雨中，他与外公共同抢收稻谷，在泥泞中体会到了守护的艰辛与意义。夏天结束，父母来接他时，晓宇发现自己已深深眷恋这片土地和这位寡言的外公，他找到了内心缺失的平静与力量。",review:"画面诗意，叙事平实而动人，完美捕捉了中国乡村的静谧之美与生活质感。少年与外公之间无声胜有声的情感互动真挚感人，是一部关于回归与治愈的暖心之作。",cover:"/125.jpg",m3u8Index:19,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍",rating:"8.8",views:324886},{id:"0141",tags:["欧美","电影","奇幻喜剧","儿童文学改编","天才少女","温馨"],relatedIds:["0010","0026","0086","0098","0057","0047"],title:"玛蒂尔达1996",region:"欧美",type:"电影",year:1996,genreRaw:"家庭 / 奇幻 / 喜剧",oneLine:"拥有超凡智力和念动力的天才小女孩，用特别的方式对抗不公，寻找温暖。",summary:"玛蒂尔达·沃姆伍德是一个天赋异禀的小女孩，她热爱阅读，智力远超常人，甚至逐渐发现自己拥有用眼睛移动物体的“念动力”。然而，她的父母庸俗势利，对她漠不关心。进入残酷的校长特朗奇布尔小姐统治的学校后，玛蒂尔达的处境更加艰难。特朗奇布尔小姐以体罚学生为乐。玛蒂尔达在善良的班主任哈尼小姐那里得到了久违的关爱。为了帮助哈尼小姐夺回被特朗奇布尔霸占的家产，也为了保护同学们，玛蒂尔达开始谨慎地运用自己的超能力，策划了一系列巧妙而有趣的恶作剧，最终智斗恶校长，让正义得到伸张，也为自己和哈尼小姐赢得了充满爱与书香的幸福新生活。",review:"一部充满想象力的经典儿童电影，小演员的表演灵动可爱。影片以夸张幽默的方式描绘影视世界的荒诞，又以孩子的纯真与智慧予以反击，既有趣又温暖人心。",cover:"/100.jpg",m3u8Index:0,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",director:"金基德",actors:"宋康昊, 全度妍, 孔刘, 马东锡",rating:"8.8",views:219631},{id:"0142",tags:["日韩","电影","科幻灾难","哥斯拉","战后创伤","生存"],relatedIds:["0057","0020","0065","0009","0084","0093"],title:"哥斯拉-1.0",region:"日韩",type:"电影",year:2023,genreRaw:"科幻 / 灾难 / 剧情",oneLine:"二战末期的日本，遭遇史上首次出现的哥斯拉，幸存者们面临绝境中的反扑。",summary:"故事设定在二战结束后的日本，满目疮痍。前神风特攻队飞行员敷岛浩志因未执行任务而怀有深刻负罪感，在废墟中艰难求生。此时，一个巨大的不明生物在太平洋被核试验唤醒，登陆日本本土，它被命名为“哥斯拉”。与后世认知不同，这是人类与哥斯拉的首次遭遇，其破坏力完全超乎想象。面对这个象征着绝对毁灭的“负”之存在，濒临崩溃的日本社会更加绝望。浩志在逃亡中，与同样失去一切的平民们相遇。为了守护仅存的生活与希望，他们必须放下过去的创伤与分歧，利用战场上残存的智慧和勇气，策划一场近乎自杀的豪赌，试图将这个“负一”的灾难驱离。",review:"影片成功将巨型怪兽灾难与深沉的历史创伤、人性反思结合，赋予了哥斯拉新的隐喻维度。特效震撼，但更出色的是对战后幸存者心理的细腻刻画，绝望中迸发的勇气尤为动人。",cover:"/104.jpg",m3u8Index:1,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",director:"是枝裕和",actors:"全度妍, 孔刘",rating:"9.5",views:152724},{id:"0143",tags:["国产","电影","奇幻喜剧","身份互换","人生逆袭","轻松搞笑"],relatedIds:["0032","0078","0047","0064","0020","0043"],title:"再次睁眼，我成了人生赢家",region:"国产",type:"电影",year:2024,genreRaw:"都市 / 奇幻 / 喜剧",oneLine:"普通社畜一觉醒来，发现自己成了财富自由、家庭美满的“人生赢家”。",summary:"35岁的普通公司职员周伟，生活压力巨大，房贷、车贷、职场晋升无望。一天加班至深夜后昏睡过去，醒来竟发现自己躺在豪华别墅里，身边有美丽的妻子和可爱的女儿，手机里满是下属的恭敬问候和巨额资产信息。他穿越到了一个和自己同名同貌、但却是上市公司CEO、家庭幸福的“成功周伟”身上。起初他闹出不少笑话，难以适应富豪生活和高管工作。在“扮演”人生赢家的过程中，他利用原身的善良和来自普通人的同理心，意外解决了一些商业和家庭隐患，也渐渐珍惜起这份来之不易的温暖。当原身意识可能回归的危机出现时，他必须做出选择：是回到自己平庸但真实的人生，还是努力留住这个美好的梦？",review:"设定有趣，喜剧效果拉满，男主角的窘态与成长令人捧腹。影片在搞笑之余，也温和探讨了关于幸福、成功与自我认知的命题，温馨又带有思考。",cover:"/73.jpg",m3u8Index:2,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",director:"河正宇",actors:"孔刘, 马东锡, 役所广司",rating:"9.3",views:344924},{id:"0144",tags:["国产","电影","古装生存","基建种田","帝妃搭档","权谋"],relatedIds:["0003","0099","0057","0095","0031","0017"],title:"帝妃荒野筑粮仓",region:"国产",type:"电影",year:2022,genreRaw:"古装 / 剧情 / 冒险",oneLine:"落难皇帝与妃子被流放荒野，二人携手从零开始，打造一个世外粮仓。",summary:"永昌帝在位晚期，政权被权臣架空，他与出身将门、性格坚毅的妃子苏云晚一同被诬陷，流放至北方苦寒的不毛之地。那里只有废弃的戍堡和少量老弱囚徒。面对绝境，苏云晚没有绝望，她利用所学的地理农桑知识，勘察地形、寻找水源；永昌帝则放下帝王身段，学习耕作、带领众人建造房屋。从开垦第一块冻土，到引来山泉灌溉，他们克服了气候、野兽、物资匮乏等重重困难，竟将荒原变成了肥沃的粮田。他们的作为吸引了更多流民前来投靠，逐渐形成村落。而当朝廷因饥荒再次动荡时，他们这个巨大的“粮仓”和凝聚的人心，成为了改变天下格局的关键力量。",review:"另类古装片，将“种田基建”元素与历史背景结合，新鲜感十足。帝妃二人从隔阂到携手共进的情感变化真实可信，在荒野求生的坚韧精神极具感染力。",cover:"/148.jpg",m3u8Index:3,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",director:"新海诚",actors:"马东锡, 役所广司, 松隆子, 长泽雅美",rating:"7.7",views:143386},{id:"0145",tags:["欧美","电影","战争历史","人性","隔岸观火","道德抉择"],relatedIds:["0077","0034","0060","0065","0096","0075"],title:"对岸的战争",region:"欧美",type:"电影",year:2017,genreRaw:"剧情 / 战争 / 历史",oneLine:"一战时期，隔河相望的两座小镇居民，在战争阴影下做出不同的人性抉择。",summary:"1914年，欧洲。一条宽阔的河流成为国界，河北岸是阿斯科特（属A国），南岸是圣朱利安（属B国）。两岸居民世代通商、通婚，关系融洽。战争爆发后，两国成为敌对国，河流成了战线。最初，两岸的居民们隔着河互相喊话，传递对和平的渴望。但随着战争持续，仇恨宣传渗透，年轻男子被征召入伍。某天，河北岸的年轻士兵彼得，发现对岸树林中疑似有敌方侦察兵，而那人影酷似他战前的好友、南岸的让。上级命令他开枪。彼得面临残酷抉择。与此同时，两岸的镇长和妇孺们，则暗中进行着危险的人道主义行动，试图在战争的铁幕下保留一丝人性的微光。影片聚焦于普通人在宏大历史中的挣扎与选择。",review:"视角独特，没有宏大战场，却通过“一河之隔”淋漓尽致地展现了战争对人性和社区的撕裂。表演细腻克制，充满道德张力和感人至深的人文关怀。",cover:"/42.jpg",m3u8Index:4,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",director:"岩井俊二",actors:"役所广司, 松隆子",rating:"9.4",views:123314},{id:"0146",tags:["国产","电影","动作悬疑","特工","阴谋","反转"],relatedIds:["0025","0022","0063","0054","0016","0064"],title:"国家机密2",region:"国产",type:"电影",year:2015,genreRaw:"动作 / 悬疑 / 犯罪",oneLine:"特工为追查境外情报组织，意外揭开一桩涉及高层腐败的惊天黑幕。",summary:"国家安全局特工陈默，在奉命追查一个窃取我国经济数据的境外情报组织“黑雀”时，发现对方的行动总能快自己一步，疑似内部有“鼹鼠”。在追捕过程中，他救下了掌握关键证据的金融分析师苏雯。两人被迫联手逃亡，从繁华都市到边境丛林，遭遇一连串致命追杀。随着调查深入，陈默震惊地发现，“黑雀”的幕后金主和指挥者，竟然与国内某个位高权重的商业巨头有关，其触角甚至伸向了某些腐败官员，形成了一个危害国家经济安全的利益网络。陈默在孤立无援的情况下，凭借对信仰的忠诚和过硬的技能，与苏雯一同周旋于多方势力之间，最终在上级的秘密支持下，将证据送抵最高检，揪出了内鬼，摧毁了网络。",review:"节奏紧凑，动作场面干净利落，追车、枪战戏码颇具水准。剧情层层递进，反转设置合理，在商业类型片中较好地平衡了娱乐性与主题的严肃性。",cover:"/77.jpg",m3u8Index:5,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",director:"北野武",actors:"松隆子, 长泽雅美, 福山雅治",rating:"7.7",views:359519},{id:"0147",tags:["日韩","电影","奇幻设定","人生选择","温情喜剧","成长"],relatedIds:["0010","0089","0002","0063","0031","0068"],title:"我能看到成功率第三季",region:"日韩",type:"电影",year:2021,genreRaw:"奇幻 / 剧情 / 喜剧",oneLine:"能看见成功率的男子步入中年，在家庭与梦想的十字路口，再次审视自己的能力。",summary:"山田浩介，一个普通的中年上班族，自少年时期便拥有看见任何行动“成功率”数字的奇异能力。前两季讲述了他如何利用能力帮助他人、寻找真爱的故事。第三季电影版中，浩介已拥有稳定的家庭和工作，能力使用得愈发谨慎。然而，公司面临重组，他的职位岌岌可危；同时，大学时代未竟的音乐梦想再次浮现——老朋友邀请他重组乐队参加大型比赛。浩介看向跳槽的成功率是“35%”，乐队比赛夺冠的成功率是“8%”。是遵循高成功率的“安全”道路，还是追逐低成功率却心之所向的梦想？这次，他决定暂时屏蔽数字的干扰，听从内心的声音。过程充满波折与笑泪，最终他明白，有些事的价值，远非一个百分比可以衡量。",review:"系列最佳收官之作，将奇幻设定深度融入现实中年危机议题，情感真挚饱满。笑点与泪点并存，对“成功”的定义进行了富有哲思的探讨，引人共鸣。",cover:"/146.jpg",m3u8Index:6,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",director:"奉俊昊",actors:"长泽雅美, 福山雅治, 韩孝周, 李秉宪",rating:"7.6",views:418641},{id:"0148",tags:["日韩","电影","家庭剧情","代际冲突","和解","温情"],relatedIds:["0077","0005","0033","0001","0052","0017"],title:"家族的形式",region:"日韩",type:"电影",year:2019,genreRaw:"剧情 / 家庭",oneLine:"一个关系疏离的现代家庭，因父亲突然再婚而重新聚拢，直面彼此的情感隔阂。",summary:"在东京生活的建筑师凉介与妹妹美香关系平淡，与独居乡下的父亲俊作更是多年鲜少交流。母亲去世后，家庭仿佛失去了纽带。一天，父亲突然宣布要与一位相识不久的阿姨结婚，并打算卖掉老宅。这一决定像一块石头投入平静的水面，激起了兄妹二人复杂的情感波澜。凉介认为父亲草率，美香则对父亲即将开启新生活感到失落与嫉妒。两人一同回乡试图劝阻，却在与父亲和未来继母的相处中，逐渐了解到父亲晚年对孤独的恐惧和对陪伴的渴望。老宅里封存的旧物，也勾起了被遗忘的家族记忆。最终，在一场家庭冲突与深夜长谈后，他们开始尝试理解并接纳父亲的选择，破碎的家族情感以新的形式缓慢重建。",review:"典型的日式家庭片，叙事细腻如水，对人物心理的刻画入木三分。没有激烈的戏剧冲突，却在平淡日常中深刻揭示了现代家庭关系的疏离与和解的可能，余味悠长。",cover:"/118.jpg",m3u8Index:7,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",director:"朴赞郁",actors:"福山雅治, 韩孝周",rating:"7.9",views:275445},{id:"0149",tags:["欧美","电影","丧尸恐怖","人性考验","末日求生","团队"],relatedIds:["0020","0042","0081","0057","0001","0059"],title:"行尸走肉第二季",region:"欧美",type:"电影",year:2012,genreRaw:"恐怖 / 剧情 / 惊悚",oneLine:"幸存者团队在高速公路和农场求生，内部矛盾与外部尸群威胁双重升级。",summary:"继疾控中心爆炸后，瑞克带领的幸存者团队沿着高速公路艰难前行。寻找失踪的女孩索菲亚成为主要任务，但搜索过程充满危险，队伍 morale 低落。卡尔中枪重伤，将他们引至赫谢尔医生的僻静农场暂避。农场看似安全，但赫谢尔对行尸（他称之为“病人”）抱有非现实的幻想，将它们圈养在谷仓，这为冲突埋下伏笔。团队在农场暂时休整，但内部矛盾凸显：肖恩与瑞克的领导权之争日益激烈，洛莉的怀孕带来更多不确定性。外部，尸群在农场周围游荡，威胁从未远离。当谷仓的秘密被揭开，索菲亚的命运尘埃落定，巨大的危机迫使团队必须做出离开还是死守的抉择，人性的阴暗与光辉在极端环境下暴露无遗。",review:"比第一季更侧重于人物心理刻画和团队内部的张力营造，节奏张弛有度。农场作为封闭舞台，上演了一出精彩的人性与生存剧情剧，结局震撼，为后续发展奠定基调。",cover:"/15.jpg",m3u8Index:8,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",director:"今村昌平",actors:"韩孝周, 李秉宪, 宋康昊",rating:"9.3",views:124744},{id:"0150",tags:["国产","电影","赛车运动","青春励志","父子情","追梦"],relatedIds:["0042","0088","0024","0028","0067","0047"],title:"为梦想发车",region:"国产",type:"电影",year:2021,genreRaw:"剧情 / 运动 / 励志",oneLine:"地下赛车手为赢得正规赛资格，必须克服心魔，并与疏远的冠军父亲和解。",summary:"林风是地下街头赛车圈公认的“弯道之王”，但一次导致好友重伤的事故让他心生阴影，从此只敢在深夜的山路独自飞驰。他的父亲林峰曾是叱咤风云的冠军车手，却因严厉与常年缺席导致父子关系冰封。国内顶级拉力赛“巅峰之路”开启海选，冠军可直通职业车队。林风在妹妹和伙伴的鼓励下决定参赛，却遭到父亲的强烈反对。在一步步通过海选、预赛的过程中，林风不仅要直面过去的心理创伤，还要应对来自其他天才车手的竞争。父亲虽表面冷漠，却暗中观察，并在关键时刻以教练的身份出现，用严苛但专业的方式帮助他突破技术瓶颈。决赛日，暴雨中的盘山赛道，林风与父亲的心结在极速中逐渐化解，他最终为梦想，也为自己的人生，全力发车。",review:"赛车场面拍摄得极具速度感与视觉冲击力，令人肾上腺素飙升。故事内核是经典的励志与亲情和解，情感真挚，父子间从对抗到理解的过程刻画得扎实动人。 VIDEO_DATA_END",cover:"/63.jpg",m3u8Index:9,videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",director:"小津安二郎",actors:"李秉宪, 宋康昊, 全度妍, 孔刘",rating:"9.4",views:154161}];
